/*Table structure for table `category` */

DROP TABLE IF EXISTS `category`;

CREATE TABLE `category` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '编号',
  `category_typeId` int DEFAULT NULL COMMENT '关键外键',
  `category_name` varbinary(50) DEFAULT NULL COMMENT 'category',
  `category_del` int DEFAULT '0' COMMENT '逻辑删除',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  PRIMARY KEY (`id`),
  KEY `category_typeId` (`category_typeId`),
  CONSTRAINT `category_ibfk_1` FOREIGN KEY (`category_typeId`) REFERENCES `question` (`category_id`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

