  `category_id` int DEFAULT NULL COMMENT '题目所属的类别',
  `question_question_type_id` int DEFAULT NULL COMMENT '题目类型',
  `question_image` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '图片题目',
  `question_subject_type_id` int DEFAULT NULL COMMENT '科目类别',
  `question_key_id` int DEFAULT NULL COMMENT '与答案表绑定',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '默认为当前时间',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `question_delete` int DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `questionKey_id` (`question_key_id`) USING BTREE,
  KEY `category_id` (`category_id`) USING BTREE,
  KEY `question_subject_type_id` (`question_subject_type_id`),
