  CONSTRAINT `question_ibfk_2` FOREIGN KEY (`question_subject_type_id`) REFERENCES `subject` (`subject_type_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1227 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC;

