/*Table structure for table `question_type` */

DROP TABLE IF EXISTS `question_type`;

CREATE TABLE `question_type` (
  `id` int NOT NULL AUTO_INCREMENT,
  `question_type_id` int DEFAULT NULL COMMENT '题目类别编号',
  `question_type_name` varchar(50) DEFAULT NULL COMMENT '题目分类名称',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Data for the table `question_type` */

insert  into `question_type`(`id`,`question_type_id`,`question_type_name`) values (1,1,'判断题'),(2,2,'单选题'),(3,3,'多选题'),(4,4,'看图答题');

/*Table structure for table `questionkey` */

DROP TABLE IF EXISTS `questionkey`;

CREATE TABLE `questionkey` (
  `id` int NOT NULL AUTO_INCREMENT,
  `question_key_question` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '题目',
  `question_key_correct` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '正确答案选项',
  `question_key_analysis` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci COMMENT '题目解析',
  `question_key_video` blob COMMENT '相关视频',
  `create_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  `question_key_delete` int DEFAULT '0' COMMENT '逻辑删除',
  PRIMARY KEY (`id`) USING BTREE,
  CONSTRAINT `questionkey_ibfk_1` FOREIGN KEY (`id`) REFERENCES `question` (`question_key_id`)
) ENGINE=InnoDB AUTO_INCREMENT=1227 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC;

/*Data for the table `questionkey` */

insert  into `questionkey`(`id`,`question_key_question`,`question_key_correct`,`question_key_analysis`,`question_key_video`,`create_time`,`update_time`,`question_key_delete`) values (1,'这个标志是何含义？','4','环岛行驶：表示只准车辆靠右环行。此标志设在环岛面向路口来车方向适当位置。',NULL,'2023-10-13 11:38:36','2023-10-13 11:38:36',0),(2,'这个标志是何含义？','1','线型诱导标线型诱导标志，用于引导车辆驾驶人改变行驶方向，促使安全运行。视需要设于易肇事之弯道路段，小半径匝道曲线或中央隔离设施及渠化设施的端部。线形诱导标的颜色规定为：指示性线形诱导标一般道路为蓝底白图案,高速公路为绿底白图案，用以提供一般性行驶指示;警告性线形诱导标为红底白图案，可使车辆驾驶人提高警觉，并准备防范应变之措施。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(3,'这个标志是何含义？','3','禁止超车：表示该标志至前方解除禁止超车标志的路段内，不准机动车超车。此标志设在禁止超车的起点。',NULL,'2023-10-13 11:38:36','2023-10-13 11:38:36',0),(5,'这个标志是何含义？','1','观景台那三个字多明显，你再不选它，叫它情何以堪。',NULL,'2023-10-13 11:38:36','2023-10-13 11:38:36',0),(8,'这个标志是何含义？','3','左右绕行：用以告示前方道路有障碍物，车辆应按标志指示减速慢行，绕行通过。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(9,'这个标志是何含义？','2','一道红线是50米，二道100米。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(10,'这个标志是何含义？','2','左转和掉头合并在一个标志里，你应该能看到的。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(12,'这个标志是何含义？','4','限制最高时速40公里：表示该标志至前方限制速度标志的路段内，机动车行驶速度不得超过标志所示数值。此标志设在需要限制车辆速度的路段的起点。以图为例：限制行驶时速不得超过40公里。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(13,'这个标志是何含义？','2','此图为非机动车车道，别误以为自行车专用车道，没有自行车专用车道这一说。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(14,'这个标志是何含义？','4','禁止鸣喇叭：表示禁止鸣喇叭。此标志设在需要禁止鸣喇叭的地方。禁止鸣喇叭的时间和范围可用辅助标志说明。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(15,'机动车仪表板上（如图所示）亮时，表示驻车制动器处于制动状态。','1','圆圈里面是“P” 表示驻车制动器处于制动状态，即手刹没松开，但是车辆没有发生故障。\r<br/>里面是“！” 表示制动系统异常或故障。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(16,'这个标志是何含义？','4','靠左侧道路行驶：表示只准一切车辆靠左侧道路行驶。此标志设在车辆必须靠左侧行驶的路口以前适当位置。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(17,'机动车仪表板上（如图所示）亮表示什么？','1','前雾灯朝左，后雾灯朝右。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(18,'这个标志是何含义？','4','此标志为多乘员车辆专用车道，比机动车专用车道标志上的小车多了2个小人，所以它是多乘员车辆专用车道。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(20,'这属于哪一种标志？','1','交叉路口：用以警告车辆驾驶人谨慎慢行，注意横向来车。设在平面交叉路口驶入路段的适当位置。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(22,'驾驶人驾驶有达到报废标准嫌疑机动车上路的，交通警察依法予以拘留。','2','1、根据《中华人民共和国道路交通安全法》规定，驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废。对驾驶前款所列机动车上道路行驶的驾驶人，处200元以上2000元以下罚款，并吊销机动车驾驶证。\r<br/>2、题目中表述的是“达到报废标准嫌疑机动车”，并未确定为已经报废，按规定无须处罚。\r<br/>因此，题目所说的“交通警察依法予以拘留”是不正确的，本题答案应为错误。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(23,'这个标志是何含义？','1','一道红线是50米，三道150米。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(25,'这个标志是何含义？','2','施工路段：用以告示前方道路施工，车辆应减速慢行或绕道行驶。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(26,'这个标志是何含义？','3','左侧绕行：用以告示前方道路有障碍物，车辆应按标志指示减速慢行，左侧绕行通过。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(27,'机动车仪表板上（如图所示）亮表示发动机可能机油量不足。','1','图中的标志是机油的标志。 该指示灯用来显示发动机内机油的压力状况，该指示灯常亮，说明该车发动机机油压力低于规定标准，需要维修。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(28,'机动车达到国家规定的强制报废标准的不能办理注册登记。','1','《机动车登记规定》有下列情形之一的，不予办理注册登记：机动车达到国家规定的强制报废标准的。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(30,'这个标志的含义是提醒前方左侧行车道或路面变窄。','1','左侧变窄：用以警告车辆驾驶人注意前方车行道或路面狭窄情况，遇有来车应予减速避让。设在双车道路面宽度缩减为6 m以下的路段起点前方。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(32,'这个标志是何含义？','4','禁止掉头：表示前方路口禁止一切车辆掉头。此标志设在禁止掉头的路口前适当位置。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(33,'驾驶机动车在路口看到这种信号灯亮时，要加速通过。','2','《道路交通安全法实施条例》第三十八条：黄灯亮时，已越过停止线的车辆可以继续通行；未经过停止线的则禁止继续通行。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(35,'这个标志是何含义？','2','禁止直行和向左转弯：表示前方路口禁止一切车辆直行和向左转弯。此标志设在禁止直行和向左转弯的路口前适当位置。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(36,'这个标志是何含义？','1','观景台那三个字多明显，你再不选它，叫它情何以堪。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(37,'这属于哪一类标志？','1','他是指方向的故为指路标志。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(38,'这个标志是何含义？','4','乡道是白底Y字开头的，县道是白底X开头的，省道是黄底的，国道是红底的。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(39,'这个标志是何含义？','1','一道红线是50米，三道150米。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(40,'这个标志是何含义？','2','表示干路先行，此标志设在车道以前适当位置。答题技巧：记住哥一句话，谁粗谁先行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(41,'申请小型汽车准驾车型驾驶证的人年龄条件是多少？','2','新交规 公安部123号令\r<br/><b>1、申请小型汽车、小型自动挡汽车、残疾人专用小型自动挡载客汽车、轻便摩托车准驾车型的，在18周岁以上、70周岁以下；</b> 　　\r<br/>2、申请低速载货汽车、三轮汽车、普通三轮摩托车、普通二轮摩托车或者轮式自行机械车准驾车型的，在18周岁以上，60周岁以下； \r<br/>3、申请城市公交车、大型货车、无轨电车或者有轨电车准驾车型的，在20周岁以上，50周岁以下； \r<br/>4、申请中型客车准驾车型的，在21周岁以上，50周岁以下； 　　\r<br/>5、申请牵引车准驾车型的，在24周岁以上，50周岁以下； 　　\r<br/>6、申请大型客车准驾车型的，在26周岁以上，50周岁以下。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(42,'这个标志是何含义？','2','慢行：此标志设在前方需要减速慢行的路段以前适当位置。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(43,'这个标志是何含义？','3','高速公路服务区预告：用于预告服务区的位置，设在减速车道起点处。表示一般服务区预告标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(46,'驾驶机动车在人行横道上临时停车属于违法行为。','1','《道路交通安全法》规定人行横道上不允许停车。违反安全法就是违法行为。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(47,'这个标志是何含义？','3','这个应该能看懂吧？很明显那个小车开灯的效果。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(50,'这个标志是何含义？','3','高速公路左侧出口预告：用于预告前方出口，在距离高速公路或城市快速路减速车道的渐变段起点处。出口预告标志应同时附着出口编号标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(52,'机动车仪表板上（如图所示）亮时，提醒驾驶人座椅没调整好。','2','该指示灯用来显示安全带是否处于锁止状态，当该灯点亮时，说明安全带没有及时的扣紧。有些车型会有相应的提示音。当安全带被及时扣紧后，该指示灯自动熄灭。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(55,'这个标志是何含义？','4','禁止停放车辆：表示在限定的范围内，禁止一切车辆临时或长时停放。此标志设在禁止车辆停放的地方。禁止车辆停放的时间、车种和范围可用辅助标志说明。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(56,'这个标志是何含义？','2','直行和向左转弯：表示只准一切车辆直行和向左转弯。此标志设在车辆必须直行和向左转弯的路口以前适当位置。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(58,'这个标志是何含义？','4','会车时停车让对方车先行：表示车辆会车时，必须停车让对方车先行。设置在会车有困难的狭窄路段的一端或由于某种原因只能开放一条车道作双向通行路段的一端。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(60,'这种白色矩形标线框含义是什么？','2','路边的平行的停车位，亲 侧方停车以后要好好学哦~',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(61,'在暂住地初次申领机动车驾驶证的，不能直接申领大型货车驾驶证。','1','在暂住地初次申领机动车驾驶证的，是可以直接申领大型货车驾驶证的。\r<br/>根据2016年4月1日起开始实行的驾驶证新规，取消了异地考驾照对A/B证的限制，A/B也可以在暂住地申领了，但是需要有当地的居住证或者暂住证。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(62,'这个标志是何含义？','3','路面不平：用以提醒车辆驾驶人减速慢行。设在路面颠簸路段或桥头跳车较严重的地点以前适当位置。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(63,'路中白色虚线是什么标线？','4','白色表示同向两车道之间的标线，虚线可跨越超车。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(64,'这个标志是何含义？','3','俩个箭头加上你来的道路形成一个Y字。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(65,'机动车购买后尚未注册登记，需要临时上道路行驶的，可以凭什么临时上道路行驶？','2','《道路交通安全法》第八条：国家对机动车实行登记制度。机动车经公安机关交通管理部门登记后，方可上道路行驶。尚未登记的机动车，需要临时上道路行驶的，应当取得临时通行牌证。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(67,'这个导向箭头是何含义？','4','直行或者掉头都可以',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(69,'这个标志是何含义？','1','表示机动车驶入前方道路之最低时速限制。此标志设在高速公路或其他道路限速路段的起点。高度限速标志是白底红字。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(70,'这个标志是何含义？','3','高速公路左侧出口预告：用于预告前方出口，在距离高速公路或城市快速路减速车道的渐变段起点处。出口预告标志应同时附着出口编号标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(71,'这个标志是何含义？','1','常识题。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(72,'机动车号牌损毁，机动车所有人要向登记地车辆管理所申请补领、换领。','1','机动车号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向登记地车辆管理所申请补领、换领。申请时，机动车所有人应当填写申请表并提交身份证明。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(74,'仪表显示当前发动机转速是6000转/分钟。','2','题目中仪表中有KM，这是速度和里程表，表示当前汽车的行驶速度是60公里/小时。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(75,'机动车仪表板上（如图所示）亮表示启用地板及前风窗玻璃吹风。','1','扇型的是前风窗，曲线向上表示前风窗玻璃吹风。箭头向下是地板出风。所以本题是对的。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(76,'这个标志是何含义？','3','一道红线是50米，一道50米。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(78,'驾驶机动车不按照规定避让校车的，一次记6分。','1','根据规定，驾驶机动车不按照规定避让校车的，一次记6分 。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(79,'路面上的黄色填充标线是何含义？','3','双黄线就是警告注意越界，“打叉的物体”就是不可移动障碍物。因此选接近障碍物标线。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(81,'这个标志是何含义？','4','高速公路交通广播频率：用以指示收听高速公路或城市快速路交通信息广播的频率，可在适当地点设置，根据需要可重复设置。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(82,'这个标志是何含义？','4','会车时停车让对方车先行：表示车辆会车时，必须停车让对方车先行。设置在会车有困难的狭窄路段的一端或由于某种原因只能开放一条车道作双向通行路段的一端。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(83,'这个标志是何含义？','1','高速公路停车区是有茶杯的，高速公路停车场是只有一个P。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(84,'醉酒驾驶机动车在道路上行驶会受到什么处罚？','3','按照《道路交通安全法》规定：醉酒驾驶机动车辆，吊销驾照，5年内不得重新获取驾照，经过判决后处以拘役，并处罚金。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(86,'道路交通安全违法行为累积记分一个周期满分为12分。','1','《公安部令第123号》第五十五条：<br/>道路交通安全违法行为累积记分周期（即记分周期）为12个月，满分为12分，从机动车驾驶证初次领取之日起计算。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(90,'这个标志是何含义？','2','路面高突：用以提醒车辆驾驶人减速慢行。设在路面突然高突以前适当位置。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(91,'这个标志是何含义？','4','错车道指的是在单车道道路上，可通视的一定距离内，供车辆交错避让用的一段加宽车道。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(92,'图中圈内黄色虚线是什么标线？','2','黄色虚线 划于路段中时，用以分隔同向行驶的交通流或作为行车安全距离识别线；划于路口时，用以引导车辆行进。\r<br/>例如：当我方车道上的车辆与对面道路上的车同时左转弯时，一律需要在线内行驶，保证有足够的安全距离。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(94,'指示标线的作用是什么？','2','指示标线是指示通行的，具体的红色标志表示禁止、限制；黄色标志表示警告。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(95,'机动车紧急制动时，ABS系统在提供最大制动力的同时能使车前轮保持转向能力。','1','ABS防抱死系统；车轮不卡死、硬化路面制动时间短平稳、可以用力踩制动、系统自动张合8次/每秒。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(96,'仪表显示当前车速是20公里/小时。','2','图显示的单位是 1/min×1000，意思是每一分钟（注意是分钟）1000转。转速指针为2，即2000转每分钟。<br/>而车速还要根据车轮大小来确定。【2×车轮半径×3.14（圆周率）】车轮周长×转速。<br/>此图，应该是<b>转速标示图</b>。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(98,'这辆红色轿车可以在该车道行驶。','2','中间红灯表示中间车道禁行。因此红色轿车不可以在该车道行驶。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(99,'持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人，记分周期内有记分的，应当在记分周期结束后三十日内到公安机关交通管理部门接受审验，同时还应当申报身体条件情况。','1','《道路交通安全法》规定：持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人，应当在每个记分周期结束后三十日内到公安机关交通管理部门接受审验。但在一个记分周期内没有记分记录的，免予本记分周期审验。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(100,'这个地面标记是什么标线？','1','这种标线在到达人行横道前的道路30-50米处设置，它的作用是用来提示驾驶员，前方已接近人行横道，应减速慢行，并须注意行人横过马路。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(101,'行车中在道路情况良好的条件下可以观看车载视频。','2','《实施条例》第六十二条，驾驶机动车不得有下列行为：\r<br/>(一)在车门、车厢没有关好时行车；\r<br/>(二)在机动车驾驶室的前后窗范围内悬挂、放置妨碍驾驶人视线的物品；\r<br/><b>(三)拨打接听手持电话、观看电视等妨碍安全驾驶的行为；</b>\r<br/>(四)下陡坡时熄火或者空挡滑行；\r<br/>(五)向道路上抛撒物品；\r<br/>(六)驾驶摩托车手离车把或者在车把上悬挂物品；\r<br/>(七)连续驾驶机动车超过4小时未停车休息或者停车休息时间少于20分钟；\r<br/>(八)在禁止鸣喇叭的区域或者路段鸣喇叭。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(102,'红色圆圈内标线含义是什么？','3','“公交车”三个字很明显，此标线为公交车停靠站。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(104,'这个路口允许车辆怎样行驶？','1','请看灯，直行和右转灯是绿的。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(105,'造成交通事故后逃逸，尚不构成犯罪的一次记12分。','1','《公安部令第123号》规定，造成交通事故后逃逸，尚不构成犯罪的，一次记12分。凡是逃逸的均为12分。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(106,'在交叉路口、隧道内均不能倒车。','1','《道路交通交通法》规定：机动车在交叉路口、隧道内均不能倒车。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(107,'驾驶人违反交通运输管理法规发生重大事故致人死亡的处3年以上有期徒刑。','2','据《刑法》第一百三十三条：\r<br/>违反交通运输管理法规，因而发生重大事故，致人重伤、死亡或者使公私财产遭受重大损失的，处三年以下有期徒刑或者拘役；\r<br/>交通运输肇事后逃逸或者有其他特别恶劣情节的，处三年以上七年以下有期徒刑；\r<br/>因逃逸致人死亡的，处七年以上有期徒刑。\r<br/>依据法规是3年以下的，所以，本题选择【错误】。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(109,'这个标志是何含义？','4','下陡坡：用以提醒车辆驾驶人小心驾驶。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(110,'这辆红色轿车可以在该车道行驶。','2','中间红灯表示中间车道禁行。因此红色轿车不可以在该车道行驶。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(112,'驾驶人因服兵役、出国（境）等原因延期审验期间不得驾驶机动车。','1','第六十三条  机动车驾驶人因服兵役、出国（境）等原因，无法在规定时间内办理驾驶证期满换证、审验、提交身体条件证明的，可以向机动车驾驶证核发地车辆管理所申请延期办理。申请时应当填写申请表，并提交机动车驾驶人的身份证明、机动车驾驶证和延期事由证明。<br/>延期期限最长不超过三年。【延期期间机动车驾驶人不得驾驶机动车】。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(113,'这个标志是何含义？','2','T型交叉路口：丁字形标志原则上设在与交叉口形状相符的道路上。右侧丁字路口，此标志设在进入T字路口以前的适当位置。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(114,'这属于哪一种标志？','3','指示标志是交通标志中主要标志的一种，，用以指示车辆和行人按规定方向、地点行驶。 指示标志的颜色为蓝底、白图案；形状分为圆形、长方形和正方形。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(116,'这个标志是何含义？','3','禁止直行：表示前方路口禁止一切车辆直行。此标志设在禁止直行的路口前适当位置。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(117,'车辆行至交叉路口，遇有转弯的车辆抢行，应怎样做？','3','如果遇有转弯的车辆抢行，一定要文明驾驶，礼貌让行。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(118,'机动车仪表板上（如图所示）亮表示什么？','1','ABS就是防抱死制动系统',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(121,'行车中遇到正在进行作业的道路养护车辆、工程作业车时要注意避让。','1','按照规定，行车途中遇到正在进行作业的道路养护车辆、工程作业车时要注意避让。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(125,'这个标志是何含义？','1','表示该处为专供行人横穿马路的通道。此标志设在人行横道的两侧。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(126,'车辆在雨天临时停车时，应开启什么灯？','2','即使不是在雨天，我们在路边临时停车时，也要开启危险报警闪光灯。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(128,'黄灯持续闪烁，表示机动车可以加速通过。','2','黄灯持续闪烁，表明已经越过停止线的车辆可以行使，没越过停止线的车辆要停车等待，机动车不能加速通过。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(129,'驾驶机动车在道路上发生交通事故，当事人不能自行移动车辆的，应当保护现场并立即报警。','1','《中华人民共和国道路交通安全法》中第七十条第一款规定，在道路上发生交通事故，车辆驾驶人应当立即停车，保护现场。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(130,'驾驶人有下列哪种违法行为一次记12分？','2','机动车驾驶人有下列违法行为之一，一次记12分：<br/>（一）驾驶与准驾车型不符的机动车的；<br/>（二）饮酒后驾驶机动车的；<br/>（三）驾驶营运客车（不包括公共汽车）、校车载人超过核定人数20％以上的；<br/>（四）造成交通事故后逃逸，尚不构成犯罪的；<br/>（五）上道路行驶的机动车未悬挂机动车号牌的，或者故意遮挡、污损、不按规定安装机动车号牌的；<br/><b>（六）使用伪造、变造的机动车号牌、行驶证、驾驶证、校车标牌或者使用其他机动车号牌、行驶证的；</b><br/>（七）驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的；<br/>（八）驾驶营运客车在高速公路车道内停车的；<br/>（九）驾驶中型以上载客载货汽车、校车、危险物品运输车辆在高速公路、城市快速路上行驶超过规定时速20％以上或者在高速公路、城市快速路以外的道路上行驶超过规定时速50％以上，以及驾驶其他机动车行驶超过规定时速50%以上的；<br/>（十）连续驾驶中型以上载客汽车、危险物品运输车辆超过4小时未停车休息或者停车休息时间少于20分钟的；<br/>（十一）未取得校车驾驶资格驾驶校车的。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(131,'设有安全带装置的车辆，应要求车内乘员系安全带。','1','行车过程中，即使是设有安全装置的车内，驾驶员与非驾驶员都要系安全带，安全第一!',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(132,'这一组交通警察手势是什么信号？','4','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(133,'路中黄色分界线的作用是什么？','2','白色表示同向可跨越车道，黄色表示反向可跨越车道；虚线表示可跨越车道。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(135,'对发生道路交通事故需要收集证据的事故车，交通警察可以依法扣留。','1','《道路交通安全违法行为处理程序规定》第二十五条规定，有下列情形之一的，依法扣留车辆：对发生道路交通事故，因收集证据需要的，可以依法扣留事故车辆。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(137,'这个标志是何含义？','2','黄底标志为警告标志，所以是注意残疾人。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(138,'这个导向箭头是何含义？','3','请记住了 so easy!!',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(140,'在这种情形中前车怎样行驶？','2','《道路法》第五十三条第1款　警车、消防车、救护车、工程救险车执行紧急任务时，其他车辆和行人应当让行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(141,'黄灯持续闪烁，表示机动车可以加速通过。','2','黄灯持续闪烁，表明已经越过停止线的车辆可以行使，没越过停止线的车辆要停车等待，机动车不能加速通过。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(142,'机动车仪表板上（如图所示）亮表示什么？','3','可能出现故障仪表板上的图标才会亮。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(143,'车辆在高速公路上行车，可以频繁地变更车道。','2','车辆在高速公路上行车，可以变更车道，但不可以“频繁”的变更车道。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(144,'这个标志提示哪种车型禁止通行？','2','此标志表示禁止小型客车驶入。轿车属于小型客车。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(145,'雨天行车，遇撑雨伞和穿雨衣的行人在公路上行走时，应怎样做？','3','安全驾驶，减速慢行。遇到撑雨伞和穿雨衣会使视线受阻碍，所以要鸣喇叭，雨天路滑所以要减速。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(146,'这个标志是何含义？','1','避险车道是指在长陡下坡路段行车道外侧增设的供速度失控车辆驶离正线安全减速的专用车道。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(147,'指示标志的作用是什么？','4','指示标志是交通标志中主要标志的一种，用以指示车辆和行人按规定方向、地点行驶。 指示标志的颜色为蓝底、白色图案；形状分为圆形、长方形和正方形。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(149,'上道路行驶的机动车故意遮挡、污损、不按规定安装机动车号牌的一次记几分？','4','《公安部令第123号》规定，上道路行驶的机动车未悬挂机动车号牌的，<b>或者故意遮挡、污损、不按规定安装机动车号牌的，一次记12分 。</b>',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(150,'初次申领驾驶证的驾驶人在实习期内可以单独驾驶机动车上高速公路行驶。','2','《公安部令第123号》第六十五条：<b>驾驶人在实习期内驾驶机动车上高速公路行驶，应当由持相应或者更高准驾车型驾驶证三年以上的驾驶人陪同。</b>其中，驾驶残疾人专用小型自动挡载客汽车的，可以由持有小型自动挡载客汽车以上准驾车型驾驶证的驾驶人陪同。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(151,'3年内有下列哪种行为的人不得申请机动车驾驶证？','4','《机动车驾驶证申领和使用规定》第十二条：三年内有吸食、注射毒品行为或者解除强制隔离戒毒措施未满三年，或者长期服用依赖性精神药品成瘾尚未戒除的，不得申请机动车驾驶证。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(152,'驾驶机动车在道路上发生交通事故，任何情况下都应标明现场位置后，先行撤离现场。','2','因为根据《交通安全法》的规定，如果机动车在道路上面发生了事故，那么必须要马上停车保护现场，如果有人员伤亡的情况，驾驶人应该马上去抢救受伤人员。并且报告执勤的交警或交通管理部门。<b>如果因为抢救伤员而而变动了现场的话，就要标明位置。</b>路人或过往的车辆驾驶人或乘客都应该协助帮忙。如果在道路上发生交通事故，没有造成人员伤亡的，当事人没有对事故有任何争议的，可以撤离现场恢复交通次序，双方自行协商处理损害赔偿就行了。如果说有争议的话，那么不要撤离现场，需要马上报个相关的交警来处理。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(153,'这个标志是何含义？','2','施工路段：用以告示前方道路施工，车辆应减速慢行或绕道行驶。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(155,'车辆驶近人行横道时，应怎样做？','3','因为行人具有随意性，所以要先减速注意观察行人、非机动车动态，确认安全后再通过。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(157,'行车中突遇对向车辆强行超车，占据自己车道时，可不予避让，迫使对方让路。','2','行车要始终记得安全文明驾驶，对方要超车，应及时减速避让。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(158,'图中圈内三角填充区域是什么标线？','3','导流线的形式主要为一个或几个根据路口地形设置的白色V形线或斜纹线区域，表示车辆必须按规定的路线行驶，不得压线或越线行驶。 主要用于过宽、不规则或行驶条件比较复杂的交叉路口,立体交叉的匝道口或其他特殊地点。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(159,'有下列哪种违法行为的机动车驾驶人将被一次记12分？','4','《公安部令第123号》规定，上道路行驶的机动车未悬挂机动车号牌的，或者故意遮挡、污损、不按规定安装机动车号牌的，一次记12分 。其余均为6分。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(160,'机动车驾驶人在实习期内有记满12分记录的，注销其实习的准驾车型驾驶资格。','1','公安部123号令规定：<br/>第六十四条 机动车驾驶人初次申请机动车驾驶证和增加准驾车型后的12个月为实习期。<br/>第六十九条 <b>机动车驾驶人在实习期内有记满12分记录的，注销其实习的准驾车型驾驶资格。</b>',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(162,'这一组交通警察手势是什么信号？','3','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(163,'如图所示，红圈中标记车辆使用灯光的方法是正确的。','2','《中华人民共和国道路交通安全法》第四十八条规定：在没有中心隔离设施或者没有中心线的道路上，夜间会车应当在距相对方向来车150米以外改用近光灯。\r<br/>途中车辆并没有在150米外切换近光灯，距离这么近仍是远光灯，因此是错误的行为。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(164,'在狭窄的路段会车时，应做到礼让三先：先慢、先让、先停。','1','文明驾驶，礼貌让行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(167,'驾驶车辆变更车道时，应提前开启转向灯，注意观察，保持安全距离，驶入要变更的车道。','1','行车变道时，提前开启转向灯，是为了提示后车。同时要观察周围情况，具有变道条件时再变更车道。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(168,'3年内有下列哪种行为的人不得申请机动车驾驶证？','4','《机动车驾驶证申领和使用规定》第十二条：三年内有吸食、注射毒品行为或者解除强制隔离戒毒措施未满三年，或者长期服用依赖性精神药品成瘾尚未戒除的，不得申请机动车驾驶证。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(170,'通过经常发生塌方、泥石流的山区地段，避免停车。','1','经常发生塌方、泥石流的都属于危险地段，所以能尽快离开就尽快离开，避免停车。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(171,'路中两条双黄色虚线是什么标线？','2','路中两条双黄色虚线是潮汐车道线。\r<br/>“潮汐车道”是指根据早晚交通流量不同情况，对有条件的道路，试点开辟潮汐车道，通过车道灯的指示方向变化，控制主干道车道行驶方向，来调整车道数，提高车道使用效率。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(172,'行车中超越同向行驶的自行车时，应怎样做？','4','驾驶机动车遇行人和非机动车肯定要减速慢行，否则会容易撞上，但“慢行”相对机动车的快行是慢的，而相对自行车来的速度来说还是比较快的。并且超车必须要确保安全距离（左右距离），防止与自行车相撞。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(173,'行车中遇有前方发生交通事故，需要帮助时，应怎样做？','3','维护道路交通安全，人人有责。当他人出了事故，请协助保护现场，并立即报警。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(174,'机动车在道路边临时停车时，应怎样做？','1','在路边临时停车时应遵循“不影响正常交通”的原则，因此除了要靠路边之外，还要尽可能留出空间便于其他车辆通行，因此不得逆向或并列停放。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(176,'这个标志是何含义？','1','你看它长的多像丁字。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(178,'机动车发生财产损失交通事故，对应当自行撤离现场而未撤离造成交通堵塞的，可以对驾驶人处以200元罚款。','1','《道路交通事故处理程序规定》第十三条：对应当自行撤离现场而未撤离的，交通警察应当责令当事人撤离现场；造成交通堵塞的，对驾驶人处以200元罚款；驾驶人有其他道路交通安全违法行为的，依法一并处罚。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(179,'机动车在高速公路行驶，下列做法正确的是？','1','紧急车道只能在紧急情况下才能使用，非紧急情况不得占用。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(181,'驾驶与准驾车型不符的机动车一次记几分？','4','根据公安部《机动车驾驶证申领和使用规定》（附件3：道路交通安全违法行为记分分值），<b>驾驶与准驾车型不符的机动车的，一次应记12分。</b>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(182,'驾驶机动车行驶到这个位置时，如果车前轮已越过停止线可以继续通过。','2','车全部越过停车线才可以继续通过，红灯时前轮刚过线必须停下来，否则就是闯红灯。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(183,'这个标志是何含义？','1','高速公路紧急停车带：用于指示紧急停车的位置，设在紧急停车带的前端。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(184,'这个标志是何含义？','3','减速让行：表示车辆应减速让行，告示车辆驾驶员必须慢行或停车，观察干路行车情况，在确保干道车辆优先的前提下，认为安全时方可续行。此标志设在视线良好交叉道路的次要路口。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(185,'驾驶机动车在这种情况下不能直行和左转弯','1','直行和左转都是红灯，所以不能直行和左转。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(187,'申请增加哪些准驾车型的，不得有在造成人员死亡的交通事故中承担同等以上责任的记录？','1','这个题目，只要认真想一下，哪些驾照持有人容易出事，还有申请大型客车驾照的人一般都是驾驶技术过关的，所以这个题目可以从驾照方面考虑，所以选择A!',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(188,'使用其他机动车号牌、行驶证的一次记3分。','2','机动车驾驶人有下列违法行为之一，一次记12分：<br/>（一）驾驶与准驾车型不符的机动车的；<br/>（二）饮酒后驾驶机动车的；<br/>（三）驾驶营运客车（不包括公共汽车）、校车载人超过核定人数20％以上的；<br/>（四）造成交通事故后逃逸，尚不构成犯罪的；<br/>（五）上道路行驶的机动车未悬挂机动车号牌的，或者故意遮挡、污损、不按规定安装机动车号牌的；<br/><b>（六）使用伪造、变造的机动车号牌、行驶证、驾驶证、校车标牌或者使用其他机动车号牌、行驶证的；</b><br/>（七）驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的；<br/>（八）驾驶营运客车在高速公路车道内停车的；<br/>（九）驾驶中型以上载客载货汽车、校车、危险物品运输车辆在高速公路、城市快速路上行驶超过规定时速20％以上或者在高速公路、城市快速路以外的道路上行驶超过规定时速50％以上，以及驾驶其他机动车行驶超过规定时速50%以上的；<br/>（十）连续驾驶中型以上载客汽车、危险物品运输车辆超过4小时未停车休息或者停车休息时间少于20分钟的；',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(189,'如图所示，驾驶机动车在路口遇到这种交通信号时，右转弯的车辆在不妨碍被放行的车辆、行人的情况下，可以通行。','1','驾驶机动车在路口遇到这种圆形交通信号时，右转弯的车辆在不妨碍被放行的车辆、行人的情况下，可以通行。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(191,'驾驶人在超车时，前方车辆不减速、不让道，应怎样做？','2','行车安全第一，如果继续强制超车，会有发生事故的危险。应该停止继续超车。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(193,'图中圈内的白色半圆状标记是什么标线？','4','白色半圆形车距确认线半球半径为30cm，间隔50m设置，一般在一定路段内连续设置。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(194,'在一般道路倒车时，若发现有过往车辆通过，应怎样做？','2','倒车时视线盲区较大，如果有意外情况无法及时处理。因此一旦后方有车辆通过，为了安全一定要停车避让。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(195,'机动车发生轻微财产损失的交通事故，对应当自行撤离现场而未撤离的，交通警察有权责令当事人撤离现场。','1','《中华人民共和国道路交通安全法》中第七十条第二、三款规定：\r<br/>在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜；不即行撤离现场的，应当迅速报告执勤的交通警察或者公安机关交通管理部门。\r<br/>机动车发生轻微财产损失的交通事故，对应当自行撤离现场而未撤离的，交通警察有权责令当事人撤离现场。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(196,'这个标志是何含义？','3','快到云居寺了，箭头指的是方向',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(198,'这个标志的含义是提醒车辆驾驶人前方是傍山险路路段。','2','<p><img src=http://tp.mnks.cn/tp_143.jpg>\r<br/>注意傍山险路\r<br/><img src=http://tp.mnks.cn/tp_140.jpg>\r<br/>注意落石</p>',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(199,'驾驶的车辆正在被其他车辆超越时，应怎样做？','4','超车从左边，如果我们正在被其他车辆超车，应该靠右边减速让行。安全第一。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(200,'驾驶人在道路上醉酒驾驶机动车的处3年以上有期徒刑。','2','醉酒驾驶机动车的，由公安机关交通管理部门约束至酒醒，吊销机动车驾驶证，依法追究刑事责任；5年内不得重新取得机动车驾驶证。\r<br/>醉酒驾驶营运机动车的，由公安机关交通管理部门约束至酒醒，吊销机动车驾驶证，依法追究刑事责任；10年内不得重新取得机动车驾驶证，重新取得机动车驾驶证后，不得驾驶营运机动车。\r<br/>醉驾不用处3年以上有期徒刑。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(202,'在高速公路上遇分流交通管制时，可不驶出高速公路，就地靠边停靠等待管制结束后继续前行。','2','高速公路上不能随便靠边停车，以免造成更大的堵塞。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(204,'机动车驾驶人一次有两个以上违法行为记分的，应当分别计算累加分值。','1','《机动车驾驶证申领和使用规定》第五十六条 对机动车驾驶人的道路交通安全违法行为，处罚与记分同时执行。<b>机动车驾驶人一次有两个以上违法行为记分的，应当分别计算，累加分值。</b>',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(207,'漫水道路行车时，应挂高速档，快速通过。','2','不应该挂高速挡，而是要选用低速挡，以保证汽车有足够的驱动力;入水时应平稳，以防溅起的水花落入电器设备，造成电器短路；发动机中速运转，保持车速，中途不得停车、换挡和急转转向盘',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(209,'这一组交通警察手势是什么信号？','1','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(214,'这个标志是何含义？','1','这个是休息区，服务区是有加油，通车，吃饭的组合标志，停车场就是一个P，图中没有加油站和吃饭的，所以它只是一个休息区。',NULL,'2023-10-13 11:38:04','2023-10-13 11:38:04',0),(216,'驾驶人有使用其他车辆检验合格标志嫌疑的，交通警察可依法扣留车辆。','1','《道路交通安全违法行为处理程序规定》第二十五条规定，有下列情形之一的，依法扣留车辆：有伪造、变造或者使用伪造、变造的机动车登记证书、号牌、行驶证、检验合格标志、 保险标志、驾驶证或者<b>使用其他车辆的机动车登记证书、号牌、行驶证、检验合格标志、保险标志嫌疑的。</b>',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(221,'这一组交通警察手势是什么信号？','1','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(223,'山区道路对安全行车的主要影响是什么？','2','<b>山区道路的特点是：坡多、路窄、急弯多，不像平原地区视线开阔。</b>最关键的一点是山区道路行驶时不容易掌握周围情况，也就是所谓视距不足。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(224,'驾驶机动车要选择绿色箭头灯亮的车道行驶。','1','只有绿灯是表示允许通行，机动车要选择绿色箭头灯亮的车道行驶。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(227,'机动车驾驶人联系电话、联系地址等信息发生变化，应当在信息变更后三十日内，向驾驶证核发地车辆管理所备案。','1','持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人联系电话、从业单位等信息发生变化未及时申报变更信息的，公安机关交通管理部门处二十元以上二百元以下罚款。机动车驾驶人联系电话、联系地址等信息发生变化，应当在信息变更后三十日内，向驾驶证核发地车辆管理所备案。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(228,'以下哪种身体条件，不可以申请机动车驾驶证?','2','红绿色盲会影响观察红绿灯，而我们在路上开车一般都是根据交通信号灯行驶的，所以不能申请驾照。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(229,'这个标志是何含义？','2','互通式立体交叉：路线交叉中的一种重要类型。交叉道路之间立体交叉并以匝道相互连通以实现交通转换的交叉。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(230,'在标志、标线齐全的高速公路上行车，应当按照什么规定的车道和车速行驶？','1','根据规定，在标志、标线齐全的路段，应该按标志、标线行驶。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(231,'驾驶机动车在路口遇到这种信号灯表示什么意思？','2','路口黄灯持续闪烁，警示驾驶人要注意瞭望，确认安全通过。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(232,'指路标志的作用是什么？','3','指路标志是传递道路方向，地点，距离信息的标志。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(234,'在这种路口怎样进行掉头？','1','虚线处可掉头，实线是不能压的，所以实线处不能掉头、变道等。因此应该从图中中心线虚线处掉头才对。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(236,'行车中遇到正在进行作业的道路养护车辆、工程作业车时要注意避让。','1','按照规定，行车途中遇到正在进行作业的道路养护车辆、工程作业车时要注意避让。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(238,'这位驾驶人违反法律规定的行为是什么？','3','《道路交通安全法》第五十一条：机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。很明显，图中司机没有系安全带，属于违法行为。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(239,'驾驶人违反交通运输管理法规发生重大事故致人死亡的处3年以上有期徒刑。','2','据《刑法》第一百三十三条：\r<br/>违反交通运输管理法规，因而发生重大事故，致人重伤、死亡或者使公私财产遭受重大损失的，处三年以下有期徒刑或者拘役；\r<br/>交通运输肇事后逃逸或者有其他特别恶劣情节的，处三年以上七年以下有期徒刑；\r<br/>因逃逸致人死亡的，处七年以上有期徒刑。\r<br/>依据法规是3年以下的，所以，本题选择【错误】。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(240,'夜间驾驶人对物体的观察明显比白天差，视距会有什么变化？','4','夜晚，在路上行车，由于车灯作用，看到的是黑色背景中的亮色物体，所以亮色物体偏大，而眼睛依旧以近大远小的感觉判断，故视距减小。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(241,'路中心黄色虚实线是何含义？','2','虚线可压，实线不可压。实线一侧禁止越线。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(242,'驾驶机动车遇到前方车辆停车排队等候或缓慢行驶时怎么办？','3','《道路交通安全法》第四十五条：<br/>机动车遇有前方车辆停车排队等候或者缓慢行驶时，不得借道超车或者占用对面车道，不得穿插等候的车辆。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(243,'机动车在高速公路上发生故障或交通事故无法正常行驶时由什么车拖曳或牵引？','4','《道路交通安全法》第六十八条：机动车在高速公路上发生故障时，应当依照本法第五十二条的有关规定办理；但是，警告标志应当设置在故障车来车方向一百五十米以外，车上人员应当迅速转移到右侧路肩上或者应急车道内，并且迅速报警。<b>机动车在高速公路上发生故障或者交通事故，无法正常行驶的，应当由救援车、清障车拖曳、牵引。</b>',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(244,'对有伪造或变造号牌、行驶证嫌疑的车辆，交通警察可依法予以扣留','1','对有伪造或变造号牌、行驶证嫌疑的车辆，交通警察可依法予以扣留',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(246,'这一组交通警察手势是什么信号？','3','如果看到别人发火，我们会做由上往下压的动作让他压压火别爆发，同理，由下往下压是让你减速慢行',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(247,'这个标志是何含义？','3','设有ETC的收费站：用以指示前方收费站。设在高速公路、城市快速路主线上渐变段起点处。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(248,'驾驶小型载客汽车在高速公路上时速低于100公里时的最小跟车距离是多少？','3','根据《中华人民共和国道路交通安全法实施条例》第八十条 机动车在高速公路上行驶，车速超过每小时100公里时，应当与同车道前车保持100米以上的距离，车速低于每小时100公里时，与同车道前车距离可以适当缩短，但最小距离不得少于50米。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(250,'夜间行车，驾驶人视距变短，影响观察，同时注意力高度集中，易产生疲劳。','1','高度集中注意力，比较费神，时间久了就会疲倦。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(252,'分离半挂车时，先降下挂车支撑架，然后断开哪个部件，开启牵引座锁止机构，将牵引车驶离挂车？','2','前面都断下了支撑架，后面又开启了锁止机构，所以只有断开制动和电缆。因为挂车时只有锁止和连接电缆。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(253,'酒后驾驶发生重大交通事故被依法追究刑事责任的人不能申请机动车驾驶证。','1','饮酒后或者醉酒驾驶机动车发生重大交通事故，构成犯罪的，依法追究刑事责任，并由公安机关交通管理部门吊销机动车驾驶证，终生不得重新取得机动车驾驶证。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(254,'这个标志是何含义？','1','用于引导行车方向，提示道路使用者前方线形变化，注意谨慎驾驶。设于中央隔离设施端部、渠化设施的端部、桥头等。∧表示俩侧通行，/这个方向的表示左侧通行，这个方向表示右侧通行。交通指路标志大全：http://www.jszks.com/onepage/16752.html',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(255,'在这个路口可以掉头。','2','《道路交通安全法实施条例》第四十九条：机动车在有禁止掉头或者禁止左转弯标志、标线的地点以及在铁路道口、人行横道、桥梁、急弯、陡坡、隧道或者容易发生危险的路段，不得掉头。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(256,'在这条城市道路上行驶的最高速度不能超过多少？','3','《中华人民共和国道路交通安全法实施条例》第四十五条：在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：\r<br/>(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；\r<br/><b>(二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。</b>\r<br/>图中道路，是同方向有1条车道的城市道路，所以最高速度为50公里/小时，本题答案应为C。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(258,'机动车所有人申请转移登记前，应当将涉及该车的道路交通安全违法行为和交通事故处理完毕。','1','已注册登记的机动车所有权发生转移的，现机动车所有人应当自机动车交付之日起三十日内向登记地车辆管理所申请转移登记。机动车所有人申请转移登记前，应当将涉及该车的道路交通安全违法行为和交通事故处理完毕。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(259,'驾驶机动车遇有前方交叉路口交通阻塞时怎么办？','2','《中华人民共和国道路交通安全法实施条例》第五十三条：<br/>机动车遇有前方交叉路口交通阻塞时，应当依次停在路口以外等候，不得进入路口。 所以应该选A。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(261,'驾驶机动车在进出非机动车道时，最高速度不能超过多少？','4','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 \r<br/>（一）<b>进出非机动车道</b>，通过铁路道口、急弯路、窄路、窄桥时；　　 \r<br/>（二）掉头、转弯、下陡坡时；　　 \r<br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 \r<br/>（四）在冰雪、泥泞的道路上行驶时；',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(262,'在这种路段如何行驶？','4','《道路交通安全法实施条例》第五十九条规定：机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意。<b>机动车驶近急弯、坡道顶端等影响安全视距的路段以及超车或者遇有紧急情况时，应当减速慢行，并鸣喇叭示意。</b>\r<br/>因此，本题答案应为A。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(263,'驾驶机动车在没有交通信号的路口遇到前方车辆缓慢行驶时要依次交替通行。','1','《中华人民共和国道路交通安全法》第四十五条明确规定：在车道减少的路段、路口，或者在没有交通信号灯、交通标志、交通标线或者交通警察指挥的交叉路口遇到停车排队等候或者缓慢行驶时，机动车应当依次交替通行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(265,'这个标志是何含义？','1','乡道是白底Y字开头的，县道是白底X开头的，省道是黄底的，国道是红底的。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(267,'驾驶人因服兵役、出国（境）等原因延期审验期间不得驾驶机动车。','1','第六十三条  机动车驾驶人因服兵役、出国（境）等原因，无法在规定时间内办理驾驶证期满换证、审验、提交身体条件证明的，可以向机动车驾驶证核发地车辆管理所申请延期办理。申请时应当填写申请表，并提交机动车驾驶人的身份证明、机动车驾驶证和延期事由证明。<br/>延期期限最长不超过三年。【延期期间机动车驾驶人不得驾驶机动车】。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(268,'饮酒后驾驶机动车的一次记12分。','1','根据规定，<b>饮酒驾驶机动车辆，罚款1000元—2000元、记12分并暂扣驾照6个月</b>；饮酒驾驶营运机动车，罚款5000元，记12分，处以15日以下拘留，并且5年内不得重新获得驾照。醉酒驾驶机动车辆，吊销驾照，5年内不得重新获取驾照，经过判决后处以拘役，并处罚金；醉酒驾驶营运机动车辆，吊销驾照，10年内不得重新获取驾照，终生不得驾驶营运车辆，经过判决后处以拘役，并处罚金。\r<br/>题目描述正确，因此答案为对。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(270,'这个标志是何含义？','2','禁止直行和向左转弯：表示前方路口禁止一切车辆直行和向左转弯。此标志设在禁止直行和向左转弯的路口前适当位置。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(271,'在道路上临时停车不得妨碍其他车辆和行人通行。','1','《道路交通安全法》第五十六条：在道路上临时停车的，不得妨碍其他车辆和行人通行。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(272,'驾驶车辆在道路上行驶时，应当按照规定的速度安全行驶。','1','安全驾驶，请驾驶员按照规定的速度行驶。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(273,'驾驶机动车驶离高速公路时，在这个位置怎样行驶？','1','这是高速路口出口，当要驶离高速路时，要先进入减速车道。正确操作是：提前打开右转向灯，并逐渐降低车速，不能压实线，要越过虚线进入减速车道。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(275,'行车中遇有非机动车准备绕过停放的车辆时，应怎样做？','2','文明驾驶，礼貌让行。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(278,'通过窄路、窄桥时，不得超车。','1','《中华人民共和国道路交通安全法》第四十三条 同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：（四）行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的。 <b>通过隧道，铁路道口，急转弯路段，窄路，窄桥或遇前方道路上有车辆掉头时，不得超车。</b>',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(280,'在大雨天行车，为避免发生“水滑”而造成危险，要控制速度行驶。','1','雨天路面积水，摩擦变小轮胎很容易打滑。安全起见，雨天要减速行驶。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(281,'驾驶证记载的驾驶人信息发生变化的要在多长时间内申请换证？','1','《公安部令第123号》第五十一条：<br/>具有下列情形之一的，机动车驾驶人应当在三十日内到机动车驾驶证核发地车辆管理所申请换证：<br/><b>（一）在车辆管理所管辖区域内，机动车驾驶证记载的机动车驾驶人信息发生变化的；</b><br/>（二）机动车驾驶证损毁无法辨认的。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(282,'同车道行驶的车辆遇前车有下列哪种情形时不得超车？','3','同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：  ①《《前车正在左转弯、掉头、超车的》》;  ②与对面来车有会车可能的;  ③前车为执行紧急任务的警车、消防车、救护车、工程救险车的;  ④行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(283,'如图所示，A车具有优先通行权。','1','直行先行，但若让A车等待B车，则时间更长，所以都是直行的情况下，A车先行。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(284,'漫水道路行车时，应挂高速档，快速通过。','2','不应该挂高速挡，而是要选用低速挡，以保证汽车有足够的驱动力;入水时应平稳，以防溅起的水花落入电器设备，造成电器短路；发动机中速运转，保持车速，中途不得停车、换挡和急转转向盘',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(285,'预计在超车过程中与对面来车有会车可能时，应提前加速超越。','2','预计在超车过程中与对面来车有会车可能时，应当放弃超车。若加速超越，有可能会引起不必要的事故。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(287,'驾驶人未携带哪种证件驾驶机动车上路，交通警察可依法扣留车辆？','1','《道路交通安全违法行为处理程序规定》第十三条 “有下列情形之一的，因无其他机动车驾驶人代替驾驶、违法行为尚未消除、需要调查或者证据保全等原因不能立即放行的，可以扣留车辆：    （一）未悬挂机动车号牌，未放置检验合格标志、保险标志，或者未携带行驶证、机动车驾驶证的；',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(288,'饮酒后只要不影响驾驶操作可以短距离驾驶机动车。','2','《道路交通安全法》第九十一条：饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。对自己对他人负责，只要饮酒就不开车。本题题干描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(289,'行车中超越右侧停放的车辆时，为预防其突然起步或开启车门，应怎样做？','4','留出安全距离、并减速，万一右侧车辆启动才有足够的空间和时间避让。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(290,'行车中遇列队横过道路的学生时，应怎样做？','2','列队横过道路的学生，人数多，通行时间长。降低车速还是容易撞上，停车让行更安全。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(292,'车辆驶近停在车站的公交车辆时，为预防公交车突然起步或行人从车前穿出，应怎样做？','1','遇到行人，减速行驶，随时准备停车。如果紧急制动的话可能会导致后车追尾，所有选择A。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(293,'驾驶人违反交通运输管理法规发生重大事故后，因逃逸致人死亡的，处3年以上7年以下有期徒刑。','2','发生重大事故，致人重伤、死亡或者使公私财产遭受重大损失的，处三年以下有期徒刑或者拘役；交通运输肇事后逃逸或者有其他特别恶劣情节的，处三年以上七年以下有期徒刑；<b>因逃逸致人死亡的，处七年以上有期徒刑。</b>',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(294,'造成交通事故后逃逸构成犯罪的人不能申请机动车驾驶证。','1','《交通法》第一百零一条 违反道路交通安全法律、法规的规定，发生重大交通事故，构成犯罪的，依法追究刑事责任，并由公安机关交通管理部门吊销机动车驾驶证。<br/><b>造成交通事故后逃逸的，由公安机关交通管理部门吊销机动车驾驶证，且终生不得重新取得机动车驾驶证。</b>',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(295,'车辆驶近人行横道时，应怎样做？','3','因为行人具有随意性，所以要先减速注意观察行人、非机动车动态，确认安全后再通过。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(297,'车辆下长坡时要减挡行驶，以充分利用发动机的制动作用。','1','变速箱高档位高速持续运转中，迅速降低变速箱的档位转速，使变速箱的低档位转速对车辆本身的惯性高速产生抑制，从而产生短时间内的所谓发动机制动(变速箱制动)。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(298,'距离宽度不足4米的窄路50米以内的路段不能停车。','1','根据《道路安全法实施条例》第六十三条，机动车在道路上临时停车应当遵守下列规定：<br/>（1）在设有禁停标志、标线的路段，在机动车道与非机动车道、人行道之间设有隔离设施的路段以及人行横道、施工地段，不得停车；<br/>（2）交叉路口、铁路道口、急转弯、<b>宽度不足4米的窄路、</b>桥梁、陡坡、隧道以及距离上述地点50米以内的路段，不得停车；<br/>（3）公共汽车站、急救站、加油站、消防栓或者消防队（站）门前以及距离上述地点30米以内的路段，除使用上述设施的以外，不得停车；<br/>（4）车辆停稳前不得开车门和上下人员，开关车门不得妨碍其他车辆和行人通行；<br/>（5）路边停车应当紧靠道路右侧，机动车驾驶人不得离车，上下人员或者装卸物品后，立即驶离；<br/>（6）城市公共汽车不得在站点以外的路段停车上下乘客。<br/>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(299,'驾驶机动车遇雾、雨、雪等能见度在50米以内时，最高速度不能超过多少？','4','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 \r<br/>（一）进出非机动车道，通过铁路道口、急弯路、窄路、窄桥时；　　 \r<br/>（二）掉头、转弯、下陡坡时；　　 \r<br/>（三）<b>遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时</b>；\r<br/>（四）在冰雪、泥泞的道路上行驶时；',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(300,'距离桥梁、陡坡、隧道50米以内的路段不能停车。','1','《中华人民共和国道路交通安全法实施条例》第六十三条 机动车在道路上临时停车，应当遵守下列规定：交叉路口、铁路道口、急弯路、宽度不足４米的窄路、桥梁、陡坡、隧道以及距离上述地点50米以内的路段，不得停车。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(301,'驾驶车辆变更车道时，应提前开启转向灯，注意观察，保持安全距离，驶入要变更的车道。','1','行车变道时，提前开启转向灯，是为了提示后车。同时要观察周围情况，具有变道条件时再变更车道。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(302,'饮酒后驾驶机动车一次记几分？','4','道路交通安全违法行为记分分值：\r<br/>　　一、机动车驾驶人有下列违法行为之一，<b>一次记12分：</b>\r<br/>　　（一）驾驶与准驾车型不符的机动车的；\r<br/>　　<b>（二）饮酒后驾驶机动车的；</b>\r<br/>　　（三）驾驶营运客车（不包括公共汽车）、校车载人超过核定人数20%以上的；\r<br/>　　（四）造成交通事故后逃逸，尚不构成犯罪的；\r<br/>　　（五）上道路行驶的机动车未悬挂机动车号牌的，或者故意遮挡、污损、不按规定安装机动车号牌的；\r<br/>　　（六）使用伪造、变造的机动车号牌、行驶证、驾驶证、校车标牌或者使用其他机动车号牌、行驶证的；\r<br/>　　（七）驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的；\r<br/>　　（八）驾驶营运客车在高速公路车道内停车的；\r<br/>　　（九）驾驶中型以上载客载货汽车、校车、危险物品运输车辆在高速公路、城市快速路上行驶超过规定时速20%以上或者在高速公路、城市快速路以外的道路上行驶超过规定时速50%以上，以及驾驶其他机动车行驶超过规定时速50%以上的；\r<br/>　　（十）连续驾驶中型以上载客汽车、危险物品运输车辆超过4小时未停车休息或者停车休息时间少于20分钟的；\r<br/>　　（十一）未取得校车驾驶资格驾驶校车的。\r<br/>　',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(303,'这个标志是何含义？','3','村庄：用以提醒车辆驾驶人小心驾驶。设在紧靠村庄、集镇且视线不良的路段以前适当位置。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(305,'驾驶机动车下长坡时，空挡滑行会导致再次挂挡困难。','1','空档滑行时，汽车会失去发动机牵制作用，下坡的过程中，由于重力的作用，汽车速度会越来越快，在没有发动机牵制下的汽车，制动距离要增大很多，也就是说，刹车的作用会大大降低，车辆会处于失控状态，再次挂档也会很难。一旦前方有状况出，驾驶员没法使车辆及时减速或者停下来，造成很大的安全隐患。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(306,'夜间通过没有路灯或路灯照明不良时，应将近光灯转换为远光灯，但同向行驶的后车不得使用远光灯。','1','通过没有路灯或路灯照明不良的路段（非路口）时可以开启远光灯，但是前方有车或行人时，为了不影响他人视线，应关闭远光，改用近光。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(308,'驾驶人违反交通运输管理法规发生重大事故致人重伤的可能判处3年以下徒刑或拘役。','1','刑法第一百三十三条规定：违反交通运输管理法规，因而发生重大事故，致人重伤、死亡或者使公私财产遭受重大损失的，处三年以下有期徒刑或者拘役；交通运输肇事后逃逸或者有其他特别恶劣情节的，处三年以上七年以下有期徒刑；因逃逸致人死亡的，处七年以上有期徒刑。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(310,'驾驶机动车遇有前方交叉路口交通阻塞时怎么办？','2','《中华人民共和国道路交通安全法实施条例》第五十三条：<br/>机动车遇有前方交叉路口交通阻塞时，应当依次停在路口以外等候，不得进入路口。 所以应该选A。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(311,'驾驶人在道路上驾驶机动车追逐竞驶，情节恶劣的处3年以下有期徒刑。','2','道路上驾驶机动车追逐竞驶，情节恶劣的，或者在道路上醉酒驾驶机动车的，处拘役，并处罚金。不用判刑。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(312,'在这种环境下通过路口如何使用灯光？','3','《道路交通安全法实施条例》第五十九条：机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意。\r<br/>因此，本题答案应为D。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(314,'这个标志是何含义？','3','高速公路终点预告：用于指示高速公路或城市快速路终点，设在高速公路或城市快速路终点处。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(315,'驾驶证记载的驾驶人信息发生变化的要在多长时间内申请换证？','1','《公安部令第123号》第五十一条：<br/>具有下列情形之一的，机动车驾驶人应当在三十日内到机动车驾驶证核发地车辆管理所申请换证：<br/><b>（一）在车辆管理所管辖区域内，机动车驾驶证记载的机动车驾驶人信息发生变化的；</b><br/>（二）机动车驾驶证损毁无法辨认的。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(318,'这样在路边临时停放机动车有什么违法行为？','1','图中汽车停在人行横道。规定是：在设有禁停标志、标线的路段，在机动车道与非机动车道、人行道之间设有隔离设施的路段以及人行横道、施工地段，不得停车；',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(320,'车辆临时靠边停车后准备起步时，应先怎样做？','4','起步时要先观察路况，小心驾驶，安全第一。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(325,'路口黄灯持续闪烁，警示驾驶人要注意�望，确认安全通过。','1','路口黄灯持续闪烁，警示驾驶人要注意�望，确认安全通过。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(326,'这一组交通警察手势是什么信号？','2','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(327,'道路最左侧白色虚线区域是何含义？','1','图上有字，“多乘员专用”，因此本题是多乘员车辆专用车道',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(328,'驾驶机动车在没有中心线的公路上，最高速度不能超过每小时70公里。','2','《中华人民共和国道路交通安全法实施条例》第四十五条：<br/>机动车在道路上行驶不得超过限速标志、标线标明的速度。在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：<br/><b>(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；</b><br/>(二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(329,'这个标志是何含义？','1','高速公路右侧出口预告：用于预告前方出口，设置在距离高速公路或城市快速路减速车道的渐变段起点处。出口预告标志应同时附着出口编号标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(331,'上道路行驶的机动车有哪种情形交通警察可依法扣留车辆？','4','未放置检验合格标志，未悬挂机动车号牌，未放置保险标志的，未携带机动车行驶证的都是可依法扣留车辆的。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(332,'车辆涉水后，应保持低速行驶，怎样操作制动踏板，以恢复制动效果？','4','采用间断轻踏摩擦刹车片来加热蒸发水分，恢复制动',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(333,'这个标志是何含义？','2','路面低洼：用以提醒车辆驾驶人减速慢行。设在路面突然低洼以前适当位置。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(334,'驾驶机动车遇到漫水桥时要察明水情确认安全后再低速通过。','1','《道路交通安全法实施条例》第六十四条：机动车行经漫水路或者漫水桥时，应当停车察明水情，确认安全后，低速通过。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(335,'道路交通违法行为累积记分周期是多长时间？','2','《公安部令第123号》第五十五条：道路交通安全违法行为累积记分周期（即记分周期）为12个月，满分为12分，从机动车驾驶证初次领取之日起计算。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(336,'驾驶人有使用其他车辆号牌、行驶证嫌疑的，交通警察可依法扣留车辆。','1','《道路交通安全违法行为处理程序规定》第二十五条规定，有下列情形之一的，依法扣留车辆：有伪造、变造或者使用伪造、变造的机动车登记证书、号牌、行驶证、检验合格标志、 保险标志、驾驶证或者<b>使用其他车辆的机动车登记证书、号牌、行驶证、检验合格标志、保险标志嫌疑</b>的。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(337,'驾驶机动车在上道路行驶前驾驶人要按规定系好安全带。','1','《道路交通安全法》第五十一条：机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(338,'在道路上跟车行驶时，跟车距离不是主要的，只须保持与前车相等的速度，即可防止发生追尾事故。','2','跟车时，与前车保持相同的速度，只能让两车间的距离保持不变，并不能保证安全。而保持足够的安全距离，才能有效防止追尾的发生。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(339,'道路交通安全违法行为累积记分一个周期满分为12分。','1','《公安部令第123号》第五十五条：<br/>道路交通安全违法行为累积记分周期（即记分周期）为12个月，满分为12分，从机动车驾驶证初次领取之日起计算。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(340,'驾驶人驾驶有达到报废标准嫌疑机动车上路的，交通警察依法予以拘留。','2','1、根据《中华人民共和国道路交通安全法》规定，驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废。对驾驶前款所列机动车上道路行驶的驾驶人，处200元以上2000元以下罚款，并吊销机动车驾驶证。\r<br/>2、题目中表述的是“达到报废标准嫌疑机动车”，并未确定为已经报废，按规定无须处罚。\r<br/>因此，题目所说的“交通警察依法予以拘留”是不正确的，本题答案应为错误。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(341,'机动车驾驶人造成重大交通事故后逃逸，构成犯罪的，十年内不能申请机动车驾驶证。','2','《交通法》第一百零一条：违反道路交通安全法律、法规的规定，发生重大交通事故，构成犯罪的，依法追究刑事责任，并由公安机关交通管理部门吊销机动车驾驶证。<b>造成交通事故后逃逸的，由公安机关交通管理部门吊销机动车驾驶证，且终生不得重新取得机动车驾驶证。</b>',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(342,'夜间驾驶机动车在窄路、窄桥会车时正确的做法是使用远光灯。','2','《道路交通安全法实施条例》第四十八条： 在没有中心隔离设施或者没有中心线的道路上，夜间会车应当在距相对方向来车150米以外改用近光灯，<b>在窄路、窄桥与非机动车会车时应当使用近光灯。</b>',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(344,'雨天行车，遇撑雨伞和穿雨衣的行人在公路上行走时，应怎样做？','3','安全驾驶，减速慢行。遇到撑雨伞和穿雨衣会使视线受阻碍，所以要鸣喇叭，雨天路滑所以要减速。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(345,'驾驶机动车在没有交通信号的路口要尽快通过。','2','《道路交通安全法》第四十四条：通过没有交通信号灯、交通标志、交通标线或者交通警察指挥的交叉路口时，应当减速慢行，并让行人和优先通过的车辆先行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(346,'机动车 仪表板上（如图所示）亮表示发动机可能机油压力过高。','2','图片表示发动机可能机油压力不足。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(347,'驾驶机动车在道路上追逐竞驶，情节恶劣，会受到什么处罚？','4','根据《中华人民共和国刑法修正案（八）》规定“在道路上驾驶机动车追逐竞驶，情节恶劣的，或者在道路上醉酒驾驶机动车的，处拘役，并处罚金”。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(349,'驾驶机动车行经漫水路或者漫水桥时，应当停车察明水情，快速通过。','2','《中华人民共和国道路交通管理条例》的第四十六条规定：车辆行经漫水路或漫水桥时,必须停车察明水情,确认安全后,低速通过。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(351,'驶近没有人行横道的交叉路口时，发现有人横穿道路，应怎样做？','1','如果没有人行横道，行人就有可能从任何地方走出。遇到行人一定要减速或停车让行，注意行人的安全。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(352,'驾驶人违反交通运输管理法规发生重大事故后，因逃逸致人死亡的，处3年以上7年以下有期徒刑。','2','发生重大事故，致人重伤、死亡或者使公私财产遭受重大损失的，处三年以下有期徒刑或者拘役；交通运输肇事后逃逸或者有其他特别恶劣情节的，处三年以上七年以下有期徒刑；<b>因逃逸致人死亡的，处七年以上有期徒刑。</b>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(353,'小型汽车驾驶人发生交通事故造成人员死亡，承担同等以上责任未被吊销驾驶证的，应当在记分周期结束后30日内接受审验。','1','《机动车驾驶证申领和使用规定》（公安部令第123号）第六十条：<br/>小型汽车驾驶人发生交通事故造成人员死亡承担同等以上责任未被吊销机动车驾驶证的，应当在本记分周期结束后三十日内到公安机关交通管理部门接受审验。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(354,'夜间行车中，前方出现弯道时，灯光照射会发生怎样的变化？','2','车辆在平面路上行驶，灯光距离不变；在出现一般的弯道，灯光由路中移动到路侧；上坡时，灯光由高变低；出现急弯或大坑时，灯光离开路面。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(355,'高速公路因发生事故造成堵塞时，可在右侧紧急停车带或路肩行驶。','2','紧急停车带：一般用于高速公路发生车祸等事故以后，警车、救护车、消防车等救援车辆的紧急通行车道，其他车辆除特殊情况下，严禁占用该车道行驶或长时间停车。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(356,'对发生道路交通事故需要收集证据的事故车，交通警察可以依法扣留。','1','《道路交通安全违法行为处理程序规定》第二十五条规定，有下列情形之一的，依法扣留车辆：对发生道路交通事故，因收集证据需要的，可以依法扣留事故车辆。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(357,'水淹路面影响行车安全，不易通行的原因是什么？','2','因为水淹没了路面，所以看不清是暗坑和凸起的路面。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(359,'如图所示，驾驶机动车在这种情况下，当C车减速让超车时，A车应该如何行驶？','1','因为C车减速让超车的同时又与来向B车进行会车，此时继续超车容易造成危险，所以应当放弃超越C车。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(360,'在这条公路上行驶的最高速度不能超过多少？','4','根据《中华人民共和国道路交通安全法实施条例》第四十五条：……在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：　　(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；　　(二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。图为公路，所以最高时速为70公里/每小时。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(362,'车辆在路边起步后应尽快提速，并向左迅速转向驶入正常行驶道路。','2','需要先观察，安全才能开过去，不是一起步就迅速进入行驶道行驶，万一后面有车是很危险的，所以“迅速”是错的。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(363,'发生交通事故造成人员受伤时，要保护现场并立即报警。','1','《道路交通事故处理程序规定》 第八条 道路交通事故有下列情形之一的，<b>当事人应当保护现场并立即报警：</b> 　　\r<br/><b>（一）造成人员死亡、受伤的； </b>　　\r<br/>（二）发生财产损失事故，当事人对事实或者成因有争议的，以及虽然对事实或者成因无争议，但协商损害赔偿未达成协议的； 　　\r<br/>（三）机动车无号牌、无检验合格标志、无保险标志的； 　　\r<br/>（四）载运爆炸物品、易燃易爆化学物品以及毒害性、放射性、腐蚀性、传染病病源体等危险物品车辆的； 　　\r<br/>（五）碰撞建筑物、公共设施或者其他设施的；　　\r<br/>（六）驾驶人无有效机动车驾驶证的； 　　\r<br/>（七）驾驶人有饮酒、服用国家管制的精神药品或者麻醉药品嫌疑的； 　　\r<br/>（八）当事人不能自行移动车辆的。 　　\r<br/>发生财产损失事故，并具有前款第二项至第五项情形之一，车辆可以移动的，当事人可以在报警后，在确保安全的原则下对现场拍照或者标划停车位置，将车辆移至不妨碍交通的地点等候处理。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(365,'夜间行车，驾驶人的视野受限，很难观察到灯光照射区域以外的交通情况，因此要减速行驶。','1','晚上开车的时候受到光线暗的局限，相对观察事物的距离也就受到局限，所以视距比较短，因此很难观察到灯光照射区域以外的交通情况。为了安全考虑，减速行驶是必须的。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(367,'已经达到报废标准的机动车经大修后可以上路行驶。','2','《道路交通安全法》第一百条规定：驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废，处200元以上2000元以下罚款，并吊销机动车驾驶证。 \r<br/>已经达到报废标准的车，无论是否经过大修都不能重新开上路。本题描述有误。因此本题答案应为错误。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(368,'车辆不得在高速公路匝道上掉头。','1','按照规定：驶入确定匝道后，迅速提高车速，但不得超过规定速度，在匝道上，不准超车、掉头、停车、和倒车。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(369,'驾驶机动车在车道减少的路口，遇到前方车辆依次停车或缓慢行驶时怎么办？','3','《道路交通安全法实施条例》第五十三条：机动车在车道减少的路口、路段，遇有前方机动车停车排队等候或者缓慢行驶的，应当每车道一辆依次交替驶入车道减少后的路口、路段。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(370,'这个标志是何含义？','3','你看那个P字上边还有个遮挡，说明是室内的，如果没有上边那个遮挡就是露天停车场。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(373,'对未取得驾驶证驾驶机动车的，追究其法律责任。','1','《道路交通安全法》第九十九条规定：<b>未取得机动车驾驶证、</b>机动车驾驶证被吊销或者机动车驾驶证被暂扣期间驾驶机动车的，由公安机关交通管理部门处二百元以上二千元以下罚款，可以并处十五日以下拘留。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(374,'这个导向箭头是何含义？','4','亲，直行哦~~',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(375,'车辆驶入双向行驶隧道前，应开启什么灯？','1','<b>凡是车辆进入双向行驶隧道，都应该开启近光灯或示廓灯，</b>提醒其他车辆，避免发生事故。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(376,'在这种路口怎样进行掉头？','1','虚线处可掉头，实线是不能压的，所以实线处不能掉头、变道等。因此应该从图中中心线虚线处掉头才对。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(377,'车辆行至交叉路口，遇有转弯的车辆抢行，应怎样做？','3','如果遇有转弯的车辆抢行，一定要文明驾驶，礼貌让行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(378,'驾驶机动车遇有前方交叉路口交通阻塞时怎么办？','2','《中华人民共和国道路交通安全法实施条例》第五十三条：<br/>机动车遇有前方交叉路口交通阻塞时，应当依次停在路口以外等候，不得进入路口。 所以应该选A。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(379,'在冰雪道路上行车时，车辆的稳定性降低，加速过急时车轮极易空转或溜滑。','1','冰雪道路，轮胎与地面的摩擦力较小，吸附力较低，只要一加速，就比较容易打滑或者溜空。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(380,'驾驶机动车遇到这种桥时首先怎样办？','3','《道路交通安全法实施条例》第六十四条：机动车行经漫水路或者漫水桥时，应当停车察明水情，确认安全后，低速通过。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(382,'驾驶机动车不能进入红色叉形灯或者红色箭头灯亮的车道。','1','《道路交通安全法实施条例》第四十条规定： 红色叉形灯或者箭头灯亮时，禁止本车道车辆通行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(383,'驾驶机动车在沙尘天气条件下行车不用开启前照灯、示廓灯和后位灯。','2','《道路交通安全法实施条例》第五十八条： 机动车在夜间没有路灯、照明不良或者<b>遇有雾、雨、雪、沙尘、冰雹等低能见度情况下行驶时，应当开启前照灯、示廓灯和后位灯，</b>但同方向行驶的后车与前车近距离行驶时，不得使用远光灯。机动车雾天行驶应当开启雾灯和危险报警闪光灯。\r<br/>题目描述有误，本题答案应为错误。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(385,'驾驶小型载客汽车在高速公路行驶的最低车速为90公里/小时。','2','《道路交通安全法实施条例》第七十八条：高速公路应当标明车道的行驶速度，最高车速不得超过每小时120公里，最低车速不得低于每小时60公里。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(386,'轮式专用机械车驾驶人离开车时，应拉紧手闸，切断电路，锁好车门。','1','',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(387,'这个标志是何含义？','4','高速公路ETC车道：用于指示电子不停车收费车道，设在收费广场渐变段起点前300 m处。表示单向3个收费车道时ETC车道指示标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(388,'夜间驾驶机动车通过人行横道时需要交替使用远近光灯。','1','《道路交通安全法实施条例》第五十九条：机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意。\r<br/>题目描述正确，因此本题答案应为正确。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(389,'驾驶机动车在道路上靠路边停车过程中如何使用灯光？','2','《道路交通安全法实施条例》第五十七条 机动车应当按照下列规定使用转向灯： (一)向左转弯、向左变更车道、准备超车、驶离停车地点或者掉头时，应当提前开启左转向灯； <b>(二)向右转弯、向右变更车道、超车完毕驶回原车道、靠路边停车时，应当提前开启右转向灯。</b>\r<br/>注意题干所说的是“靠边停车过程中”，而非已经靠边停车了。所以应该提前开启右转向灯，本题答案应为D。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(390,'驾驶车辆通过无人看守的铁路道口时，应怎样做？','3','一停，是停在未到铁道前，不是停在铁路上，二看，是在铁道前观察是否有火车要经过，三通过，才是安全通过。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(392,'拼装的机动车只要认为安全就可以上路行驶。','2','《道路交通安全法》第一百条规定：驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废，处200元以上2000元以下罚款，并吊销机动车驾驶证。\r<br/>无论司机认为拼装车是否安全，都不能开上路，一旦开上路就是违法行为。本题描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(393,'驾驶机动车通过漫水路时要加速行驶。','2','《道路交通安全法实施条例》第六十四条：机动车行经漫水路或者漫水桥时，应当停车察明水情，确认安全后，低速通过。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(394,'行驶在高速公路上遇大雾视线受阻时，应当立即紧急制动停车。','2','<b>错在“紧急制动”上，要逐渐减速停车，</b>大雾天气视线不佳，紧急制动容易发生追尾事故，要逐渐减速停车。并且要开启危险警示灯以及雾灯。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(395,'服用国家管制的精神药品可以短途驾驶机动车。','2','《道路交通安全法》第二十二条规定：饮酒、<b>服用国家管制的精神药品</b>或者麻醉药品，或者患有妨碍安全驾驶机动车的疾病，或者过度疲劳影响安全驾驶的，不得驾驶机动车。本题题干表述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(396,'行车中当驾驶人意识到爆胎时，应在控制住方向的情况下，轻踏制动踏板，使车辆缓慢减速，逐渐平稳地停靠于路边。','1','这种情况下为了保障安全，驾驶员首先要做的就是控制住方向，然后缓慢减速，平稳停车。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(397,'行车中遇有非机动车准备绕过停放的车辆时，应怎样做？','2','文明驾驶，礼貌让行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(398,'行车中超越右侧停放的车辆时，为预防其突然起步或开启车门，应怎样做？','4','留出安全距离、并减速，万一右侧车辆启动才有足够的空间和时间避让。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(401,'驾驶机动车在铁路道口、桥梁、陡坡、隧道或者容易发生危险的路段不能掉头。','1','《中华人民共和国道路交通安全法实施条例》第四十九条第一款：<br/>“机动车在有禁止掉头或者禁止左转弯标志、标线的地点以及在铁路道口、人行横道、桥梁、急弯、陡坡、隧道或者容易发生危险的路段,不得掉头。”',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(402,'机动车参加安全技术检验的主要目的是检查车辆各项性能系数，及时消除车辆安全隐患，减少事故发生。','1','机动车参加安全技术检验的主要目的，是为了降低交通安全隐患，减少交通事故发生的可能性。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(403,'车辆上坡行驶，要提前观察路况、坡道长度，及时减挡使车辆保持充足的动力。','1','提前观察路况可以增加行车时的预见性，及时减档保持充足的动力才能顺利上坡。低档速度慢，但是动力足，才能保证不熄火，顺利上坡。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(404,'驾驶的车辆正在被其他车辆超越时，应怎样做？','4','超车从左边，如果我们正在被其他车辆超车，应该靠右边减速让行。安全第一。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(405,'在山区道路遇对向来车时，应怎样会车？','4','山区道路比较复杂，容易出事故，为了安全，会车时要减速或者停车让行。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(407,'机动车仪表板上（如图所示）亮表示什么？','2','位置灯就是车辆示宽灯，也就是当你开启双跳灯后，前后左右四个闪的灯 宽灯就是转向信号灯同时闪烁，用于警告作用。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(408,'这个标志是何含义？','4','上边有十字能看到吧？',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(410,'机动车在道路上发生故障难以移动时要在车后50米以内设置警告标志。','2','机动车在道路上发生故障或者发生交通事故，妨碍交通又难以移动的，应当按照规定开启危险报警闪光灯并在车后50米至100米处设置警告标志，夜间还应当同时开启示廓灯和后位灯。 所以不是在50米内，应该是50米以外100米内。扩展提示：高速公路上要在车后150米外设置警告标志。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(411,'驾驶机动车行经下列哪种路段不得超车？','3','《中华人民共和国道路交通安全法》第四十三条：<br/>同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：<br/>（一）前车正在左转弯、掉头、超车的；<br/>（二）与对面来车有会车可能的；<br/>（三）前车为执行紧急任务的警车、消防车、救护车、工程救险车的；<br/>（四）行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、<b>人行横道、</b>市区交通流量大的路段等没有超车条件的。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(413,'变更车道时只需开启转向灯，便可迅速转向驶入相应的行车道。','2','<b>开转向灯后，要充分观察确认安全后方可使入车道，</b>本题错在“迅速”且没有观察。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(414,'驾驶人将机动车交给驾驶证被暂扣的人驾驶的，交通警察给予口头警告。','2','《道路交通安全法》第九十九条：将机动车交由未取得机动车驾驶证或者机动车驾驶证被吊销、暂扣的人驾驶的，由公安机关交通管理部门处二百元以上二千元以下罚款，可以并处吊销机动车驾驶证。\r<br/>并不是口头警告这么简单。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(415,'驾驶机动车通过没有交通信号和管理人员的铁路道口怎样通过？','3','《道路交通安全法》第四十六条：机动车通过铁路道口时，应当按照交通信号或者管理人员的指挥通行；<b>没有交通信号或者管理人员的，应当减速或者停车，在确认安全后通过。</b>',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(416,'对驾驶已达到报废标准的机动车上路行驶的驾驶人，会受到下列哪种处罚？','4','根据《中华人民共和国道路交通安全法》规定，驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废。<b>对驾驶前款所列机动车上道路行驶的驾驶人，处200元以上2000元以下罚款，并吊销机动车驾驶证。</b>因此本题答案为B。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(417,'饮酒后驾驶机动车的一次记12分。','1','根据规定，<b>饮酒驾驶机动车辆，罚款1000元—2000元、记12分并暂扣驾照6个月</b>；饮酒驾驶营运机动车，罚款5000元，记12分，处以15日以下拘留，并且5年内不得重新获得驾照。醉酒驾驶机动车辆，吊销驾照，5年内不得重新获取驾照，经过判决后处以拘役，并处罚金；醉酒驾驶营运机动车辆，吊销驾照，10年内不得重新获取驾照，终生不得驾驶营运车辆，经过判决后处以拘役，并处罚金。\r<br/>题目描述正确，因此答案为对。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(418,'驾驶机动车在夜间超车时怎样使用灯光？','4','《实施条例》第四十七条规定：机动车超车时，应当提前开启左转向灯、<b>变换使用远、近光灯或者鸣喇叭</b>。夜间视线不佳，应该变换使用远、近光灯提醒其他车辆。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(420,'在交叉路口遇到这种情况时，要在红灯亮以前加速通过路口。','2','黄灯亮了，车身没越过白色停止线，所以要停车等待。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(421,'行车中突遇对向车辆强行超车，占据自己车道时，可不予避让，迫使对方让路。','2','行车要始终记得安全文明驾驶，对方要超车，应及时减速避让。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(422,'在这个路口可以掉头。','2','《道路交通安全法实施条例》第四十九条：机动车在有禁止掉头或者禁止左转弯标志、标线的地点以及在铁路道口、人行横道、桥梁、急弯、陡坡、隧道或者容易发生危险的路段，不得掉头。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(423,'打开位置灯开关，（如图所示）亮起。','1','该指示灯是用来显示车辆示宽灯（也叫示廓灯、位置灯）的工作状态，平时为熄灭状态，当示宽灯打开时，该指示灯随即点亮。当示宽灯关闭或者关闭示宽灯打开大灯时，该指示灯自动熄灭。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(424,'这种情况超车时，从前车的哪一侧超越？','3','超车只能从左侧超越。因为驾驶员在左边，左边超车，驾驶员能观察到相对行驶车道有无来车。而右方超车驾驶员是看不到前方是否来车或速度慢的车辆。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(425,'遇到这种情况的路段，可以进入网状线区域内停车等候。','2','《道路交通安全法实施条例》第五十三条：机动车在遇有前方机动车停车排队等候或者缓慢行驶时，应当依次排队，不得从前方车辆两侧穿插或者超越行驶，不得在人行横道、网状线区域内停车等候。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(426,'进入左侧道路超车，无法保证与正常行驶前车的横向安全间距时，应怎样做？','2','没有超车条件，放弃超车是最安全的行为。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(427,'在路口这个位置时可以加速通过路口。','2','这是红灯信号，应该禁止通过，应停车等待绿灯，再通过。\r<br/>题目描述有误，本题答案应为错误。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(428,'夜间驾驶人对物体的观察明显比白天差，视距会有什么变化？','4','夜晚，在路上行车，由于车灯作用，看到的是黑色背景中的亮色物体，所以亮色物体偏大，而眼睛依旧以近大远小的感觉判断，故视距减小。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(429,'驾驶机动车在高速公路违法占用应急车道行驶的一次记6分。','1','《公安部令第123号》规定，驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶的，一次记6分 。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(431,'驾驶机动车在没有交通信号的路口要尽快通过。','2','《道路交通安全法》第四十四条：通过没有交通信号灯、交通标志、交通标线或者交通警察指挥的交叉路口时，应当减速慢行，并让行人和优先通过的车辆先行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(432,'在道路与铁路道口遇到一个红灯亮时要尽快通过道口。','2','车辆通过设有交通信号的铁路道口时，必须遵守下列规定： 1）两个红灯交替闪烁或红灯稳定亮时，表示火车接近道口，禁止通行； 2）红灯熄灭白灯亮时，表示道口开通，准许车辆通行； 3）当红灯和白灯同时熄灭时，表示停电或者设备发生故障，道口信号无效，在这种情况下，必须听从道口看守人员和道口安全管理人员的指挥，在道口前减速或者停车，确认安全无误后迅速通行。凡遇到道口栏杆（栏门）关闭、音响器发出报警、道口信号显示红色灯光或者道口看守人员示意火车即将通过等任意一种情况时，车辆严禁抢行，必须依次停在停止线外，没有停止线的，停在距最外钢轨的5米以外，并且不得影响栏杆或者栏门的关闭。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(433,'这个路口允许车辆怎样行驶？','2','右转的灯是绿的，所以只能向右转弯。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(434,'驾驶人吸食或注射毒品后驾驶机动车的，一经查获，其驾驶证将被注销。','1','严禁机动车驾驶员酒驾或者毒驾，驾驶人吸食或注射毒品后驾驶机动车的，一经查获，将注销其驾驶证。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(435,'在泥泞路上制动时,车轮易发生侧滑或甩尾，导致交通事故。','1','常识题，泥泞路摩擦系数低。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(436,'机动车在高速公路上遇前方交通受阻时，应当跟随前车顺序排队，并立即开启危险报警闪光灯，防止追尾。','1','开启危险警报闪光灯是为了提醒后车：前方有故障，请减速慢行，谨防追尾。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(437,'行车中当驾驶人意识到车辆爆胎时，应在控制住方向的情况下采取紧急制动，迫使车辆迅速停住。','2','车辆爆胎后，应先控制方向，保持直线行驶，然后利用发动机制动，缓慢减速停车。不能采取紧急制动，容易翻车。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(438,'在这种路段如何行驶？','4','《道路交通安全法实施条例》第五十九条规定：机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意。<b>机动车驶近急弯、坡道顶端等影响安全视距的路段以及超车或者遇有紧急情况时，应当减速慢行，并鸣喇叭示意。</b>\r<br/>因此，本题答案应为A。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(439,'驾驶机动车通过没有交通信号的交叉路口怎样行驶？','1','交叉路口的车流量本来就比较大，在没有交通信号的交叉路口，更应该减速慢行，同时注意观察周围情况，确认可以通过后再通过。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(440,'这是什么操纵装置？','2','这个是点火装置没错。灯光开关在左手边，雨刷开关在右手边。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(442,'机动车仪表板上（如图所示）亮表示什么？','3','可能出现故障仪表板上的图标才会亮。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(445,'路面上的黄色填充标线是何含义？','3','双黄线就是警告注意越界，“打叉的物体”就是不可移动障碍物。因此选接近障碍物标线。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(446,'这两辆车发生追尾的主要原因是什么？','4','因为有人行横道线，所以司机应该知道要提前减速，速度降得低了，后车要刹车就应该应该不会再追尾了。追尾都是后车的责任，因为没有保持足有的安全距离。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(447,'造成交通事故后逃逸，尚不构成犯罪的一次记几分？','3','《公安部令第123号》附件2，造成交通事故后逃逸，尚不构成犯罪的，一次记12分 。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(450,'车辆长时间停放时，应选择停车场停车。','1','路边只能临时停车，要长时间停车，应该选择停车场。以免妨碍其他车辆通行。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(452,'这个仪表是何含义？','1','此为发动机转速表，跟时速表对比记忆。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(453,'机动车驾驶人违法驾驶造成重大交通事故构成犯罪的，依法追究什么责任？','1','根据《道路交通安全法》第一百零一条规定：<b>违反道路交通安全法律、法规规定，发生重大交通事故，构成犯罪的，依法追究刑事责任，\r\n\r\n并由公安机关交通管理部门吊销机动车驾驶证。</b>',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(455,'这个标志是何含义？','1','线型诱导标线型诱导标志，用于引导车辆驾驶人改变行驶方向，促使安全运行。视需要设于易肇事之弯道路段，小半径匝道曲线或中央隔离设施及渠化设施的端部。线形诱导标的颜色规定为：指示性线形诱导标一般道路为蓝底白图案,高速公路为绿底白图案，用以提供一般性行驶指示;警告性线形诱导标为红底白图案，可使车辆驾驶人提高警觉，并准备防范应变之措施。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(456,'这个标志是何含义？','4','乡道是白底Y字开头的，县道是白底X开头的，省道是黄底的，国道是红底的。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(458,'机动车仪表板上（如图所示）亮时，提醒驾驶人安全带插头未插入锁扣。','1','该指示灯用来显示安全带是否处于锁止状态，当该灯点亮时，说明安全带没有及时的扣紧。有些车型会有相应的提示音。当安全带被及时扣紧后，该指示灯自动熄灭。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(460,'机动车驾驶人在实习期内驾驶机动车不得牵引挂车。','1','《公安部令第123号》第六十五条规定：机动车驾驶人在<b>实习期内</b>不得驾驶公共汽车、营运客车或者执行任务的警车、消防车、救护车、工程救险车以及载有爆炸物品、易燃易爆化学物品、剧毒或者放射性等危险物品的机动车；<b>驾驶的机动车不得牵引挂车。</b>',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(461,'驾驶机动车通过窄路、窄桥时的最高速度不能超过每小时30公里。','1','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 <br/>（一）进出非机动车道，通过铁路道口、急弯路、<b>窄路、窄桥时；</b>　　 <br/>（二）掉头、转弯、下陡坡时；　　 <br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 <br/>（四）在冰雪、泥泞的道路上行驶时。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(462,'未取得驾驶证的学员在道路上学习驾驶技能，下列哪种做法是正确的？','1','《公安部令第123号》规定：未取得驾驶证的学员在道路上学习驾驶技能，使用所学车型的教练车由教练员随车指导。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(463,'在交叉路口遇到这种情况时，要在红灯亮以前加速通过路口。','2','黄灯亮了，车身没越过白色停止线，所以要停车等待。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(465,'驾驶车辆进入高速公路加速车道后，应尽快将车速提高到每小时多少公里以上？','2','高速公路加速车道最低行驶速度60公里每小时！ 《道路交通安全法实施条例》第78条规定：<b>“高速公路最高车速不得超过每小时120公里，最低车速不得低于每小时60公里。”</b>',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(466,'图中路口中央黄色路面标记是什么标线？','3','路面黄色网状线表示严格禁止一切车辆长时或临时停车，防止交通阻塞。当黄色网状线前方有车辆停驶时，后车必须在黄色网状线外等候，直到确认黄色网状线前方有足够空间停驶本车时，方可驶过黄色网状线。 另有黄色网状线是施画在重要国家机关、军队、大型企事业单位和公交枢纽门前，确保车辆进出时不致被门前拥堵车辆堵住的措施。网状线是黄色线，停车时禁止占用。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(468,'路中两条双黄色虚线是什么标线？','2','路中两条双黄色虚线是潮汐车道线。\r<br/>“潮汐车道”是指根据早晚交通流量不同情况，对有条件的道路，试点开辟潮汐车道，通过车道灯的指示方向变化，控制主干道车道行驶方向，来调整车道数，提高车道使用效率。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(469,'这辆红色轿车可以在该车道行驶。','2','中间红灯表示中间车道禁行。因此红色轿车不可以在该车道行驶。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(470,'驾驶人在驾驶证丢失后3个月内还可以驾驶机动车。','2','机动车驾驶人在机动车驾驶证丢失后，不得驾驶机动车。如果驾驶人在驾驶证丢失期间开车上路，其行为虽不按“未取得机动车驾驶证”处理，但仍要受到法律的制裁，即依照“未随车携带驾驶证”的情况进行处罚。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(472,'这一组交通警察手势是什么信号？','3','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(473,'雨天对安全行车的主要影响是什么？','1','雨天路面湿滑，雨水会使视线受阻，所以更要注意行车安全。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(474,'机动车在高速公路上发生交通事故无法正常行驶时，用救援车、清障车拖曳、牵引。','1','《中华人民共和国道路交通安全法》第六十八条： 机动车在高速公路上发生故障或者交通事故，无法正常行驶的，应当由救援车、清障车拖曳、牵引。 所以本题是正确的。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(475,'驾驶机动车在道路上向左变更车道时如何使用灯光？','3','《道路交通安全法实施条例》第五十七条,机动车应当按照下列规定使用转向灯：\r<br/><b>(一)向左转弯、向左变更车道、准备超车、驶离停车地点或者掉头时，应当提前开启左转向灯；</b>\r<br/> (二)向右转弯、向右变更车道、超车完毕驶回原车道、靠路边停车时，应当提前开启右转向灯。\r<br/>根据规定，向左变更车道应该<b>提前开启左转向灯</b>，选项C符合规定，因此本题答案为C。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(476,'冰雪道路对安全行车的主要影响是什么？','4','冰雪道路，因汽车轮胎与路面的摩擦系数减小、附着力大大降低，汽车驱动轮很容易打滑或空转，尤其是上坡、起步、停车时还会出现后溜车的现象；车辆在行驶中如果突然加速或减速，很容易造成侧滑及方向跑偏现象；遇情况紧急制动时，制动距离会大大延长。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(477,'这是什么操纵装置？','4','左手边控制灯光、信号组合开关，右手边控制刮水器开关。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(478,'这个标志是何含义？','4','用以指示前方道路为死胡同，无出口、不能通行。该标志为蓝底白色街区红色图案。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(480,'在这个路口右转弯如何通行？','4','对面左转车辆已到路口中间，本车先让对面左转弯车转弯再右转。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(481,'打开左转向灯开关，（如图所示）亮起。','2','图中朝右的箭头亮起，表示打开的是右转向灯。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(483,'机动车在发生碰撞时，安全带可以减轻驾乘人员伤害。','1','安全带加上安全气囊的双重保护才能充分发挥作用。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(484,'初次申领的机动车驾驶证的有效期为多少年？','3','机动车驾驶证有效期首次申领为6年，6年有效期内每个记分周期均未达到12分的，换发10年有效期的机动车驾驶证；在机动车驾驶证的10年有效期内，每个记分周期均未达到12分的，换发长期有效的机动车驾驶证。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(485,'这一组交通警察手势是什么信号？','1','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(486,'这个标志的含义是表示车辆会车时，对方车辆应停车让行。','2','此为<b>会车让行标志</b>，表示车辆会车时，面对标志的车辆必须停车让对方车辆先行。题目描述有误，因此本题答案为错。\r<br/>\r<br/>【拓展延伸】\r<br/><p><img src=http://tp.mnks.cn/tp_176.jpg>\r<br/>停车让行</p><p><img src=http://tp.mnks.cn/tp_178.jpg>\r<br/>会车让行</p><p><img src=http://tp.mnks.cn/tp_219.jpg>\r<br/>会车先行</p>',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(488,'这个标志是何含义？','2','表示只准一切车辆直行和向左转弯。此标志设在车辆必须直行和向左转弯的路口以前适当位置。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(491,'机动车仪表板上（如图所示）亮表示什么？','1','亲，这个真的选A。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(492,'科目三考试分为道路驾驶技能考试和安全文明驾驶常识考试两部分。','1','机动车驾驶人考试内容分为道路交通安全法律、法规和相关知识考试科目（以下简称“科目一”）、场地驾驶技能考试科目（以下简称“科目二”）、<b>道路驾驶技能和安全文明驾驶常识考试科目（以下简称“科目三”）。</b>',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(494,'在驾驶技能准考证明的有效期内，科目二和科目三道路驾驶技能考试预约次数不得超过多少次？','3','在驾驶技能准考证明有效期内，科目二和科目三道路驾驶技能考试预约考试的次数不得超过五次。第五次预约考试仍不合格的，已考试合格的其他科目成绩作废。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(497,'行车中需要借道绕过前方障碍物，但对向来车已接近障碍物时，应怎样做？','4','请注意看题干“对向来车已接近障碍物时”，对方的车更接近障碍物，文明礼让，对向来车优先通行。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(498,'服用国家管制的精神药品可以短途驾驶机动车。','2','《道路交通安全法》第二十二条规定：饮酒、<b>服用国家管制的精神药品</b>或者麻醉药品，或者患有妨碍安全驾驶机动车的疾病，或者过度疲劳影响安全驾驶的，不得驾驶机动车。本题题干表述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(499,'在这个路口不能掉头。','2','此处有指示掉头的标志，而且虚线是可以临时跨越的，所以是可以掉头的。题目描述有误，因此本题答案为错。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(502,'驾驶机动车在下列哪种路段不得超车？','4','《中华人民共和国道路交通安全法》第四十三条：\r<br/>同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：\r<br/>（一）前车正在左转弯、掉头、超车的；\r<br/>（二）与对面来车有会车可能的；\r<br/>（三）前车为执行紧急任务的警车、消防车、救护车、工程救险车的；\r<br/>（四）行经铁路道口、交叉路口、<b>窄桥、弯道、</b>陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(503,'车辆下坡行驶，要适当控制车速，充分利用发动机进行制动。','1','下坡时不能空挡滑行，应充分利用发动机制动。防止下坡时刹车发生打滑，所以应该利用发动机制动。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(504,'机动车仪表板上（如图所示）亮时表示什么？','3','远光灯的灯光走向是直的。近光灯的灯光走向是朝下的。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(506,'图中圈内的白色折线是什么标线？','1','白色平行粗实线，用以提供车辆驾驶人保持行车安全距离的参考，与车距确认标志配合使用。设在常发生超车、易肇事或其他有需要路段。高速公路车距确认标线作用为，见此标线时，驾驶人应与前车保持行车安全距离，避免发生交通事故。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(507,'驾驶机动车在道路上违反道路交通安全法的行为，属于什么行为？','4','题干中明确表述“违反道路交通安全法”，因此该行为属于违法行为。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(508,'机动车向左转弯、向左变更车道，驶离停车地点及掉头时，提前开启左转向灯是为了什么？','3','开启左转向灯，主要是为了提醒后车，开启左转向灯，当然是向左变更车道了。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(509,'机动车在高速公路上发生故障时，将车上人员迅速转移到右侧路肩上或者应急车道内，并且迅速报警。','1','《道路交通安全法》第五十二条： \r<br/>机动车在道路上发生故障，需要停车排除故障时，驾驶人应当立即开启危险报警闪光灯，将机动车移至不妨碍交通的地方停放；难以移动的，应当持续开启危险报警闪光灯，并在来车方向设置警告标志等措施扩大示警距离，必要时迅速报警。 \r<br/>第六十八条： \r<br/>机动车在高速公路上发生故障时，应当依照本法第五十二条的有关规定办理；警告标志应当设置在故障车来车方向一百五十米以外，<b>车上人员应当迅速转移到右侧路肩上或者应急车道内，并且迅速报警。 </b>\r<br/>根据规定，题目描述无误，因此本题答案为对。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(510,'驾驶人在行车中经过积水路面时，应怎样做？','1','行车中经过积水路面时，应特别留意减速慢行；<b>加速或保持正常车速通过，溅起的水花会冲击前挡风玻璃，阻挡驾驶员的视线，</b>无法观察前方情况，极易导致车辆失控或交通事故。另外，驾驶车辆行经两侧有行人或非机动车行驶且有积水的路面时，更应减速慢行，<b>以免泥水飞溅到行人或非机动车驾驶员身上。</b>',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(512,'（如图所示）这个符号的开关控制什么装置？','4','此为前风窗玻璃刮水器。关于如何区分前风窗玻璃刮水器及洗涤器和后风窗玻璃刮水器及洗涤器，你只需记住一点半弧形的图标是前风窗，四四方方的图标就是后风窗。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(513,'遇到这种情形怎样行驶？','1','《道路交通安全法实施条例》第四十八条： 在没有中心隔离设施或者没有中心线的道路上，在有障碍的路段，<b>无障碍的一方先行；</b>但有障碍的一方已驶入障碍路段而无障碍的一方未驶入时，有障碍的一方先行。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(515,'机动车在发生碰撞时，安全带可以减轻驾乘人员伤害。','1','安全带加上安全气囊的双重保护才能充分发挥作用。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(518,'这是什么操纵装置？','3','变速器操纵杆也就是换挡的，当我们速度越开越快的时候也要对应上相应的档位，故此为变速器操纵杆。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(519,'这个路面标记是什么标线？','3','中心圈，设置在交叉路口中心的白色圆形或菱形区域，用以区分车辆大、小转弯，及交叉路口车辆左右转弯的指示，车辆不得压线行驶。机动车向左转弯时，必须紧靠中心圈小转弯。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(521,'驾驶机动车发生以下交通事故，哪种情况适用自行协商解决？','3','《中华人民共和国道路交通安全法实施条例》第八十六条规定:“机动车与机动车、机动车与非机动车在道路上发生未造成人身伤亡的交通事故，当事人对事实及成因无争议的，在记录交通事故的时间、地点、对方当事人的姓名和联系方式、机动车牌号、驾驶证号、保险凭证号、碰撞部位，并共同签名后，撤离现场，自行协商损害赔偿事宜。当事人对交通事故事实及成因有争议的，应当迅速报警。”',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(522,'未上坡的车辆遇到这种情况让对向下坡车先行。','1','《道路交通安全法实施条例》第四十八条： 在狭窄的坡路，上坡的一方先行；但下坡的一方已行至中途而上坡的一方未上坡时，下坡的一方先行。图中下坡的车已经到了中途，可以先行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(523,'这个标志的含义是告示前方是塌方路段，车辆应绕道行驶。','2','<b>图中是 [施工路段] 标志。</b>用以告示前方道路施工，车辆应减速慢行或绕道行驶。该标志可以作为临时标志支设在施工路段以前适当位置。题目描述有误，因此本题答案为错。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(524,'如图所示，以下哪种情况可以超车?(图50a.50b. 50c. 50d)','3','大家都知道的，实线一侧是不可以跨越的，只有虑线的一侧才可以，所以只有50c具备超车条件。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(526,'在路口遇有交通信号灯和交通警察指挥不一致时，按照交通信号灯通行。','2','《道路交通安全法》第三十八条：车辆、行人应当按照交通信号通行；<b>遇有交通警察现场指挥时，应当按照交通警察的指挥通行；</b>在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。\r<br/>题目描述有误，本题答案应为错误。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(527,'驾驶机动车跨越双实线行驶属于什么行为？','2','《道路交通安全法》规定双实线是不能跨越的，违反道路交通安全法，就是违法行为。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(528,'这种握转向盘的动作是正确的。','2','正确的握法是握住方向盘的两边，分别在10点和4点位置，左手为主右手为辅。题中的握法是驾驶的陋习，是有很大的风险的。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(529,'车辆下坡行驶，要适当控制车速，充分利用发动机进行制动。','1','下坡时不能空挡滑行，应充分利用发动机制动。防止下坡时刹车发生打滑，所以应该利用发动机制动。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(530,'这个标志的含义是提醒车辆驾驶人前方路段通过村庄或集镇。','1','警告标志：注意村庄，注意行车安全。用以提醒车辆驾驶人小心驾驶。设在紧靠村庄、集镇且视线不良的路段以前适当位置。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(531,'驾驶机动车在道路上违反道路通行规定应当接受相应的处罚。','1','违反道路通行规定应该接受相应处罚，以提高司机的安全行车意识，避免类似情况再次发生。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(532,'机动车驾驶人造成事故后逃逸构成犯罪的，吊销驾驶证且多长时间不得重新取得驾驶证？','4','《道路交通安全法》第一百零一条规定：<b>造成交通事故后逃逸的且构成犯罪的，由公安机关交通管理部门吊销机动车驾驶证，且终生不得重新取得机动车驾驶证。</b>上述规定泛指各类交通事故，只要是造成交通事故后逃逸的，就应当由公安机关交通管理部门吊销其机动车驾驶证，并且终身不得重新取得驾驶证，而不论其造成交通事故后果的大小。也就是说，法律规定惩罚的交通肇事逃逸行为，与驾驶人造成交通事故后果的轻重无关；构成犯罪的，依法追究刑事责任。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(534,'准驾车型为小型自动挡汽车的，可以驾驶低速载货汽车。','2','小型自动挡汽车（C2）准驾车型：小型、微型自动挡载客汽车以及轻型、微型自动挡载货汽车。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(535,'在暴雨天气驾车，刮水器无法刮净雨水时，应怎样做？','2','暴雨天气驾车，刮水器无法刮净雨水的话，司机很难完全看清楚路况，十分危险。为了安全起见，一定要立即减速靠边停车，不能再继续向前行驶。选项C符合要求，因此答案选C。\r<br/>\r<br/>【拓展延伸】\r<br/>发生这种情况后，司机绝不能继续向前开，“A减速行驶”、“B集中注意力谨慎驾驶”、“D以正常速度行驶”都包含了继续行驶的意思，是错误的。\r<br/>而很多人会认为C项“立即”是错误的，可以这样理解：<b>立即减速靠边停车≠紧急制动</b>，是说司机意识到危险情况后，立即采取了减速并靠边停车这样的应对措施。是没有问题的，注意审题。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(536,'打开前雾灯开关，（如图所示）亮起。','2','图中是后雾灯亮起。\r<br/><p><img src=http://tp.mnks.cn/tp_365.jpg>\r<br/>前雾灯\r<br/><img src=http://tp.mnks.cn/tp_366.jpg>\r<br/>后雾灯</p>',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(538,'机动车在紧急制动时ABS系统会起到什么作用？','4','ABS防抱死系统；车轮不卡死、硬化路面制动时间短平稳、可以用力踩制动、系统自动张合8次/每秒。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(539,'如图所示，驾驶机动车经过这种道路时，应降低车速在道路中间通行。','1','图中道路两侧都有行人，驾驶机动车经过这种道路时，为了保障行人安全，需要降低车速在道路中间通行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(540,'这个标志的含义是提醒车辆驾驶人前方是过水路面或漫水桥路段。','1','警告标志：过水路面，应当减速慢行。用以提醒车辆驾驶人谨慎慢行。设在过水路面或漫水桥路段以前适当位置。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(541,'大型、中型非营运载客汽车从注册登记之日起，超过10年的，每多长时间检验1次？','1','载客的,从注册起,5年内,每年检1次，非载客的,从注册起,10年内,每年检1次,超过10年的,每6个月检1次，看来对客车是要求的严重些!',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(542,'客车失火无法开启车门时，为了减少伤害，应尽快组织乘客如何逃生？','2','因为在客车两侧都备有用来敲碎玻璃的逃生锤！',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(543,'机动车仪表板上（如图所示）亮表示什么？','1','这个没有问题吧。。。老衲也不知如何解释这个题。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(544,'驾驶机动车上道路行驶,不允许超过限速标志标明的最高时速。','1','这个没问题，按照标志行驶不会错。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(545,'这个标志预告什么？','4','<p><img src=http://tp.mnks.cn/tp_283.jpg>\r<br/>高速公路停车区\r<br/><img src=http://tp.mnks.cn/tp_284.jpg>\r<br/>高速公路停车场\r<br/><img src=http://tp.mnks.cn/tp_282.jpg>\r<br/>高速公路服务区预告</p>',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(546,'通过漫水路时要谨慎慢行，不得空挡滑行。','1','机动车行经漫水桥路段时，应当停车察明水情，确认安全后，低速通过。空档滑行十分危险。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(548,'初次申领的机动车驾驶证的有效期为4年。','2','根据规定，初次取得驾驶证的有效期是六年，在六年有效期里的每个记分周期未达到12分的换发十年有效期驾驶证，在十年有效期里的每个记分周期未达到12分的换发长期驾驶证。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(550,'如图所示，在这种情况下不能够超车的原因是什么？','4','按照规定，当前方车辆正在超车时，为了行车安全，驾驶员应该主动放弃超车。而图中蓝色车辆很明显在超车，因此选择D。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(551,'汽车列车的车身越长，转弯半径越小。','2','和圆规画圆性质一样啊，圆规两只脚距离越长所画出半圆半径越大 。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(554,'客车在加油站加油时，驾驶人应当提醒乘客怎么做？','3','怕引起火灾，安全第一。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(556,'行车中当车辆前轮爆胎已发生转向时，驾驶人应双手紧握转向盘，尽力控制车辆直线行驶。','1','行车中当车辆前轮爆胎已发生转向时：第一步：驾驶人应双手紧握转向盘，尽力控制车辆转回原行驶路线。如果不控制方向，很容易翻车，如果急刹车，也很容翻车。第二步：利用发动机制动减速，打开右转向灯缓慢停靠在路肩上。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(558,'如图所示，驾驶机动车遇到这种情况时，以下做法正确的是什么？ ','1','图中所示，河水已经漫过路面，驾驶机动车遇到这种情况时，应停车察明水情，确认安全后，低速通过；不可随意通行。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(559,'驾驶机动车发生交通事故未造成人身伤亡的，责任明确双方无争议时，应当如何处置？','4','《中华人民共和国道路交通安全法》第七十条：明确规定在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜；不即行撤离现场的，应当迅速报告执勤的交通警察或者公安机关交通管理部门。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(560,'如图所示，A车具有优先通行权。','2','三个先行原则：转弯的机动车让直行的车辆先行，右方道路来车先行，右转弯车让左转弯车先行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(563,'这是什么踏板？','1','从左往右数起，分别是离合，制动踏板，加速踏板。图中指的最中间的是制动踏板。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(565,'机动车驶近急弯、坡道顶端等影响安全视距的路段时，减速慢行并鸣喇叭示意是为了什么？','2','视线受阻，彼此看不到，所以就要靠喇叭来提醒，路上的行人或者车辆，我方有来车需要注意安全。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(566,'机动车仪表板上（如图所示）亮时，提醒发动机需要补充机油。','2','这个是燃油液面高度指示灯。图中所示，说明是<b>燃油</b>已到最低液面。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(567,'以下哪种身体条件，不可以申请机动车驾驶证?','2','红绿色盲会影响观察红绿灯，而我们在路上开车一般都是根据交通信号灯行驶的，所以不能申请驾照。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(571,'这个标志的含义是告示车辆驾驶人应慢行或停车，确保干道车辆优先。','1','减速让行，表示车辆应减速让行，告示车辆驾驶人必须慢行或停车，观察干道行车情况，在确保干道车辆优先的前提下，认为安全时方可续行。设于视线良好交叉道路次要道路路口。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(572,'驾驶机动车在高速公路上行驶，遇低能见度气象条件时，能见度在200米以下，车速不得超过每小时多少公里，与同车道前车至少保持多少米的距离？','1','驾驶机动车在高速公路上行驶，遇低能见度气象条件时，能见度在200米以下，车速不得超过60公里/小时，与同车道前车至少保持100米的车距以保证安全。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(573,'如图所示，在这种情形下，对方车辆具有先行权。','1','在两辆车相对行驶的时候，如果道路一侧有障碍物，那么有障碍物一侧的车辆，避让无障碍物一侧的车辆。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(574,'如图所示，当A车后方有执行任务的救护车驶来时，以下做法正确的是什么？','3','行车中遇到执行任务的消防车、救护车、工程救险车时要及时让行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(576,'如图所示，在超车过程中，遇对向有来车时要放弃超车是因为什么?','1','如图所示，对向车道有来车，前方车辆左侧没有足够的安全距离，应放弃超车，避免与对面车辆发生刮擦、相撞。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(577,'如图所示，在这种情况下，会车时必须减速靠右通过。','1','如图所示，车道较窄，会车时，为了防止不必要的摩擦，所以要减速靠右行驶。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(579,'将转向灯开关向下拉，右转向灯亮。','2','向上提：右转向灯亮，（顺时针方向，向右打方向盘的方向） \r<br/>向下拉：左转向灯亮，（逆时针方向，向左打方向盘的方向）',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(583,'申请人因故不能按照预约时间参加考试的，应当提前一日申请取消预约，对申请人未按照预约考试时间参加考试的，判定该次考试不合格。','1','申请人因故不能按照预约时间参加考试的，应当提前一日申请取消预约。对申请人未按照预约考试时间参加考试的，判定该次考试不合格。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(584,'如图所示，当您超越右侧车辆时，应该尽快超越，减少并行时间。','1','减少并行时间一方面是为了防止与右侧车刮擦，另一方面则是为了防止与对向来车相撞。减少并行，快速超越，这样才能确保超车安全。\r<br/>\r<br/>【拓展延伸】\r<br/>不少学员认为“尽快超越”有问题，担心右侧车辆会在超车时突然向左，会发生事故。但在超车时，被超越车辆更大几率情况应靠右侧让行，而正在进行超车的车辆占用了对向车道，随时有可能驶来车辆，如果不尽快完成超车，很容易发生事故。综上所述，题目描述没有问题。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(585,'当您即将通过交叉路口的时候，才意识到要左转而不是向前，以下说法正确的是什么?','2','按规定，交叉路口，不可以停车，不可以倒车，只能继续向前行驶。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(587,'为保障乘车人不受伤害，客车驾驶人或乘务员应当向乘客讲解安全门的使用方法。','1','记忆题',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(588,'这个标志是何含义？','4','车距确认标线作为车辆驾驶人保持行车安全距离的参考，视需要设于较长直线段、易发生追尾事故或其他需要的路段，应与车距确认标志配合使用。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(590,'驾驶机动车在道路上发生交通事故造成人身伤亡的，驾驶人必须报警。','1','《中华人民共和国道路交通安全法》第七十条规定：在道路上发生交通事故，车辆驾驶人应当立即停车，保护现场；造成人身伤亡的，车辆驾驶人应当立即抢救受伤人员，并迅速报告执勤的交通警察或者公安机关交通管理部门。因抢救受伤人员变动现场的，应当标明位置。乘车人、过往车辆驾驶人、过往行人应当予以协助。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(591,'关于醉酒驾驶机动车的处罚，以下说法错误的是什么？','4','根据规定，醉酒驾驶机动车的，由公安机关交通管理部门约束至酒醒，<b>吊销机动车驾驶证</b>，依法追究刑事责任，五年内不得重新取得机动车驾驶证。\r<br/>注意，题目说要选择“说法错误的是什么”，选项D“记6分”与规定的“吊销机动车驾驶证”不符，是错误的。因此本题答案选D。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(592,'机动车仪表板上（如图所示）亮，提示发电机向蓄电池充电。','2','是蓄电池坏了不是电量不足，所以不是充电就能解决问题的，所以应该是充电系统出现故障。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(594,'驾驶机动车变更车道前应仔细观察，目的是判断有无变更车道的条件。','1','变更车道时，不得影响其他车辆的正常通行。注意观察是为了确认有无变更车道的条件。如果没有应该停止变更车道，寻找合适时机。条件允许才可以变更车道。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(596,'机动车仪表板上（如图所示）亮表示什么？','4','驻车制动器处于制动状态，就是手刹没松开。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(597,'行车中，发现行人突然横过道路时，应迅速减速避让。','1','发现行人突然横过道路时，应迅速减速避让，确保行人安全。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(598,'机动车驾驶人在实习期内可以单独驾驶大型营运客车。','2','机动车驾驶人在实习期内不得驾驶公共汽车、营运客车或者执行任务的警车、消防车、救护车、工程救险车以及载有爆炸物品、易燃易爆化学物品、剧毒或者放射性等危险物品的机动车；驾驶的机动车不得牵引挂车。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(599,'驾驶机动车在道路上违反交通安全法规的行为属于违法行为。','1','题干中明确表述“违反道路交通安全法规”，违反法律法规即视为违法行为。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(600,'这个标志是何含义？','3','高速公路加油站：用于指示加油站的位置，设在通往加油站的入口附近。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(601,'在没有交通信号指示的交叉路口，转弯的机动车让直行的车辆和行人先行。','1','车辆通过交叉路口时的通行规定，直行第一、左转弯第二、右转弯第三通行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(602,'这个标志的含义是指示此处设有室内停车场','2','你看那个P字上边没有遮挡，说明是露天停车场，如果P字上边有遮挡就是室内停车场了。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(604,'下列哪个指示灯亮表示车辆在使用近光灯?(图9a. 9b. 9c. 9d)','3','9a是车廓灯，9b是前后雾灯，9c是近光灯，9d制动系统出现异常或故障。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(605,'这是什么交通标志？','3','左侧变窄：用以警告车辆驾驶人注意前方车行道或路面狭窄情况，遇有来车应予减速避让。设在双车道路面宽度缩减为6 m以下的路段起点前方。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(606,'年龄在60岁以上持有准驾车型为大型客车的驾驶人，应当到驾驶证核发地车辆管理所换领准驾车型为小型汽车或小型自动挡汽车的驾驶证。','1','为了安全起见，超过年龄，驾照要降级。 ',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(609,'持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人，在记分周期内有记分的，应当在记分周期结束后三十日内到公安机关交通管理部门接受审验。','1','《公安部令第123号》第六十八条：持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人有下列情形之一的，车辆管理所应当注销其最高准驾车型驾驶资格，并通知机动车驾驶人在三十日内办理降级换证业务，在一个记分周期内有记满12分记录的。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(610,'驾驶机动车在进出非机动车道时，最高速度不能超过多少？','4','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 \r<br/>（一）<b>进出非机动车道</b>，通过铁路道口、急弯路、窄路、窄桥时；　　 \r<br/>（二）掉头、转弯、下陡坡时；　　 \r<br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 \r<br/>（四）在冰雪、泥泞的道路上行驶时；',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(611,'申请人患有精神病的，可以申领机动车驾驶证，但是在发病期间不得驾驶机动车。','2','《机动车驾驶证申领和使用规定》第十二条有下列情形之一的，不得申请机动车驾驶证：<b>(一)有器质性心脏病、癫痫病、美尼尔氏症、眩晕症、癔病、震颤麻痹、精神病、痴呆以及影响肢体活动的神经系统疾病等妨碍安全驾驶疾病的;</b>(二)三年内有吸食、注射毒品行为或者解除强制隔离戒毒措施未满三年，或者长期服用依赖性精神药品成瘾尚未戒除的;(三)造成交通事故后逃逸构成犯罪的;（四）申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的；(五)醉酒驾驶营运机动车依法被吊销机动车驾驶证未满十年的。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(612,'图中圈内两条黄色虚线间的区域是何含义？','4','黄色虚线中的车道里有写字，黄色虚线是想突出引动驾驶员注意的，因此本题是公交专用车道。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(614,'行车中当车辆突然爆胎时，驾驶人切忌慌乱中急踏制动踏板，尽量采用“抢挡”的方法，利用发动机制动使车辆减速。','1','车胎爆胎时紧急制动极易导致车辆侧翻。应该利用抢档的方式，用发动机制动减速停车。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(615,'驾驶机动车遇到沙尘、冰雹、雨、雾、结冰等气象条件时应降低行驶速度。','1','安全第一，毫无疑问。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(618,'严禁在车辆未停稳或行驶途中开启车门，以防乘客被甩出酿成事故。','1','',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(620,'饮酒后只要不影响驾驶操作可以短距离驾驶机动车。','2','《道路交通安全法》第九十一条：饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。对自己对他人负责，只要饮酒就不开车。本题题干描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(621,'驾驶机动车在没有道路中心线的狭窄山路怎样会车？','1','在没有中心隔离设施或者没有中心线的道路上，机动车遇相对方向来车时应当遵守下列规定：\r<br/>1)减速靠右行驶，并与其他车辆、行人保持必要的安全距离。\r<br/>2)在有障碍的路段，无障碍的一方先行：但有障碍的一方已驶入障碍路段而无障碍的一方未驶入时，有障碍的一方先行。\r<br/>3)在狭窄的坡路，上坡的一方先行；但下坡的一方已行至中途而上坡的一方未上坡时，下坡的一方先行。\r<br/>4)<b>在狭窄的山路，不靠山体的一方先行。</b>\r<br/>5)夜间会车应当在距相对方向来车150m以外改用近光灯，在窄路、窄桥与非机动车会车时应当使用近光灯。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(624,'载客汽车除车身外部的行李架和内置的行李箱外，不得载货。','1','应该客车是不可以载货的，但再仔细审题目的话，说的是客车的构造包含了行李架和行李箱，既然是行李架和行李箱是放行李的，又怎么能载货呢。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(625,'人行横道上禁止掉头的原因是什么？','4','人行横道禁止掉头。虽然设有交通隔离护栏路段的人行横道不设禁止掉头交通标志，但规定严禁在人行横道掉头，这主要是为了保护人行横道上行人的安全。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(628,'驾驶机动车应当随身携带哪种证件？','3','《道路交通安全法》第十九条：驾驶人应当按照驾驶证载明的准驾车型驾驶机动车；驾驶机动车时，应当随身携带机动车驾驶证。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(629,'超车需从前车左侧超越，以下说法正确的是什么？','1','除了“便于观察，有利于安全”其他选项表述均错。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(630,'造成交通事故后逃逸且构成犯罪的驾驶人,将吊销驾驶证且终生不得重新取得驾驶证。','1','吊二撤三醉五逃终生，这样就好理解了吧！',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(631,'驾驶人驾驶有达到报废标准嫌疑机动车上路的，交通警察依法予以拘留。','2','1、根据《中华人民共和国道路交通安全法》规定，驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废。对驾驶前款所列机动车上道路行驶的驾驶人，处200元以上2000元以下罚款，并吊销机动车驾驶证。\r<br/>2、题目中表述的是“达到报废标准嫌疑机动车”，并未确定为已经报废，按规定无须处罚。\r<br/>因此，题目所说的“交通警察依法予以拘留”是不正确的，本题答案应为错误。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(632,'驾驶人在驾驶证丢失后3个月内还可以驾驶机动车。','2','机动车驾驶人在机动车驾驶证丢失后，不得驾驶机动车。如果驾驶人在驾驶证丢失期间开车上路，其行为虽不按“未取得机动车驾驶证”处理，但仍要受到法律的制裁，即依照“未随车携带驾驶证”的情况进行处罚。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(633,'夜间会车规定150米以内使用近光灯的原因是什么？','2','<b>在夜间会车时开远光灯，容易造成对方驾驶员眼睛出现盲区，</b>这种情况一般可持续四五秒，而这四五秒极有可能酿成车祸。所以，会车150米以内应使用近光灯。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(634,'营运载客汽车从注册登记之日起，超过5年的，每多长时间检验1次？','1','载客的,从注册起,5年内,每年检1次,超过5年的,每6个月检1次，看来对客车是要求的严重些!',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(636,'公路客运车辆载客超过核定乘员，公安机关交通管理部门依法扣留机动车后，驾驶人应当将超载的乘车人转运，费用由谁承担？','2','怎么可能是JC叔叔掏钱，你懂的！',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(637,'这个标志的含义是告示前方道路有障碍物，车辆左侧绕行。','1','警告标志：左侧绕行，注意安全。用以告示前方道路有障碍物，车辆应按标志指示减速慢行。设在道路障碍物前适当位置。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(638,'机动车、非机动车和行人实行分道行驶，是为了规范交通秩序，提高通行效率。','1','《道路交通安全法》第三十六条：根据道路条件和通行需要，道路划分为机动车道、非机动车道和人行道的，机动车、非机动车、行人实行分道通行。没有划分机动车道、非机动车道和人行道的，机动车在道路中间通行，非机动车和行人在道路两侧通行。规范交通秩序，提高通行效率。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(640,'取得驾驶牵引车准驾车型资格多少年以上的，并在申请前最近5个记分周期内没有满分记录的，可以申请增加大型客车？','2','载客汽车是5年，牵引车是2年 ',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(641,'安装乘客安全带的车辆，应要求乘客在起步前按规定使用安全带。','1','',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(642,'造成交通事故后逃逸且构成犯罪的驾驶人,将吊销驾驶证且终生不得重新取得驾驶证。','1','吊二撤三醉五逃终生，这样就好理解了吧！',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(644,'怎样通过这样的路口？','4','右上角的图标为无人看守的铁道路口，驾驶员要减速或者停车确认安全后再通过。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(645,'机动车登记证书、号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向哪个部门申请补领、换领。','3','根据《机动车登记规定》第四十四条的规定：机动车号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向登记地车辆管理所申请补领、换领。申请时，机动车所有人应当填写申请表并提交身份证明。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(646,'路中心的黄色斜线填充是何含义？','2','图中两侧车道很明显是不同方向的，并且双黄线是禁止跨越的，因此路中心的黄色斜线填充为禁止跨越对向车行道分界线。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(647,'将转向灯开关向上提，左转向灯亮。','2','向上提：右转向灯亮；\r<br/>向下拉：左转向灯亮。\r<br/>题目描述及图片显示均错误，因此本题答案为错。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(648,'准驾车型为小型自动挡汽车的，可以驾驶以下哪种车型？','4','小型自动挡汽车（C2）准驾车型：小型、微型自动挡载客汽车以及轻型、微型自动挡载货汽车。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(649,'在什么情况下不得行车？','2','《道路交通安全法实施条例》第六十二条：驾驶机动车不得在车门、车厢没有关好时行车。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(653,'当行人出现交通安全违法行为时，车辆可以不给行人让行。','2','安全第一，文明驾驶，礼貌让行。无论何时都应该让行。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(655,'这个标志的含义是提醒车辆驾驶人前方是堤坝路段。','2','<p><img src=http://tp.mnks.cn/tp_144.jpg>\r<br/>堤坝路\r<br/><img src=http://tp.mnks.cn/tp_143.jpg>\r<br/>傍山险路</p>',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(656,'准驾车型为小型汽车的，可以驾驶小型自动挡载客汽车。','1','小型汽车（C1）准驾车型：小型、微型载客汽车以及轻型、微型载货汽车；轻型、微型专项作业车，小型、微型自动挡载客汽车以及轻型、微型自动挡载货汽车，低速载货汽车，三轮汽车。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(657,'初次申领的机动车驾驶证的有效期为4年。','2','根据规定，初次取得驾驶证的有效期是六年，在六年有效期里的每个记分周期未达到12分的换发十年有效期驾驶证，在十年有效期里的每个记分周期未达到12分的换发长期驾驶证。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(659,'夜间在道路上会车时，距离对向来车多远将远光灯改用近光灯？','2','《中华人民共和国道路交通安全法》第四十八条：<br/>在没有中心隔离设施或者没有中心线的道路上，机动车遇相对方向来车时应当遵守下列规定：<br/>(一)减速靠右行驶，并与其他车辆、行人保持必要的安全距离；<br/>(二)在有障碍的路段，无障碍的一方先行；但有障碍的一方已驶入障碍路段而无障碍的一方未驶入时，有障碍的一方先行；<br/>(三)在狭窄的坡路，上坡的一方先行；但下坡的一方已行至中途而上坡的一方未上坡时，下坡的一方先行；<br/>(四)在狭窄的山路，不靠山体的一方先行；<br/>(五)<b>夜间会车应当在距相对方向来车150米以外改用近光灯，</b>在窄路、窄桥与非机动车会车时应当使用近光灯。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(660,'机动车驾驶人在一个记分周期内累积记分达到12分，拒不参加学习和考试的，将被公安机关交通管理部门公告其驾驶证停止使用。','1','正确的，所以要及时去处理扣分。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(661,'防抱死制动系统（ABS）在什么情况下可以最大限度发挥制动器效能?','3','ABS的目的就是为了防止刹车的时候一脚踩死，导致翻车什么的。 不过刹车刹死就比较慢（速度N快的时候），效果等于踩下刹车，再松下刹车，反复几次！',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(662,'安装防抱死制动装置（ABS）的机动车紧急制动时，可用力踏制动踏板。','1','ABS防抱死系统；车轮不卡死、硬化路面制动时间短平稳、可以用力踩制动、系统自动张合8次/每秒。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(664,'机动车仪表板上（如图所示）亮，提示右侧车门未关闭。','2','从图而知，是左侧车门是开启状态，因此该标志是指左侧车门未关闭。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(666,'遇后车超车时，在条件许可的情况下应减速靠右让路，是为了给后车留出超车空间。','1','和谐第一，做题就要假扮圣人，人家要超车就减速靠右给他让出超车的位置。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(667,'机动车登记证书、号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向居住地车辆管理所申请补领、换领。','2','根据《机动车登记规定》第四十四条的规定：机动车号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向<b>登记地车</b>辆管理所申请补领、换领。申请时，机动车所有人应当填写申请表并提交身份证明。\r<br/>本题题干说的是“居住地车辆管理所”，是不正确的，本题答案应为错误。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(668,'交通肇事致一人以上重伤，负事故全部或者主要责任，并具有下列哪种行为的，构成交通肇事罪?','3','交通肇事致一人受伤(属于一般事故)，负事故全部或者主要责任，并具有酒后、无证驾驶(这个是没有驾驶证，而不是没带驾驶证)、严重超载等情形之一的，以交通肇事罪处罚。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(669,'隐瞒有关情况或者提供虚假材料申请机动车驾驶证，申请人在多少年内不得再次申领机动车驾驶证？','1','《机动车驾驶证申领和使用规定》第六章第七十八条规定：<b>隐瞒有关情况或者提供虚假材料申领机动车驾驶证的，申请人在一年内不得再次申领机动车驾驶证。</b>',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(670,'这辆在道路上行驶的机动车有下列哪种违法行为？','2','《道路交通安全法》第十一条规定：机动车号牌应当按照规定悬挂并保持清晰、完整，不得故意遮挡、污损。 \r<br/>观察可知，图中机动车的车号牌被故意遮挡住了。但并没有存在逆向行驶、不悬挂号牌、占用非机动车道这些违法行为，因此本题答案应为C。\r<br/>\r<br/>【拓展延伸】\r<br/>图中黄色虚线，设置在 <b>[ 双向道路 ]</b> 的中间，并非单向车道。图中车辆在对向车道上，并未逆向行驶，注意审图。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(671,'机动车驾驶证有效期分为6年、10年、20年。','2','《中华人民共和国道路交通安全法实施条例》第二十六条明确规定： 机动车驾驶人在机动车驾驶证的6年有效期内，每个记分周期均未达到12分的，换发10年有效期的机动车驾驶证；在机动车驾驶证的10年有效期内，每个记分周期均未达到12分的，换发长期有效的机动车驾驶证。\r<br/>有效期为6年，10年，长期。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(672,'驾驶机动车在道路上发生交通事故，任何情况下都应标明现场位置后，先行撤离现场。','2','因为根据《交通安全法》的规定，如果机动车在道路上面发生了事故，那么必须要马上停车保护现场，如果有人员伤亡的情况，驾驶人应该马上去抢救受伤人员。并且报告执勤的交警或交通管理部门。<b>如果因为抢救伤员而而变动了现场的话，就要标明位置。</b>路人或过往的车辆驾驶人或乘客都应该协助帮忙。如果在道路上发生交通事故，没有造成人员伤亡的，当事人没有对事故有任何争议的，可以撤离现场恢复交通次序，双方自行协商处理损害赔偿就行了。如果说有争议的话，那么不要撤离现场，需要马上报个相关的交警来处理。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(673,'准驾车型为小型自动挡汽车的，可以驾驶低速载货汽车。','2','小型自动挡汽车（C2）准驾车型：小型、微型自动挡载客汽车以及轻型、微型自动挡载货汽车。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(678,'如图所示，这这种情况下只要后方、对向无来车，可以掉头。','1','简单来说：黄线是用来画分来回车道的，黄实线是禁止越线行驶。黄虚线是在对面没车来的情况下，可以在黄虚线越过转弯或者是掉头。白实线是用来规分同方向车道的，实线是表示同方向行驶，不能越线到另一同方向车道行驶。白虚线是虚线同方向车道的，可以越线到另一同方向车道行驶。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(679,'遇前方路段车道减少，车辆行驶缓慢，为保证安全有序应该怎样做？','1','第五十三条：机动车在车道减少的路口、路段，遇有前方机动车停车排队等候或者缓慢行驶的，应当每车道一辆依次交替驶入车道减少后的路口、路段。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(681,'以下哪种行为处十日以下拘留，并处一千元以上二千元以下罚款，吊销机动车驾驶证？','4','依据《中华人民共和国道路交通安全法》：饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。<b>因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车的，处十日以下拘留，并处一千元以上二千元以下罚款，吊销机动车驾驶证。</b>',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(682,'图中标志的含义是什么？','3','禁止载货汽车驶入：表示禁止载货机动车通行。此标志设在载货机动车通行的路段入口处。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(684,'这个仪表是何含义？','1','看到那个温度计没说明他是管温度的。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(686,'年龄在60岁以上持有准驾车型为大型货车的驾驶人，应当到驾驶证核发地车辆管理所换领准驾车型为小型汽车或小型自动挡汽车的驾驶证。','1','超过年龄，驾照要降级。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(687,'车辆在山区上坡路驾驶，减挡要及时、准确、迅速，避免拖挡行驶导致发动机动力不足。','1','上坡前要减档，避免拖挡行驶导致的发动机动力不足而熄火。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(688,'如图所示，以下哪种情况可以超车?(图50a.50b. 50c. 50d)','3','大家都知道的，实线一侧是不可以跨越的，只有虑线的一侧才可以，所以只有50c具备超车条件。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(689,'机动车在环形路口内行驶，遇有其他车辆强行驶入时，只要有优先权就可以不避让','2','当然错拉，有优先权就了不起呀?有优先权也要考虑到安全啊，不然容易发生两车相撞。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(690,'机动车在紧急制动时ABS系统会起到什么作用？','4','ABS防抱死系统；车轮不卡死、硬化路面制动时间短平稳、可以用力踩制动、系统自动张合8次/每秒。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(695,'这个路面标记是什么标线？','4','中心圈，设置在交叉路口中心的白色圆形或菱形区域，用以区分车辆大、小转弯，及交叉路口车辆左右转弯的指示，车辆不得压线行驶。机动车向左转弯时，必须紧靠中心圈小转弯。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(696,'发现前方道路堵塞，正确的做法是什么？','1','如果遇到前方拥堵，应该按顺序停车等候。随便加塞或者鸣喇叭都不是文明行车行为。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(697,'仪表显示当前发动机转速是6000转/分钟。','2','题目中仪表中有KM，这是速度和里程表，表示当前汽车的行驶速度是60公里/小时。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(698,'这个标志的含义是提醒车辆驾驶人前方有很强的侧向风。','1','注意横风，这种标志会出现在一些风口或是宽阔的地段,提醒驾驶员前方会有较强侧风。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(701,'专用车道规定的专用使用时间之外，其他车辆可以进入专用车道行驶。','1','重点看题目中的“专用使用时间之外”，审题要仔细。<br/>在规定时间内，道路划设为专用车道的，在专用车道内，只准许规定的车辆通行，其他车辆不得进入专用车道内行驶。在规定时间之外，其他车辆可以行使。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(702,'当驾驶人的血液中酒精含量为100毫克/100毫升时，属于醉酒驾驶。','1','驾驶人的血液中酒精含量在80毫克/100毫升以上，含（80毫克/100毫升）都属于醉酒驾驶。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(703,'申请人在考试过程中有贿赂、舞弊行为的，申请人在多少年内不得再次申领机动车驾驶证？','1','根据123号令第六章法律责任的规定：<b>申请人在考试过程中有贿赂、舞弊行为的，取消考试资格，已经通过考试的其他科目成绩无效；申请人在一年内不得再次申领机动车驾驶证。</b>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(704,'准驾车型为小型自动挡汽车的，可以驾驶低速载货汽车。','2','小型自动挡汽车（C2）准驾车型：小型、微型自动挡载客汽车以及轻型、微型自动挡载货汽车。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(706,'雾天行车时，应及时开启什么灯？','3','雾天行车应开启雾灯和危险报警闪光灯，本题选D。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(707,'在后方无来车的情况下，在隧道中倒车应靠边行驶。','2','《中华人民共和国道路交通安全法实施条例》第五十条规定： 机动车不得在铁路道口、交叉路口、单行路、桥梁、急弯、陡坡或者隧道中倒车。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(708,'驾驶机动车应在变更车道的同时开启转向灯。','2','机动车超车时，应当<b>提前</b>开启左转向灯、变换使用远、近光灯，所以转向灯必须要提前打。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(709,'如图所示，驾驶机动车接打电话容易导致发生交通事故。','1','驾驶机动车需要驾驶员集中注意力观察周围的情况，打电话容易分散驾驶员的注意力，会导致驾驶员不注意周围情况从而引发交通事故。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(710,'驾驶机动车在冰雪道路行驶时，最高速度不能超过多少？','3','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 <br/>（一）进出非机动车道，通过铁路道口、急弯路、窄路、窄桥时；　　 <br/>（二）掉头、转弯、下陡坡时；　　 <br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 <br/>（四）在<b>冰雪</b>、泥泞的道路上行驶时；',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(711,'车辆在通过山区道路弯道时，要做到“减速、鸣喇叭、靠右行”。','1','通过弯道时，大家都知道要减速，而在山区道路，由于前方状况很难了解，因此，若要经过弯道，应当鸣号告知其他车辆你要通过弯道了，靠右行是为了避免在弯道时遇到对向来车，若不靠右行驶，很可能会与来车发生碰撞。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(712,'初次申领机动车驾驶证的，可以申请下列哪种准驾车型？','3','初次申领机动车驾驶证的，可以申请准驾车型为城市公交车、大型货车、小型汽车、小型自动挡汽车、低速载货汽车、三轮汽车、残疾人专用小型自动挡载客汽车、普通三轮摩托车、普通二轮摩托车、轻便摩托车、轮式自行机械车、无轨电车、有轨电车的机动车驾驶证。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(713,'在冰雪路面上行车，必须降低车速、加大安全距离。','1','冰雪路面行驶时，路面滑摩擦系数小，制动距离比平时要大。因此要考虑到紧急状况。如果出现紧急情况，需要有足够的制动距离。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(714,'这是什么操纵装置？','4','左手边控制灯光、信号组合开关，右手边控制刮水器开关。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(717,'浓雾天气能见度低，开启远光灯会提高能见度。','2','不能开启远光灯，因浓雾会反射灯光。应开启雾灯。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(719,'牵引故障车时，牵引与被牵引的机动车，在行驶中都要开启危险报警闪光灯。','1','分析：《中华人民共和国道路交通安全法实施条例》第六十一条 牵引故障机动车应当遵守下列规定： 　　<br/>(一)被牵引的机动车除驾驶人外不得载人，不得拖带挂车； 　　<br/>(二)被牵引的机动车宽度不得大于牵引机动车的宽度； 　　<br/>(三)使用软连接牵引装置时，牵引车与被牵引车之间的距离应当大于4米小于10米； 　　<br/>(四)对制动失效的被牵引车，应当使用硬连接牵引装置牵引； 　　<br/>(五)<b>牵引车和被牵引车均应当开启危险报警闪光灯。</b>汽车吊车和轮式专用机械车不得牵引车辆。摩托车不得牵引车辆或者被其他车辆牵引。转向或者照明、信号装置失效的故障机动车，应当使用专用清障车拖曳。>>>因此本题是对的。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(720,'这个路面标记是什么标线？','3','中心圈，设置在交叉路口中心的白色圆形或菱形区域，用以区分车辆大、小转弯，及交叉路口车辆左右转弯的指示，车辆不得压线行驶。机动车向左转弯时，必须紧靠中心圈小转弯。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(721,'进入减速车道时怎样使用灯光？','4','减速车道在右侧，应该开启右转向灯提醒后车注意减速避让，然后从虚线处进入减速车道。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(722,'汽车列车换档减档时机，要比单车怎样？','2','因为挂车没有小车灵活。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(723,'如图所示，在这种情况下遇右侧车辆变更车道，应减速保持间距，注意避让。','1','碰到右侧车辆打了左转灯，前车轮已经向本车道转过来了，需要减速保持车距，如果不避让硬冲上去，极有可能发生事故。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(724,'遇到这种情形怎样行驶？','1','《道路交通安全法实施条例》第四十八条： 在没有中心隔离设施或者没有中心线的道路上，在有障碍的路段，<b>无障碍的一方先行；</b>但有障碍的一方已驶入障碍路段而无障碍的一方未驶入时，有障碍的一方先行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(726,'载货汽车从注册登记之日起，超过10年的，每年检验多少次？','2','十年内1次，十年后2次',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(729,'机动车仪表板上（如图所示）一直亮，表示发动机控制系统故障。','1','该标志表示发动机控制系统故障，因此本题正确。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(730,'如图所示，A车具有优先通行权。','1','左转让直行！右转让左转！',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(732,'这个标志的含义是告示前方道路是单向通行路段。','2','警告标志：右侧绕行，注意安全。用以告示前方道路有障碍物，车辆应按标志指示减速慢行。设在道路障碍物前适当位置。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(734,'驾驶机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件下，能见度在100米以下时，车速不得超过每小时多少公里，与同车道前车至少保持多少米的距离？','1','能见度小于200米时，开启雾灯、近光灯、示廓灯和前后位灯，车速不得超过每小时60公里，与同车道前车保持100米以上的距离；<b>能见度小于100米时，开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，车速不得超过每小时40公里，与同车道前车保持50米以上的距离；</b>能见度小于50米时，开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，车速不得超过每小时20公里，并从最近的出口尽快驶离高速公路。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(736,'醉酒驾驶营运机动车的，由公安机关交通管理部门约束至酒醒，并做怎样处理？','3','吊销机动车驾驶证，5年内不得重新取得机动车驾驶证，并依法追究刑事责任。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(738,'机动车仪表板上（如图所示）这个符号表示什么？','3','此为车灯总开关。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(739,'机动车仪表板上（如图所示）亮表示什么？','4','A,B,C都巨不靠谱，只有D最合理。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(740,'已注册登记的机动车，改变车身颜色，机动车所有人不需要向登记地车辆管理所申请变更登记。','2','《中华人民共和国道路运输条例》说明，已注册登记的机动车，改变机动车车身颜色的应到公安交通管理部门申请变更登记。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(741,'机动车在抵押登记、质押备案期间不可以办理转移登记。','1','第二十条有下列情形之一的，不予办理转移登记：(一)机动车与该车档案记载内容不一致的；(二)属于海关监管的机动车，海关未解除监管或者批准转让的；(三)机动车在抵押登记、质押备案期间的；(四)有本规定第九条第(一)项、第(二)项、第(七)项、第(八)项、第(九)项规定情形的。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(742,'夜间行车，可选择下列哪个地段超车?','3','超车前，应选择视线良好、平直宽阔、左右均无障碍且前方路段200米范围内没有来车的道路，在保证安全的前提下方能超车。千万不要盲目超车。几个选项中，当然是选路宽车少的路段了。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(743,'路中心黄色虚线的含义是分隔对向交通流，在保证安全的前提下，可越线超车或转弯。','1','黄色虚线是中心线，可以跨越；黄色单实线就已经不能跨越了；黄色双实线是严格禁止压线或者跨越',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(744,'驾驶人要按照驾驶证载明的准驾车型驾驶车辆。','1','《公安部令第123号》规定：驾驶与准驾驶车型不符的机动车的违法行为，一次记12分。处罚200以上1000以下的罚款。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(745,'车辆在较窄的山路上行驶时，如果靠山体的一方不让行，应怎样做？','3','如果靠山体的一方不让行，为了保障行车安全，一定要提前减速或停车避让。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(746,'机动车仪表板上（如图所示）亮表示什么？','4','此为充电电路故障，一般没有故障这些都不会亮的，只有出故障了才会亮。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(747,'如图所示，夜间驾驶机动车与同方向行驶的前车距离较近时，以下做法正确的是什么？','2','夜间驾驶机动车与同方向行驶的前车距离较近时，禁止使用远光灯，避免灯光照射至前车后视镜造成前车驾驶人眩目。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(748,'这个开关控制机动车哪个部位？','2','这个控制风窗玻璃刮水器的。风窗玻璃除雾器和危险报警闪光灯都是按钮形式的，照明、信号装置在你的左手边。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(749,'驾驶机动车上路前应当检查车辆安全技术性能。','1','《道路交通安全法》第二十一条规定：驾驶人驾驶机动车上道路行驶前，应当对机动车的安全技术性能进行认真检查；不得驾驶安全设施不全或者机件不符合技术标准等具有安全隐患的机动车。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(750,'在这种天气条件下行车如何使用灯光？','1','一般雪天能见度低，应该注意灯光的正确使用。一是开启近光灯，帮助驾驶员�望前方情况，使驾驶员对前方情况看得清楚一些。二是开启示廓灯和前后位灯，示意自己车辆的存在，使前后行驶的车辆，能够看到自己的具体位置及通行情况，方便他们采取相应的措施。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(751,'如图所示，驾驶机动车遇前方车流行驶缓慢时，借用公交专用道超车是正确的。','2','公交车道没有规定时间限制的，其他车辆任何时候都不能占用。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(752,'点火开关在LOCK位置拔出钥匙转向盘会锁住。','1','LOCK-----（锁止），ACC------------ (断电)<br/>ON--------（通电），START--------（起动）。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(753,'在这个路口怎样左转弯？','2','注意，本题中出现的红绿灯是最普通的三色灯，不具备指示通行方向的作用，在没有限制行进方向的路口，前方绿灯即可视为左右前均为放行状态。所以只要选择正确的左转方式就可以了，规定左转要靠路口中心点左侧转弯。所以应该选B。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(754,'机动车向左转弯、向左变更车道，驶离停车地点及掉头时，提前开启左转向灯是为了什么？','3','开启左转向灯，主要是为了提醒后车，开启左转向灯，当然是向左变更车道了。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(755,'在高速公路上驾驶机动车，车辆发生故障后的处置方法，以下说法错误的是什么？','3','《道路交通安全法》规定：机动车在高速公路上发生故障时，驾驶人应当立即开启危险报警闪光灯，将车辆移至不妨碍交通的地点，并在车后150米设置警告标志。夜间还应当同时开启示廓灯和后位灯。驾驶人和乘车人应当迅速转移到右侧路肩上或者应急车道内。\r<br/>如果发生故障无法正常行驶的，应当由救援车、清障车拖曳、牵引。而不是车内乘员将其推到紧急停车带上。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(757,'如何通过这种交叉路口？','3','路旁有多名行人马上要横穿马路，一定要减速慢行，保证行人安全。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(758,'机动车驾驶人血液中酒精含量大于或者等于多少可认定为醉驾？','3','驾驶人的血液中酒精含量在80毫克/100毫升以上，含（80毫克/100毫升）都属于醉酒驾驶',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(759,'驾驶机动车发生交通事故后当事人故意破坏、伪造现场、毁灭证据的，应当承担什么责任？','4','发生交通事故后当事人逃逸的，故意破坏、伪造现场、毁灭证据的，均承担全部责任。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(760,'持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人从业单位等信息发生变化的，应当在信息变更后三十日内，向驾驶证核发地车辆管理所备案。','1','机动车驾驶人联系电话、联系地址等信息发生变化，以及持有大型客车、牵引车、城市公交车、中型客车、大型货车准驾车型驾驶证的驾驶人从业单位等信息发生变化，应在信息变更后三十日内，向驾驶证<b>核发地</b>车辆管理所备案。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(761,'驾驶人的驾驶证损毁后不得驾驶机动车。','1','《中华人民共和国道路交通安全法实施条例》第二十八条：机动车驾驶人在机动车驾驶证丢失、损毁、超过有效期或者被依法扣留、暂扣期间以及记分达到12分的，不得驾驶机动车。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(764,'驾驶车辆通过人行横道线时，应注意礼让行人。','1','安全第一，文明驾驶，礼貌让行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(765,'驾驶机动车超车时，被超越车辆未减速让路，应迅速提速超越前方车辆完成超车。','2','被超车辆未减速让行，说明不具备超车条件，此时应该放弃超车，否则容易撞在一起，非常危险。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(767,'这辆小型载客汽车进入高速公路行车道的行为是正确的。','2','这辆车直接驶入了行车道，要先在加速车道，也就是靠右的车道加速后才能驶入，所以错',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(768,'驾驶人连续驾驶不得超过多长时间？','4','《道路交通安全法实施条例》第六十二条：连续驾驶机动车超过4小时应停车休息，停车休息时间不少于20分钟。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(769,'驾驶人要按照驾驶证载明的准驾车型驾驶车辆。','1','《公安部令第123号》规定：驾驶与准驾驶车型不符的机动车的违法行为，一次记12分。处罚200以上1000以下的罚款。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(770,'旋转开关这一档控制机动车哪个部位？','2','此处为雾灯的控制。下边的控制前雾灯，上边的控制后雾灯。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(771,'车辆在通过山区道路弯道时，要做到“减速、鸣喇叭、靠右行”。','1','通过弯道时，大家都知道要减速，而在山区道路，由于前方状况很难了解，因此，若要经过弯道，应当鸣号告知其他车辆你要通过弯道了，靠右行是为了避免在弯道时遇到对向来车，若不靠右行驶，很可能会与来车发生碰撞。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(772,'违反交通信号灯通行的一次记6分。','1','《公安部令第123号》规定，驾驶机动车违反道路交通信号灯通行的，一次记6分 。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(773,'行至漫水路时，应当怎样做？','2','《中华人民共和国道路交通安全法实施条例》第六十四条：<b>机动车行经漫水路或者漫水桥时，应当停车察明水情，确认安全后，低速通过。</b>',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(774,'如图所示，通过有这个标志的路口时应该减速让行。','2','图中为停车让行标志。表示车辆必须在停止线以外停车瞭望，确认安全后，才准许通行。题目描述错误，因此本题答案为错。\r<br/>\r<br/>【拓展延伸】\r<br/><p><img src=http://tp.mnks.cn/tp_176.jpg>\r<br/>停车让行\r<br/><img src=http://tp.mnks.cn/tp_177.jpg>\r<br/>减速让行</p>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(775,'驾驶机动车发生交通事故，仅造成财产损失的，但是对交通事故事实及成因有争议的，应当怎么处理？','1','对于事故成因不明的交通事故，应及时报警，交由警察处理。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(776,'驾驶机动车在道路上掉头时，应当提前开启左转向灯。','1','《中华人民共和国道路交通安全法实施条例》第五十七条机动车应当按照下列规定使用转向灯：（一）向左转弯、向左变更车道、准备超车、驶离停车地点或者掉头时，应当提前开启左转向灯；（二）向右转弯、向右变更车道、超车完毕驶回原车道、靠路边停车时，应当提前开启右转向灯。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(780,'驾驶机动车发生交通事故未造成人身伤亡的，责任明确双方无争议时，应当如何处置？','4','《中华人民共和国道路交通安全法》第七十条：明确规定在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜；不即行撤离现场的，应当迅速报告执勤的交通警察或者公安机关交通管理部门。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(782,'驾驶机动车超车时，可以鸣喇叭替代开启转向灯。','2','机动车超车时，应当提前开启左转向灯、变换使用远、近光灯，打转向灯是必要的步骤。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(783,'行人参与道路交通的主要特点除了行走随意性大、方向多变以外，还喜欢聚集、围观。','1','除了行走随意性大、方向多变以外，喜欢聚集、围观也是行人参与道路交通的特点。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(784,'这个导向箭头是何含义？','4','请记住了哦',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(785,'在暂住地初次申领机动车驾驶证的，不能直接申领大型货车驾驶证。','1','在暂住地初次申领机动车驾驶证的，是可以直接申领大型货车驾驶证的。\r<br/>根据2016年4月1日起开始实行的驾驶证新规，取消了异地考驾照对A/B证的限制，A/B也可以在暂住地申领了，但是需要有当地的居住证或者暂住证。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(786,'驾驶人户籍迁出原车辆管理所需要向什么地方的车辆管理所提出申请？','4','《公安部令第123号》第四十九条：机动车驾驶人户籍迁出原车辆管理所管辖区的，应当向迁入地车辆管理所申请换证。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(788,'下列哪个指示灯亮表示车辆在使用近光灯?(图9a. 9b. 9c. 9d)','3','9a是车廓灯，9b是前后雾灯，9c是近光灯，9d制动系统出现异常或故障。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(789,'如图所示，在这起交通事故中，以下说法正确的是什么？ ','1','这起交通事故主要是因为A车绕开障碍物时未提前观察减速为B车让行造成的，所以A车全责。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(790,'闪光警告信号灯为持续闪烁的黄灯，其作用是提示车辆、行人需要快速通过。','2','持续闪烁的黄灯是为了警告车辆和行人在此处应该注意观察，确认安全后再通过，而非快速通过。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(791,'前方路口这种信号灯亮表示什么意思？','3','黄灯为警示灯，所以是路口警示。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(792,'机动车驾驶证被依法扣押、扣留、暂扣期间能否申请补发？','4','机动车驾驶证被依法扣押、扣留或者暂扣期间，机动车驾驶人不得申请补发。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(793,'这个标志的含义是提醒车辆驾驶人前方是桥头跳车较严重的路段。','2','此为<b>驼峰桥标志</b>。用以提醒车辆驾驶人谨慎驾驶。设在拱度很大，影响视距的驼峰桥以前适当位置。题目描述错误，因此本题答案为错。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(794,'驾驶机动车行驶过程中，遇道路养护车辆从本车道逆向驶来时，以下做法正确的是什么？','1','《中华人民共和国道路交通安全法》第五十四条条明确规定：<b>道路养护车辆、工程作业车进行作业时，在不影响过往车辆通行的前提下，其行驶路线和方向不受交通标志、标线限制，过往车辆和人员应当注意避让。</b>\r<br/>如果道路养护车逆向驶来，一定要靠边减速或停车让行，避免正向相撞。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(795,'驾驶机动车遇紧急事务，可以边开车边接打电话。','2','新修订的《机动车驾驶证申领和使用规定》公布后，2013年1月1日起施行，其中规定：<b>驾驶机动车有拨打、接听手持电话等妨碍安全驾驶的行为的一次记2分。此外，边开车边打电话也会危害人身安全。</b>',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(796,'在这段道路上一定要减少鸣喇叭的频率。','2','右侧的标志是禁止鸣喇叭，不是“减少”，而是绝对不能鸣喇叭。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(797,'这个标志是何含义？','2','注意危险：用以促使车辆驾驶员谨慎慢行。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(798,'在道路上发生未造成人员伤亡且无争议的轻微交通事故如何处置？','3','《道路交通安全法》第七十条：<b>在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜；</b>不立即撤离现场的，应当迅速报告执勤的交通警察或者公安机关交通管理部门。 在道路上发生交通事故，仅造成轻微财产损失，并且基本事实清楚的，当事人应当先撤离现场再进行协商处理。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(800,'在道路上超车时，应尽量加大横向距离，必要时可越实线超车。','2','实线不能跨越，因此不能越实线超车，本题错误。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(801,'如图所示，铁路道口禁止掉头的原因是什么？','4','铁道路口行车条件比较复杂，掉头容易引发事故。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(802,'驾驶机动车在山路行驶时，为了减少油耗，下坡时可以空挡滑行，并使用行车制动器控制速度。','2','下坡时用空档滑行容易烧坏变速器，非常危险，属于交通陋习。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(804,'这个标志是何含义？','1','堤坝路：用以提醒车辆驾驶人小心驾驶，设在沿水库、湖泊、河流等堤坝道路以前适当位置。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(805,'当您即将通过交叉路口的时候，才意识到要左转而不是向前，以下说法正确的是什么?','2','按规定，交叉路口，不可以停车，不可以倒车，只能继续向前行驶。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(808,'因避让特种车辆而发生违法行为，被电子警察拍到时，可向交管部门复议。','1','根据规定，路上碰见特种车辆需要避让。因此避让特种车辆是遵守交通法规的行为，如果因此被电子警察拍到，是可以申请复议的。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(809,'驾驶人一边驾车，一边打手持电话是违法行为。','1','新修订的《机动车驾驶证申领和使用规定》公布后，2013年1月1日起施行，其中规定：驾驶机动车有拨打、接听手持电话等妨碍安全驾驶的行为的一次记2分。并且违反了《道路交通安全法》的相关规定，属于违法行为。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(810,'驾驶机动车由加速车道进入高速公路行驶，以下做法错误的是什么？','4','《中华人民共和国道路交通安全法实施条例》第七十八条：高速公路应当标明车道的行驶速度，最高车速不得超过每小时120公里，最低车速不得低于每小时60公里。在高速公路上行驶的小型载客汽车最高车速不得超过每小时120公里，其他机动车不得超过每小时100公里，摩托车不得超过每小时80公里。同方向有2条车道的，左侧车道的最低车速为每小时100公里；同方向有3条以上车道的，最左侧车道的最低车速为每小时110公里，中间车道的最低车速为每小时90公里。因此，<b>驾车进入高速公路后，不能直接驶入最左车道，要循序渐进。</b>',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(811,'驾驶车辆时，长时间左臂搭在车门窗上，或者长时间右手抓住变速器操纵杆，是一种驾驶陋习。','1','长时间左臂搭在车门窗上，或者长时间右手抓住变速器操纵杆，如果出现紧急情况，驾驶员很难做出良好及时的应对，属于驾驶陋习。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(812,'发生交通事故后，当事人故意破坏、伪造现场、毁灭证据的，承担全部责任。','1','发生交通事故后，当事人故意破坏、伪造现场、毁灭证据的，导致后期无法采证的，应该负全部责任。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(814,'驾驶机动车在高速公路遇到能见度低于100米的气象条件时，最高车速是多少？','1','《道路交通安全法实施条例》第八十一条：机动车在高速公路上行驶，遇有雾、雨、雪、沙尘、冰雹等低能见度气象条件时，应当遵守下列规定：(一)能见度小于200米时，开启雾灯、近光灯、示廓灯和前后位灯，车速不得超过每小时60公里，与同车道前车保持100米以上的距离；<b>(二)能见度小于100米时，开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，车速不得超过每小时40公里，与同车道前车保持50米以上的距离；</b>(三)能见度小于50米时，开启雾灯、近光灯、示廓灯、前后位灯和危险报警闪光灯，车速不得超过每小时20公里，并从最近的出口尽快驶离高速公路。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(815,'这个标志的含义是表示车辆会车时，对方车辆应停车让行。','2','此为<b>会车让行标志</b>，表示车辆会车时，面对标志的车辆必须停车让对方车辆先行。题目描述有误，因此本题答案为错。\r<br/>\r<br/>【拓展延伸】\r<br/><p><img src=http://tp.mnks.cn/tp_176.jpg>\r<br/>停车让行</p><p><img src=http://tp.mnks.cn/tp_178.jpg>\r<br/>会车让行</p><p><img src=http://tp.mnks.cn/tp_219.jpg>\r<br/>会车先行</p>',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(816,'上道路行驶的机动车有哪种情形交通警察可依法扣留车辆？','4','未放置检验合格标志，未悬挂机动车号牌，未放置保险标志的，未携带机动车行驶证的都是可依法扣留车辆的。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(817,'如图所示，在这起交通事故中，以下说法正确的是什么？','2','A车在车道上正常行驶，B车掉头导致事故发生，因此，B车负全责。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(818,'将机动车交由未取得机动车驾驶证的人驾驶的，由公安交通管理部门处二百元以上二千元以下罚款，可以并处以下哪种处罚？','2','将机动车交由未取得机动车驾驶证的人驾驶的，由公安交通管理部门处二百元以上二千元以下罚款，并处以吊销驾驶证的处罚。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(819,'驾驶机动车遇前方交叉路口交通阻塞时，路口内无网状线的，可停在路口内等候。','2','《中华人民共和国道路交通安全法实施条例》第五十三条：机动车遇有前方交叉路口交通阻塞时，应当依次停在路口以外等候，不得进入路口。\r<br/>无论路口内有没有网状线，都不能进入路口等待。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(821,'如图所示，驾驶机动车遇到这种情况时，以下做法正确的是什么？ ','2','机动车在有积水较深的桥下通过行车时，应当停车察明水情，确认安全后，低速通过。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(823,'已注册登记的机动车，机动车所有人住所在车辆管理所管辖区域内迁移或者机动车所有人姓名（单位名称）、联系方式变更的，应当向登记地车辆管理所备案。','1','《机动车登记规定》第十七条规定：已注册登记的机动车，机动车所有人住所在车辆管理所管辖区域内迁移或者机动车所有人姓名(单位名称)、联系方式变更的，应当向登记地车辆管理所备案。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(825,'如图所示，在高速公路最左侧车道行驶，想驶离高速公路，以下说法正确的是什么？','3','变更车道，每次只能变更一条车道，变更之后需行驶一段距离，再变道。不可以连续变更车道。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(826,'自愿降级的驾驶人需要到车辆管理所申请换领驾驶证。','1','自愿降级的驾驶人，由本人带驾驶证、身份证去车管所提出申请，并换领驾驶证。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(828,'车辆下坡行驶，要适当控制车速，充分利用发动机进行制动。','1','下坡时不能空挡滑行，应充分利用发动机制动。防止下坡时刹车发生打滑，所以应该利用发动机制动。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(829,'打开右转向灯开关，（如图所示）亮起。','2','图中朝左的箭头亮起，表示打开的是左转向灯。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(831,'机动车仪表板上（如图所示）亮时，提醒驾驶人安全带插头未插入锁扣。','1','该指示灯用来显示安全带是否处于锁止状态，当该灯点亮时，说明安全带没有及时的扣紧。有些车型会有相应的提示音。当安全带被及时扣紧后，该指示灯自动熄灭。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(832,'如图所示，在这种情况下通过路口，交替使用远近光灯的目的是什么？','1','如图所示，在没有交通信号灯控制的路口，应当交替使用远近光灯示意，提示横向车道上的来车注意。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(833,'驾驶机动车下陡坡时不得有哪些危险行为？','1','《道路交通安全法实施条例》第六十二条规定，驾驶机动车下陡坡时不得熄火或者空挡滑行。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(834,'实习期驾驶人驾驶机动车上高速公路行驶，以下做法正确的是什么？','3','《道路交通安全法》规定：实习期驾驶人驾驶机动车上高速公路行驶，应当由持相应或者更高准驾车型驾驶证三年以上的驾驶人陪同。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(835,'驾驶机动车造成重大交通事故后逃逸，构成犯罪的，由公安机关交通管理部门吊销机动车驾驶证，且终生不得重新取得机动车驾驶证。','1','<b>《道路交通安全法》第一百零一条规定，造成交通事故后逃逸的，由公安机关交通管理部门吊销机动车驾驶证，且终身不得重新取得机动车驾驶证。</b>上述规定泛指各类交通事故，只要是造成交通事故后逃逸的，就应当由公安机关交通管理部门吊销其机动车驾驶证，并且终身不得重新取得驾驶证，而不论其造成交通事故后果的大小。也就是说，法律规定惩罚的交通肇事逃逸行为，与驾驶人造成交通事故后果的轻重无关；构成犯罪的，依法追究刑事责任。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(836,'驾驶人违反交通运输管理法规发生重大事故致人重伤的可能判处3年以下徒刑或拘役。','1','刑法第一百三十三条规定：违反交通运输管理法规，因而发生重大事故，致人重伤、死亡或者使公私财产遭受重大损失的，处三年以下有期徒刑或者拘役；交通运输肇事后逃逸或者有其他特别恶劣情节的，处三年以上七年以下有期徒刑；因逃逸致人死亡的，处七年以上有期徒刑。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(837,'这个导向箭头是何含义？','4','亲，直行哦~~',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(838,'驾驶人在下列哪种情况下不能驾驶机动车？','3','2011年2月25日，十一届全国人大常委会第十九次会议表决通过了刑法修正案（八）。首次将醉酒驾车这种严重危害群众利益的行为规定为犯罪，并于5月1日正式实施。具体规定为：在道路上驾驶机动车追逐竞驶，情节恶劣的，或者在道路上醉酒驾驶机动车的，处拘役，并处罚金。\r<br/>国家严禁机动车驾驶员酒后驾驶，因此本题应选A。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(840,'这个标志是何含义？','2','有火车形状的，为无人看守的铁路口，还有一个栅栏形式的图片为有人看守的铁路口。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(842,'行驶过程中发现车门未关好，应及时关闭车门，否则车辆在转弯等激烈运动过程中会造成人员或货物被甩到车外。','1','行车过程中，车门一定要关紧，否则很容易将车内物品、人甩出。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(843,'服用国家管制的精神药品可以短途驾驶机动车。','2','《道路交通安全法》第二十二条规定：饮酒、<b>服用国家管制的精神药品</b>或者麻醉药品，或者患有妨碍安全驾驶机动车的疾病，或者过度疲劳影响安全驾驶的，不得驾驶机动车。本题题干表述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(844,'这个标志的含义是提醒车辆驾驶人前方是车辆渡口。','1','警告标志：渡口。用以提醒车辆驾驶人谨慎驾驶。设在车辆渡口以前适当位置。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(846,'机动车仪表板上（如图所示）亮表示什么？','3','这个毫无疑问俩边门都开了。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(847,'驾驶机动车在路口遇到这种信号灯表示什么意思？','2','路口黄灯持续闪烁，警示驾驶人要注意瞭望，确认安全通过。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(848,'如图所示，以下哪种情况可以超车?(图51a.51b. 51c. 51d)','1','如图所示，能够超车的必须满足两个条件：一是必须在虚线的一侧，而是对向没有来车。满足这个两个条件的就只有51a了。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(849,'如图所示，驾驶机动车行驶至车道减少的路段时，遇前方机动车排队等候或行驶缓慢时，以下做法正确的是什么？','2','驾驶机动车行驶至车道减少的路段时，前方机动车排队等候或行驶缓慢时，应当每车道一辆依次交替驶入左侧车道。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(850,'驾驶机动车在路口遇到这种信号灯亮时，不能右转弯。','2','只有 红 黄 绿三色且是圆形（如图）交通信号灯的路口，任何情况下都能右转，如果是箭头信号灯的话按箭头方向行驶。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(851,'如图所示，驾驶机动车遇到这种情况，可以轻按喇叭提醒前方非机动车和行人后方有来车。','1','前方有行人和自行车，道路较窄，驾驶机动车遇到这种情况，可以轻按喇叭提醒前方非机动车和行人后方有来车，这样更加安全。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(853,'大雾天行车,多鸣喇叭是为了什么?','1','都说了是大雾天，肯定能见度很低啦，所以要靠耳朵来听。多响几声喇叭，就是要告诉别人，这里有车，提高注意！',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(854,'驾驶人在机动车驾驶证的6年有效期内，每个记分周期均未达到12分的，换发10年有效期的机动车驾驶证。','1','机动车驾驶人在机动车驾驶证的六年有效期内，每个记分周期均未记满12分的，换发十年有效期的机动车驾驶证；在机动车驾驶证的十年有效期内，每个记分周期均未记满12分的，换发长期有效的机动车驾驶证。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(855,'持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人联系电话、从业单位等信息发生变化未及时申报变更信息的，公安机关交通管理部门处二十元以上二百元以下罚款。','1','持有大型客车、牵引车、城市公交车、中型客车、大型货车驾驶证的驾驶人联系电话、从业单位等信息发生变化未及时申报变更信息的，公安机关交通管理部门处二十元以上二百元以下罚款。机动车驾驶人联系电话、联系地址等信息发生变化，应当在信息变更后三十日内，向驾驶证核发地车辆管理所备案。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(856,'机动车发生轻微财产损失的交通事故，对应当自行撤离现场而未撤离的，交通警察有权责令当事人撤离现场。','1','《中华人民共和国道路交通安全法》中第七十条第二、三款规定：\r<br/>在道路上发生交通事故，未造成人身伤亡，当事人对事实及成因无争议的，可以即行撤离现场，恢复交通，自行协商处理损害赔偿事宜；不即行撤离现场的，应当迅速报告执勤的交通警察或者公安机关交通管理部门。\r<br/>机动车发生轻微财产损失的交通事故，对应当自行撤离现场而未撤离的，交通警察有权责令当事人撤离现场。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(857,'以下哪种行为处十日以下拘留，并处一千元以上二千元以下罚款，吊销机动车驾驶证？','4','依据《中华人民共和国道路交通安全法》：饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。<b>因饮酒后驾驶机动车被处罚，再次饮酒后驾驶机动车的，处十日以下拘留，并处一千元以上二千元以下罚款，吊销机动车驾驶证。</b>',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(860,'这个路面标记是何含义？','1','白色为最低限速，黄色为最高限速。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(861,'这个标志是何含义？','3','这个应该能看懂吧？很明显那个小车开灯的效果。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(862,'这个标志是何含义？','2','一道红线是50米，二道100米。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(864,'夜间驾驶机动车在没有中心隔离设施或者没有中心线的道路上行驶，以下哪种情况下应当改用近光灯？','2','夜间驾驶机动车在没有中心隔离设施或者没有中心线的道路上行驶，在会车时，使用远光灯，会使对方看不清路况从而容易发生事故，应该切换近光灯。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(865,'这个标志是何含义？','4','高速公路ETC车道：用于指示电子不停车收费车道，设在收费广场渐变段起点前300 m处。表示单向3个收费车道时ETC车道指示标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(866,'道路最左侧白色虚线区域是何含义？','1','图上有字，“多乘员专用”，因此本题是多乘员车辆专用车道',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(868,'这个标志是何含义？','3','减速让行：表示车辆应减速让行，告示车辆驾驶员必须慢行或停车，观察干路行车情况，在确保干道车辆优先的前提下，认为安全时方可续行。此标志设在视线良好交叉道路的次要路口。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(869,'这个标志是何含义？','4','车距确认标线作为车辆驾驶人保持行车安全距离的参考，视需要设于较长直线段、易发生追尾事故或其他需要的路段，应与车距确认标志配合使用。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(872,'这个标志的含义是提醒车辆驾驶人前方是车辆渡口。','1','警告标志：渡口。用以提醒车辆驾驶人谨慎驾驶。设在车辆渡口以前适当位置。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(874,'这个标志是何含义？','4','禁止鸣喇叭：表示禁止鸣喇叭。此标志设在需要禁止鸣喇叭的地方。禁止鸣喇叭的时间和范围可用辅助标志说明。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(875,'这个标志是何含义？','3','过水路面指的是通过平时无水或流水很少的宽浅河流而修筑的在洪水期间容许水流浸过的路面。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(876,'路缘石上的黄色实线是何含义？','4','黄色实线表示禁止停放车辆，黄色虚线表示禁止长时间停车。题目图片是黄色实线，因此表示禁止停放车辆。选项D正确，答案选D。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(878,'这个标志是何含义？','2','用于引导行车方向，提示道路使用者前方线形变化，注意谨慎驾驶。设于中央隔离设施端部、渠化设施的端部、桥头等。答题技巧：∧表示俩侧通行，/这个方向的表示左侧通行，这个方向表示右侧通行。交通指路标志大全：http://www.jszks.com/onepage/16752.html',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(881,'驾驶小型载客汽车在高速公路上时速超过100公里时的跟车距离是多少？','3','《道路交通安全法实施条例》第八十条：机动车在高速公路上行驶，车速超过每小时100公里时，应当与同车道前车保持100米以上的距离，车速低于每小时100公里时，与同车道前车距离可以适当缩短，但最小距离不得少于50米。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(882,'驾驶机动车经过无划分车道的道路时，可以随意通行。','2','按规定：驾驶机动车经过无划分车道的道路时，机动车在道路中间通行，非机动车和行人在道路两侧通行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(883,'漫水道路行车时，应挂高速档，快速通过。','2','不应该挂高速挡，而是要选用低速挡，以保证汽车有足够的驱动力;入水时应平稳，以防溅起的水花落入电器设备，造成电器短路；发动机中速运转，保持车速，中途不得停车、换挡和急转转向盘',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(884,'车辆前轮胎爆裂，危险较大，方向会立刻向爆胎车轮一侧跑偏，直接影响驾驶人对转向盘的控制。','1','爆胎后，车辆整体平衡会受到影响，会向爆胎的一边跑偏，直接影响到驾驶人对转向盘的控制。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(885,'这个标志是何含义？','3','隧道：用以提醒车辆驾驶人注意慢行。设在双向行驶并且照明不好的隧道口前适当位置。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(886,'如图所示，驾驶机动车在路口遇到这种交通信号时，右转弯的车辆在不妨碍被放行的车辆、行人的情况下，可以通行。','1','驾驶机动车在路口遇到这种圆形交通信号时，右转弯的车辆在不妨碍被放行的车辆、行人的情况下，可以通行。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(888,'在这条车道行驶的最高车速是多少？','2','高速公路上同方向有2条车道的，左侧车道的最低车速为每小时100公里。但是图中最高限度标志为90公里/小时，所以应根据标志来选择90公里/小时。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(890,'如图所示，A车具有优先通行权。','1','直行先行，但若让A车等待B车，则时间更长，所以都是直行的情况下，A车先行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(892,'路面由白色虚线和三角地带标线组成的是什么标线？','4','道路出口标线为白色虚线，主要用于高速公路和其他采用立体交叉道路。该标线作用为，高速公路出入口横向标线或三角地带标线是为驶入或驶出匝道车辆提供安全交汇引导，减少与突出部缘石碰撞。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(893,'机动车在高速公路上发生交通事故无法正常行驶时，用救援车、清障车拖曳、牵引。','1','《中华人民共和国道路交通安全法》第六十八条： 机动车在高速公路上发生故障或者交通事故，无法正常行驶的，应当由救援车、清障车拖曳、牵引。 所以本题是正确的。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(894,'这个标志是何含义？','2','停车检查：表示机动车必须停车接受检查。此标志设在关卡将近处，以便要求车辆接受检查或缴费等手续。标志中可加注说明检查事项。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(895,'如图所示，驾驶机动车在路口前遇到这种情况时，A车具有优先通行权。','1','道路上行驶时，右转弯让左转弯，转弯让直行。因此图中的A车具有优先通行权。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(896,'机动车仪表板上（如图所示）亮表示什么？','2','位置灯就是车辆示宽灯，也就是当你开启双跳灯后，前后左右四个闪的灯 宽灯就是转向信号灯同时闪烁，用于警告作用。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(897,'申请人患有癫痫病的，可以申领机动车驾驶证，但是驾驶时必须有人陪同。','2','申请人患有癫痫病的，因为不知道发病时间，所以驾驶车辆是存在安全隐患的，所以不能申请。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(898,'驾驶机动车下长坡时，空挡滑行会导致再次挂挡困难。','1','空档滑行时，汽车会失去发动机牵制作用，下坡的过程中，由于重力的作用，汽车速度会越来越快，在没有发动机牵制下的汽车，制动距离要增大很多，也就是说，刹车的作用会大大降低，车辆会处于失控状态，再次挂档也会很难。一旦前方有状况出，驾驶员没法使车辆及时减速或者停下来，造成很大的安全隐患。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(899,'载货汽车从注册登记之日起，多长时间以内每年检验1次？','4','十年之内是一次，十年之后是两次！',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(900,'驾驶机动车需要在路边停车时怎样选择停车地点？','2','一般人行道上是不能停车的，路边也不能随意停车。在路边可以顺向临时停车，但是不能逆向停车。所以最佳停车地点还是停车泊位内。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(902,'车速超过规定时速达到50%的一次记3分。','2','《公安部令第123号》规定，驾驶中型以上载客载货汽车、校车、危险物品运输车辆在高速公路、城市快速路上行驶超过规定时速20％以上或者在高速公路、城市快速路以外的道路上行驶超过规定时速50％以上，以及驾驶其他机动车行驶超过规定时速50%以上的，一次记12分。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(906,'图中圈内白色实线是什么标线？','1','将车流诱导到应行驶的路线的设施的总称。导向车道：大城市主要平交路口两端，引导车辆分道行驶的车道，其分界线用白色单实线，表明进入该车道的车辆不得变更车道或压线行驶。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(907,'这个标志是何含义？','2','禁止长时停车：禁止车辆长时停放，临时停放不受限制。禁止车辆停放的时间、车种和范围可用辅助标志说明。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(908,'驾驶机动车在高速公路上行驶，遇低能见度气象条件时，能见度在200米以下，车速不得超过每小时多少公里，与同车道前车至少保持多少米的距离？','1','驾驶机动车在高速公路上行驶，遇低能见度气象条件时，能见度在200米以下，车速不得超过60公里/小时，与同车道前车至少保持100米的车距以保证安全。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(909,'驾驶机动车遇到前方道路拥堵时，可以借用无人通行的非机动车道行驶。','2','遇到道路拥堵，应该按顺序排队等待，不得借用非机动车道行驶。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(910,'这个标志是何含义？','1','右侧绕行：用以告示前方道路有障碍物，车辆应按标志指示减速慢行，右侧绕行通过。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(911,'如图所示，驾驶机动车直行遇前方道路堵塞时，车辆可以在黄色网格线区域临时停车等待，但不得在人行横道停车。','2','驾驶机动车直行遇前方道路堵塞时，车辆不可在黄色网格线区域临时停车等待，也不可在人行横道停车。即使绿灯亮了，也要在路口外停车等待。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(914,'驾驶机动车在隧道、陡坡等特殊路段不得超车。','1','《中华人民共和国道路交通安全法》第四十三条：<br/>同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：<br/>（一）前车正在左转弯、掉头、超车的；<br/>（二）与对面来车有会车可能的；<br/>（三）前车为执行紧急任务的警车、消防车、救护车、工程救险车的；<br/>（四）行经铁路道口、交叉路口、窄桥、弯道、<b>陡坡、隧道、</b>人行横道、市区交通流量大的路段等没有超车条件的。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(915,'避让特种车辆使其顺利通过后，车辆应有序回到原车道继续行驶，不要尾随特种车辆，以免发生交通事故。','1','特种车辆本身车速较快，而且由于其特殊性，驾驶路线与常规车辆也不同。如果跟随特种车会十分危险，因此避让特种车后，要有序回到原车道继续行驶。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(917,'在狭窄的路段会车时，应做到礼让三先：先慢、先让、先停。','1','文明驾驶，礼貌让行。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(921,'前方路口这种信号灯亮表示什么意思？','3','黄灯为警示灯，所以是路口警示。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(922,'这一组交通警察手势是什么信号？','4','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(924,'路中心双黄实线是何含义？','1','双黄实线表示禁止跨越。因此是禁止跨越对向车行道分界线。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(925,'如图所示，驾驶机动车遇到右侧车辆强行变道，应减速慢行，让右前方车辆顺利变道。','1','驾驶机动车遇到右侧车辆强行变道，应减速慢行，让右前方车辆顺利变道。如都不相让的话，就会造成交通事故了。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(926,'驾驶机动车遇前方交叉路口交通阻塞时，路口内无网状线的，可停在路口内等候。','2','《中华人民共和国道路交通安全法实施条例》第五十三条：机动车遇有前方交叉路口交通阻塞时，应当依次停在路口以外等候，不得进入路口。\r<br/>无论路口内有没有网状线，都不能进入路口等待。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(929,'这个标志是何含义？','4','高速公路下一出口预告：预告下一出口可到达地点。当互通式立体交叉间距大于或等于3 km、小于5 km时，应设置下一出口预告标志，预告下一出口的信息和距离。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(930,'驾驶人在驾驶证有效期满前多长时间申请换证？','3','《公安部令第123号》第四十八条：机动车驾驶人应当于机动车驾驶证有效期满前九十日内，向机动车驾驶证核发地车辆管理所申请换证。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(932,'这个标志是何含义？','3','高速公路终点预告：用于指示高速公路或城市快速路终点，设在高速公路或城市快速路终点处。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(937,'驾驶机动车在路口直行遇到这种信号灯应该怎样行驶？','4','亮红灯时，车辆应该在停止线内停车等待。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(938,'交通标志和交通标线不属于交通信号。','2','《公安部令第123号》第二十五条规定：交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(939,'使用伪造、变造的驾驶证一次记12分。','1','机动车驾驶人有下列违法行为之一，一次记12分：使用伪造、变造的机动车号牌、行驶证、驾驶证、校车标牌或者使用其他机动车号牌、行驶证的。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(942,'这辆小型载客汽车驶离高速公路行车道的方法是正确的。','1','图中车辆进入减速车道并未压实线，并且开启了转向灯，操作正确，所以是对的。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(943,'道路交通安全违法行为累积记分的周期是多长时间？','1','123号令第五十五条规定：道路交通安全违法行为<b>累积记分周期（即记分周期）为12个月</b>，满分为12分，从机动车驾驶证初次领取之日起计算。因此本题答案应为C。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(944,'前方路口这种信号灯亮表示什么意思？','4','绿灯行。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(945,'遇到这种情况时，要加速从红车前变更车道。','2','图中车辆按照道路提示需要向左变道，所以需要减速或者停车等待左侧车道直行车辆通行完毕后变道，而不可能是加速。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(946,'道路交通事故中，机动车无号牌、检验合格标志、保险标志时，要保护现场并立即报警。','1','《道路交通事故处理程序规定》 第八条 道路交通事故有下列情形之一的，当事人应当保护现场并立即报警： 　　<br/>（一）造成人员死亡、受伤的； 　　<br/>（二）发生财产损失事故，当事人对事实或者成因有争议的，以及虽然对事实或者成因无争议，但协商损害赔偿未达成协议的； 　　<br/>（三）<b>机动车无号牌、无检验合格标志、无保险标志的；</b> 　　<br/>（四）载运爆炸物品、易燃易爆化学物品以及毒害性、放射性、腐蚀性、传染病病源体等危险物品车辆的； 　　<br/>（五）碰撞建筑物、公共设施或者其他设施的；　　<br/>（六）驾驶人无有效机动车驾驶证的； 　　<br/>（七）驾驶人有饮酒、服用国家管制的精神药品或者麻醉药品嫌疑的； 　　<br/>（八）当事人不能自行移动车辆的。 　　<br/>发生财产损失事故，并具有前款第二项至第五项情形之一，车辆可以移动的，当事人可以在报警后，在确保安全的原则下对现场拍照或者标划停车位置，将车辆移至不妨碍交通的地点等候处理。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(947,'这个标志是何含义？','4','错车道指的是在单车道道路上，可通视的一定距离内，供车辆交错避让用的一段加宽车道。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(948,'这个标志是何含义？','1','高速公路入口预告：用于指示进入高速公路或城市快速路的入口，设在进入高速公路或城市快速路前的被交道路上适当位置。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(949,'已注册登记的机动车，改变机动车车身颜色的应到公安交通管理部门申请变更登记。','1','《中华人民共和国道路运输条例》规定：已注册登记的机动车，改变机动车车身颜色的应到公安交通管理部门申请变更登记。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(950,'这个标志是何含义？','4','高速公路地点距离预告：预告高速公路或城市快速路前方所要经过的重要的地点、道路的名称和距离，设置在互通式立体交叉加速车道的渐变段终点以后1 km以上路段的合适位置处。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(951,'驾驶机动车行经市区下列哪种道路时不得超车？','3','《中华人民共和国道路交通安全法》第四十三条：<br/>同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：<br/>（一）前车正在左转弯、掉头、超车的；<br/>（二）与对面来车有会车可能的；<br/>（三）前车为执行紧急任务的警车、消防车、救护车、工程救险车的；<br/>（四）行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、<b>市区交通流量大的路段</b>等没有超车条件的。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(952,'这个导向箭头是何含义？','4','亲，直行哦~~',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(955,'交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥。','1','全国统一的交通信号分为：交通信号灯、交通标志、交通标线和交通警察的指挥。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(956,'饮酒后只要不影响驾驶操作可以短距离驾驶机动车。','2','《道路交通安全法》第九十一条：饮酒后驾驶机动车的，处暂扣六个月机动车驾驶证，并处一千元以上二千元以下罚款。对自己对他人负责，只要饮酒就不开车。本题题干描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(957,'如图所示，夜间驾驶机动车遇对方使用远光灯，无法看清前方路况时，以下做法正确的是什么？ ','3','夜间驾驶机动车遇对方使用远光灯，无法看清前方路况时，降低车速，谨慎会车，以免发生车祸、危险。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(958,'如图所示，驾驶机动车经过这种道路时，应降低车速在道路中间通行。','1','图中道路两侧都有行人，驾驶机动车经过这种道路时，为了保障行人安全，需要降低车速在道路中间通行。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(961,'对驾驶拼装机动车上路行驶的驾驶人，会受到下列哪种处罚？','2','根据《中华人民共和国道路交通安全法》规定，驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废。<b>对驾驶前款所列机动车上道路行驶的驾驶人，处200元以上2000元以下罚款，并吊销机动车驾驶证。</b>选项中只有C项符合规定，因此本题答案为C。\r<br/>\r<br/>【拓展延伸】\r<br/>本题很多学员容易选择“D、吊销机动车行驶证”，注意上面的法规说明是［<b>吊销驾驶证</b>］不是“行驶证”。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(962,'驾驶机动车超车后立即开启右转向灯驶回原车道。','2','错，不能立即，应在与被超车辆拉开必要的安全距离后，开启右转向灯驶回原车道。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(963,'使用伪造、变造的行驶证一次记几分？','4','《公安部令第123号》规定，使用伪造、变造的机动车号牌、行驶证、驾驶证、校车标牌或者使用其他机动车号牌、行驶证的，一次记12分 。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(964,'这个标志是何含义？','3','乡道是白底Y字开头的，县道是白底X开头的，省道是黄底的，国道是红底的。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(965,'遇到这种情况下可以从右侧超车。','2','超车只能从左侧超车，任何情况下都是不能从右边超车的。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(966,'不得驾驶具有安全隐患的机动车上道路行驶。','1','《道路交通安全法》第二十一条：驾驶人驾驶机动车上道路行驶前，应当对机动车的安全技术性能进行认真检查；<b>不得驾驶安全设施不全或者机件不符合技术标准等具有安全隐患的机动车。</b>因此本题答案应为正确。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(967,'驾驶人在驾驶证有效期满前多长时间申请换证？','3','《公安部令第123号》第四十八条：机动车驾驶人应当于机动车驾驶证有效期满前九十日内，向机动车驾驶证核发地车辆管理所申请换证。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(968,'已注册登记的机动车，改变车身颜色，机动车所有人不需要向登记地车辆管理所申请变更登记。','2','《中华人民共和国道路运输条例》说明，已注册登记的机动车，改变机动车车身颜色的应到公安交通管理部门申请变更登记。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(969,'这个标志是何含义？','3','这个应该能看懂吧？很明显那个小车开灯的效果。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(970,'驾驶人将机动车交给驾驶证被暂扣的人驾驶的，交通警察给予口头警告。','2','《道路交通安全法》第九十九条：将机动车交由未取得机动车驾驶证或者机动车驾驶证被吊销、暂扣的人驾驶的，由公安机关交通管理部门处二百元以上二千元以下罚款，可以并处吊销机动车驾驶证。\r<br/>并不是口头警告这么简单。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(971,'行车中遇列队横过道路的学生时，应怎样做？','2','列队横过道路的学生，人数多，通行时间长。降低车速还是容易撞上，停车让行更安全。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(972,'这个标志是何含义？','3','向左急转弯：向左急弯路标志设在左急转弯的道路前方适当位置。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(973,'机动车仪表板上（如图所示）亮时表示什么？','2','近光灯的灯光走向是朝下的。远光灯的灯光走向是直的。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(974,'以下哪种身体条件，不可以申请机动车驾驶证?','2','红绿色盲会影响观察红绿灯，而我们在路上开车一般都是根据交通信号灯行驶的，所以不能申请驾照。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(976,'这两辆车发生追尾的主要原因是什么？','4','因为有人行横道线，所以司机应该知道要提前减速，速度降得低了，后车要刹车就应该应该不会再追尾了。追尾都是后车的责任，因为没有保持足有的安全距离。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(977,'车辆进入山区道路后，要特别注意“连续转弯”标志，并主动避让车辆及行人，适时减速和提前鸣喇叭。','1','山区本来就是有山的地势，自然就会有坡度，以及拐弯，连续的弯路，容易影响行车的视线，所以要注意“连续转弯”的标志，以防在转弯处突然出现对向来车，为了安全，当然要适时减速和提前鸣喇叭，以提醒车辆与行人。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(978,'驾驶机动车通过窄路、窄桥时的最高速度不能超过每小时30公里。','1','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 <br/>（一）进出非机动车道，通过铁路道口、急弯路、<b>窄路、窄桥时；</b>　　 <br/>（二）掉头、转弯、下陡坡时；　　 <br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 <br/>（四）在冰雪、泥泞的道路上行驶时。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(980,'如图所示，驾驶机动车行经该路段时，应减速慢行，避免因眩目导致的交通事故。','1','驾驶员在驶出隧道口时，因为此处光线发生变化，驾驶员会有炫目感。安全起见，还是要减速慢行。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(981,'机动车发生财产损失交通事故，对应当自行撤离现场而未撤离的，交通警察不可以责令当事人撤离现场。','2','《道路交通事故处理程序规定》第十三条：<b>对应当自行撤离现场而未撤离的，交通警察应当责令当事人撤离现场；</b>造成交通堵塞的，对驾驶人处以200元罚款；驾驶人有其他道路交通安全违法行为的，依法一并处罚。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(982,'驾驶机动车在路口遇到这种信号灯亮时，不能右转弯。','2','只有 红 黄 绿三色且是圆形（如图）交通信号灯的路口，任何情况下都能右转，如果是箭头信号灯的话按箭头方向行驶。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(984,'驾驶机动车在这种信号灯亮的路口，可以右转弯。','1','要看路口的信号灯。如果路口只有红、黄、绿圆形三色的信号灯时，就可以直接右转弯。如果路口信号灯有箭头指示灯时，需要根据箭头灯的指示。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(986,'驾驶机动车在泥泞道路行驶时，最高速度不能超过多少？','4','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 <br/>（一）进出非机动车道，通过铁路道口、急弯路、窄路、窄桥时；　　 <br/>（二）掉头、转弯、下陡坡时；　　 <br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 <br/>（四）在冰雪、<b>泥泞</b>的道路上行驶时；',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(988,'风、雨、雪、雾等复杂气象条件，遇前车速度较低时，应开启前照灯，连续鸣喇叭迅速超越。','2','复杂天气下超车十分危险，为了道路安全最好不要超车。应该选择合适地点减速停车。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(989,'这个标志是何含义？','2','窄桥：用以警告车辆驾驶人注意前方桥面宽度变窄，应谨慎驾驶。设在桥面净宽较两端路面宽度变窄，且桥的净宽小于6 m的桥梁以前适当位置。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(990,'夜间驾驶人对事物的观察能力明显比白天差，视距变短。','1','白天开车的时候由于光线比较充足，所以观察事物的范围比较广，观察事物的视线距离相对也就比较大，<b>而在晚上受到光线暗的局限，相对观察事物的距离也就受到局限，所以视距比较短。</b>',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(991,'夜间会车时，若对方车辆不关闭远光灯，可变换灯光提示对向车辆，同时减速靠右侧行驶或停车。','1','夜间安全驾驶知识中第三条就有：“夜间会车应当在距对方来车150米以外改用近光灯，若对方车辆不关闭远光灯，可连续变换灯光提示对向车辆。当遇对面来车仍不关闭远光灯时，应及时减速靠右侧行驶或停车让行。”',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(992,'有吸食、注射毒品后驾驶驾车行为的机动车驾驶人，不会被注销驾驶证。','2','被查获有吸食、注射毒品后驾驶机动车行为，正在执行社区戒毒、强制隔离戒毒、社区康复措施，或者长期服用依赖性精神药品成瘾尚未戒除的，车辆管理所应当注销其机动车驾驶证。三年内有吸食、注射毒品行为，或者解除强制隔离戒毒措施未满三年，或者长期服用依赖性精神药品成瘾尚未戒除的，不得申请机动车驾驶证。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(994,'这个标志是何含义？','1','连续下坡：用以提醒车辆驾驶人小心驾驶。当连续下坡总长大于3 km后，应重复设置。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(995,'在没有中心线的道路上发现后车发出超车信号时，如果条件许可如何行驶？','3','如果迅速停车的话，会很容易追尾，降速靠右让路是因为超车规定要在左侧超越。安全文明驾驶原则，后车条件许可超车，前车那就减速靠右行驶。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(996,'在交叉路口遇到这种情况享有优先通行权。','1','右转让左转，没有问题。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(999,'客车遇险后，应设法开启车门、安全门或紧急出口，迅速疏散车上乘客。','1','',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(1000,'遇有这种排队等候的情形怎么做？','3','前方拥堵，请耐心等候。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(1001,'在交叉路口遇到这种情况时，要在红灯亮以前加速通过路口。','2','黄灯亮了，车身没越过白色停止线，所以要停车等待。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1002,'路面上的白色标线是何含义？','2','<p><img src=http://nimg.cysq.com/yxlimg/20a43532.jpg>\r<br/>横向减速标线\r<br/><img src=http://nimg.cysq.com/yxlimg/2ec73df9.jpg>\r<br/>纵向减速标线</p>',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1003,'掉头过程中，应严格控制车速，仔细观察道路前后方情况，确认安全后方可前进或倒车。','1','掉头过程中，要控制好车速，仔细观察周围情况。这样能最大程度的避免掉头中发生事故。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(1004,'这个导向箭头是何含义？','4','直行或者掉头都可以',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1005,'这位驾驶人违反法律规定的行为是什么？','3','《道路交通安全法》第五十一条：机动车行驶时，驾驶人、乘坐人员应当按规定使用安全带，摩托车驾驶人及乘坐人员应当按规定戴安全头盔。很明显，图中司机没有系安全带，属于违法行为。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1007,'这个标志的含义是提醒车辆驾驶人前方是无人看守铁路道口。','1','无人看守铁路道口：用以警告车辆驾驶人注意慢行或及时停车。设在无人看守铁路道口以前适当位置。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1008,'在这个弯道上行驶时的最高速度不能超过多少？','2','机动车行驶中遇有下列情形之一的，<b>最高行驶速度不得超过每小时30公里，</b>其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 <br/>（一）进出非机动车道，通过铁路道口、急弯路、窄路、窄桥时；　　 <br/>（二）<b>掉头、转弯、下陡坡时；</b>　　 <br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 <br/>（四）在冰雪、泥泞的道路上行驶时；',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1011,'驾驶机动车通过窄路、窄桥时，最高速度不能超过多少？','3','机动车行驶中遇有下列情形之一的，最高行驶速度不得超过每小时30公里，其中拖拉机、电瓶车、轮式专用机械车不得超过每小时15公里：　　 <br/>（一）进出非机动车道，通过铁路道口、急弯路、<b>窄路、窄桥时；</b>　　 <br/>（二）掉头、转弯、下陡坡时；　　 <br/>（三）遇雾、雨、雪、沙尘、冰雹，能见度在50米以内时；　　 <br/>（四）在冰雪、泥泞的道路上行驶时；',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(1012,'这一组交通警察手势是什么信号？','4','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1013,'遇后车发出超车信号后，只要具备让超条件应怎样做？','2','文明礼让，和谐驾驶。如果遇到后车发出超车信号，我们应该主动减速并靠右侧行驶。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1015,'在路口遇有交通信号灯和交通警察指挥不一致时，按照交通信号灯通行。','2','《道路交通安全法》第三十八条：车辆、行人应当按照交通信号通行；<b>遇有交通警察现场指挥时，应当按照交通警察的指挥通行；</b>在没有交通信号的道路上，应当在确保安全、畅通的原则下通行。\r<br/>题目描述有误，本题答案应为错误。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1016,'这个标志是何含义？','1','用于引导行车方向，提示道路使用者前方线形变化，注意谨慎驾驶。设于中央隔离设施端部、渠化设施的端部、桥头等。∧表示俩侧通行，/这个方向的表示左侧通行，这个方向表示右侧通行。交通指路标志大全：http://www.jszks.com/onepage/16752.html',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1017,'夜间驾驶机动车在窄路、窄桥会车怎样使用灯光？','2','《道路交通安全法实施条例》第四十八条： 在没有中心隔离设施或者没有中心线的道路上，夜间会车应当在距相对方向来车150米以外改用近光灯，<b>在窄路、窄桥与非机动车会车时应当使用近光灯。</b>',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1018,'驾驶车辆进入交叉路口前，应降低行驶速度，注意观察，确认安全。','1','进入交叉路口时，要安全驾驶，减速前行。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1019,'行车中前方遇自行车影响通行时，可鸣喇叭提示，加速绕行。','2','本题错在加速绕行，鸣喇叭提示是对的。应当减速与其保持安全距离，道路宽度允许通过时谨慎通过。因此本题错了。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1021,'在这个路口可以掉头。','2','《道路交通安全法实施条例》第四十九条：机动车在有禁止掉头或者禁止左转弯标志、标线的地点以及在铁路道口、人行横道、桥梁、急弯、陡坡、隧道或者容易发生危险的路段，不得掉头。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1022,'前方路口这种信号灯亮表示什么意思？','4','红灯停。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1024,'在路口这个位置时可以加速通过路口。','2','这是红灯信号，应该禁止通过，应停车等待绿灯，再通过。\r<br/>题目描述有误，本题答案应为错误。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1025,'驾驶车辆时，长时间左臂搭在车门窗上，或者长时间右手抓住变速器操纵杆，是一种驾驶陋习。','1','长时间左臂搭在车门窗上，或者长时间右手抓住变速器操纵杆，如果出现紧急情况，驾驶员很难做出良好及时的应对，属于驾驶陋习。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1027,'有这种信号灯的路口允许机动车如何行驶？','1','图中是箭头指示的交通信号灯，只有右转的灯是绿灯，并且我方车辆在右转车道上，所以只能向右转弯。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1029,'可以从这个位置直接驶入高速公路行车道。','2','应该按照标线行驶，不要乱开。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1030,'驾驶人有使用其他车辆保险标志嫌疑的，交通警察可依法扣留车辆。','1','《道路交通安全违法行为处理程序规定》第二十五条规定，有下列情形之一的，依法扣留车辆：有伪造、变造或者使用伪造、变造的机动车登记证书、号牌、行驶证、检验合格标志、 保险标志、驾驶证或者使用其他车辆的机动车登记证书、号牌、行驶证、检验合格标志、保险标志嫌疑的。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1031,'雾天行车多使用喇叭可引起对方注意；听到对方车辆鸣喇叭，也应鸣喇叭回应。','1','雾天视线不佳，喇叭可当做一种信号和其他车辆交流，有利于安全行车。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(1033,'道路上划设这种标线的车道内允许下列哪类车辆通行？','1','请注意地面的字，公交专用车道。所以是只有公交车才能行驶。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1034,'驾驶机动车在这种道路上如何通行？','1','《道路交通安全法》第三十六条：根据道路条件和通行需要，道路划分为机动车道、非机动车道和人行道的，机动车、非机动车、行人实行分道通行。<b>没有划分机动车道、非机动车道和人行道的，机动车在道路中间通行，非机动车和行人在道路两侧通行。</b>',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1035,'轮胎气压过低时，高速行驶轮胎会出现波浪变形温度升高而导致什么？','3','轮胎气不足，会造成轮胎与地面的摩擦范围增大，温度升高从而爆胎。压力过低和过高都会导致爆胎。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1036,'将点火开关转到ACC位置起动机工作。','2','LOCK-----（锁止），ACC------------ (断电)\r<br/>ON--------（通电），START--------（起动）',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1037,'这个标志是何含义？','3','禁止向左转弯：表示前方路口禁止一切车辆向左转弯。此标志设在禁止向左转弯的路口前适当位置',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1038,'驶入高速公路的收费口时，应选择怎样的入口？','3','绿灯是表示收费站正常运行的，所以应该选择绿灯亮的入口。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1040,'在这段道路上，只要不影响其他车辆通行的前提下可以掉头。','1','黄线用来区分不同方向的车道，一般画在马路正中，好像一条隔离带，把马路隔成两个方向： 1、无论单黄线还是双黄线，只要是实线，就严禁跨越的，比如超车、转弯、掉头等。行车时没有特别情况就不应该越线。 <b>2、无论单黄线还是双黄线，只要是虚线，就可以在保证安全的情况下超车或掉头。</b>',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1042,'行车中，发现行人突然横过道路时，应迅速减速避让。','1','发现行人突然横过道路时，应迅速减速避让，确保行人安全。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1044,'机动车在道路上变更车道需要注意什么？','3','《道路交通安全法实施条例》第四十四条：在道路同方向划有2条以上机动车道的，变更车道的机动车不得影响相关车道内行驶的机动车的正常行驶。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1047,'连续驾驶大型载客汽车超过4小时未停车休息，按照规定将被公安机关交通管理部门给予一次记多少分？','3','由于大型载客汽车出现事故会造成很多伤亡等严重问题，故惩罚力度大，超过4个小时未休息直接扣12分。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1048,'在这种环境里行车使用近光灯。','1','注意观察题目图片，夜间驾驶机动车，机动车前方有人行横道，<b>路边有行人</b>。在这种情况下行车应该使用近光灯，不妨碍行人正常通行。题目描述正确，因此本题答案为对。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1049,'这个路面数字标记是何含义？','3','<p><img src=http://tp.mnks.cn/tp_321.jpg>\r<br/>限制速度\r<br/><img src=http://tp.mnks.cn/tp_322.jpg>\r<br/>限制最高速度\r<br/><img src=http://tp.mnks.cn/tp_323.jpg>\r<br/>限制最低速度</p>',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1051,'驾驶机动车在沙尘天气条件下行车不用开启前照灯、示廓灯和后位灯。','2','《道路交通安全法实施条例》第五十八条： 机动车在夜间没有路灯、照明不良或者<b>遇有雾、雨、雪、沙尘、冰雹等低能见度情况下行驶时，应当开启前照灯、示廓灯和后位灯，</b>但同方向行驶的后车与前车近距离行驶时，不得使用远光灯。机动车雾天行驶应当开启雾灯和危险报警闪光灯。\r<br/>题目描述有误，本题答案应为错误。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1052,'在这条公路上行驶的最高速度不能超过多少？','4','根据《中华人民共和国道路交通安全法实施条例》第四十五条：……在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：　　(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；　　(二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。图为公路，所以最高时速为70公里/每小时。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1053,'倒车过程中要缓慢行驶，注意观察车辆两侧和后方的情况，随时做好停车准备。','1','倒车时主要观察车后面和车两侧的情况，整个过程要缓慢谨慎，安全第一。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1055,'这个标志是何含义？','4','黄底为警告标志，所以排除A和B，图很明显的为合流标志，所以选D',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1056,'驾驶报废机动车上路行驶的驾驶人，除按规定罚款外，还要受到哪种处理？','4','根据《中华人民共和国道路交通安全法》规定，驾驶拼装的机动车或者已达到报废标准的机动车上道路行驶的，公安机关交通管理部门应当予以收缴，强制报废。<b>对驾驶前款所列机动车上道路行驶的驾驶人，处200元以上2000元以下罚款，并吊销机动车驾驶证。</b>因此本题答案为D。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1058,'这个标志是何含义？','3','高速公路命名编号：用于指示高速公路的编号，作为指路标志的路线信息，出现在高速公路、城市快速路、一般道路指路标志版面中。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(1059,'行车中当车辆突然爆胎时，驾驶人切忌慌乱中急踏制动踏板，尽量采用“抢挡”的方法，利用发动机制动使车辆减速。','1','车胎爆胎时紧急制动极易导致车辆侧翻。应该利用抢档的方式，用发动机制动减速停车。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1060,'冰雪路行车时应注意什么？','1','车辆在冰雪路面上行驶，<b>因汽车轮胎与路面的摩擦系数减小、附着力大大降低，</b>所以遇有冰雪路面，车辆在行驶中最重要的是车辆制动问题，要采取点刹、并和前后车保持车距离。遇情况紧急制动时，制动距离会大大延长。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1062,'驾驶机动车在道路上靠路边停车过程中如何使用灯光？','2','《道路交通安全法实施条例》第五十七条 机动车应当按照下列规定使用转向灯： (一)向左转弯、向左变更车道、准备超车、驶离停车地点或者掉头时，应当提前开启左转向灯； <b>(二)向右转弯、向右变更车道、超车完毕驶回原车道、靠路边停车时，应当提前开启右转向灯。</b>\r<br/>注意题干所说的是“靠边停车过程中”，而非已经靠边停车了。所以应该提前开启右转向灯，本题答案应为D。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1063,'这个标志是何含义？','4','俩个车道变成三个，表示车道数增加。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1065,'这个标志的含义是提醒车辆驾驶人前方是堤坝路段。','2','<p><img src=http://tp.mnks.cn/tp_144.jpg>\r<br/>堤坝路\r<br/><img src=http://tp.mnks.cn/tp_143.jpg>\r<br/>傍山险路</p>',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1066,'这个标志是何含义？','4','4M高度，因为超过所以只能绕行。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1067,'通过窄路、窄桥时，不得超车。','1','《中华人民共和国道路交通安全法》第四十三条 同车道行驶的机动车，后车应当与前车保持足以采取紧急制动措施的安全距离。有下列情形之一的，不得超车：（四）行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的。 <b>通过隧道，铁路道口，急转弯路段，窄路，窄桥或遇前方道路上有车辆掉头时，不得超车。</b>',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1069,'车辆驶入双向行驶隧道前，应开启什么灯？','1','<b>凡是车辆进入双向行驶隧道，都应该开启近光灯或示廓灯，</b>提醒其他车辆，避免发生事故。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1070,'在这段路的最高时速为每小时50公里。','2','白底红圈表示最高限速，蓝色牌子表示最低限速。所以最高时速应该为80公里/小时。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1071,'当驾驶车辆行经两侧有非机动车行驶且有积水的路面时，应怎样做？','1','文明驾驶。减速行驶能够防止水溅到行人身上。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1072,'仪表显示当前冷却液的温度是90度。','1','此仪表盘温度表示的是冷却液的温度。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(1073,'红色圆圈内标线含义是什么？','3','都写了公交站了，不许选错了',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1074,'这个标志是何含义？','2','限制宽度为3米：表示禁止装载宽度超过标志所示数值的车辆通行。此标志设在最大允许宽度受限制的地方。 以图为例：装载宽度不得超过3米',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1075,'驾驶机动车通过没有交通信号和管理人员的铁路道口怎样通过？','3','《道路交通安全法》第四十六条：机动车通过铁路道口时，应当按照交通信号或者管理人员的指挥通行；<b>没有交通信号或者管理人员的，应当减速或者停车，在确认安全后通过。</b>',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1076,'雨天行车，遇撑雨伞和穿雨衣的行人在公路上行走时，应怎样做？','3','安全驾驶，减速慢行。遇到撑雨伞和穿雨衣会使视线受阻碍，所以要鸣喇叭，雨天路滑所以要减速。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1077,'这个标志是何含义？','2','路面高突：用以提醒车辆驾驶人减速慢行。设在路面突然高突以前适当位置。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1079,'设有安全带装置的车辆，应要求车内乘员系安全带。','1','行车过程中，即使是设有安全装置的车内，驾驶员与非驾驶员都要系安全带，安全第一!',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1080,'在堵车的交叉路口绿灯亮时，车辆应怎样做？','2','前方堵车，这时进入交叉路口只能更堵。因此堵车时即便绿灯亮了，也不要驶入路口内。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1081,'夜间会车时，若对方车辆不关闭远光灯，可变换灯光提示对向车辆，同时减速靠右侧行驶或停车。','1','夜间安全驾驶知识中第三条就有：“夜间会车应当在距对方来车150米以外改用近光灯，若对方车辆不关闭远光灯，可连续变换灯光提示对向车辆。当遇对面来车仍不关闭远光灯时，应及时减速靠右侧行驶或停车让行。”',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1082,'进入这个路口应该怎样做？','3','前方标志为环岛行驶，应该让已进入环岛内的车辆通行。当前车辆不能压白色网状区域。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1085,'会车前选择的交会位置不理想时，应怎样做？','1','发现交会位置不理想时，应减速或停车让行，以寻找下一个理想会车位置。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1086,'车辆下长坡时要减挡行驶，以充分利用发动机的制动作用。','1','变速箱高档位高速持续运转中，迅速降低变速箱的档位转速，使变速箱的低档位转速对车辆本身的惯性高速产生抑制，从而产生短时间内的所谓发动机制动(变速箱制动)。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1088,'预计在超车过程中与对面来车有会车可能时，应提前加速超越。','2','预计在超车过程中与对面来车有会车可能时，应当放弃超车。若加速超越，有可能会引起不必要的事故。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1089,'下列哪种行为会受到200元以上2000元以下罚款，并处吊销机动车驾驶证？','2','第九十九条　有下列行为之一的，由公安机关交通管理部门处二百元以上二千元以下罚款：\r<br/>（一）未取得机动车驾驶证、机动车驾驶证被吊销或者机动车驾驶证被暂扣期间驾驶机动车的；\r<br/>（二）将机动车交由未取得机动车驾驶证或者机动车驾驶证被吊销、暂扣的人驾驶的；\r<br/>（三）造成交通事故后逃逸，尚不构成犯罪的；\r<br/><b>（四）机动车行驶超过规定时速百分之五十的；（超过规定时速50%）</b>\r<br/>（五）强迫机动车驾驶人违反道路交通安全法律、法规和机动车安全驾驶要求驾驶机动车，造成交通事故，尚不构成犯罪的；\r<br/>（六）违反交通管制的规定强行通行，不听劝阻的；\r<br/>（七）故意损毁、移动、涂改交通设施，造成危害后果，尚不构成犯罪的；\r<br/>（八）非法拦截、扣留机动车辆，不听劝阻，造成交通严重阻塞或者较大财产损失的。\r<br/><b>行为人有前款第二项、第四项情形之一的，可以并处吊销机动车驾驶证</b>；有第一项、第三项、第五项至第八项情形之一的，可以并处十五日以下拘留。\r<br/>\r<br/>A选项中，违反道路通行规定的说法太宽泛了，不适用于具体的处罚标准。\r<br/>C选项中，造成交通事故逃逸的处罚是：吊销机动车驾驶证，且终生不得重新取得机动车驾驶证。如果造成交通事故逃逸，不构成犯罪的，处罚款200以上2000以下。但选项中没有说明是否构成犯罪，因此不能判断罚款金额。\r<br/>D选项中，驾车没带驾驶证的处罚是：扣留机动车，通知驾驶人提供驾驶证。\r<br/>\r<br/>综上，本题应该选B。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1092,'机动车仪表板上（如图所示）亮表示什么？','4','A,B,C都巨不靠谱，只有D最合理。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1093,'行车中从其他道路汇入车流前，应注意观察侧后方车辆的动态。','1','行车中从其他道路线汇入车流前，应注意观察侧后方车辆的动态，确保行车安全。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(1094,'机动车 仪表板上（如图所示）亮表示发动机可能机油压力过高。','2','图片表示发动机可能机油压力不足。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1095,'叉车货叉定位应可靠，货叉挂钩的支承面、定位面不得有明显缺陷。','1','',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1096,'道路上划设这种标线的车道内允许下列哪类车辆通行？','1','请注意地面的字，公交专用车道。所以是只有公交车才能行驶。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1097,'驾驶机动车在道路上向左变更车道时如何使用灯光？','3','《道路交通安全法实施条例》第五十七条,机动车应当按照下列规定使用转向灯：\r<br/><b>(一)向左转弯、向左变更车道、准备超车、驶离停车地点或者掉头时，应当提前开启左转向灯；</b>\r<br/> (二)向右转弯、向右变更车道、超车完毕驶回原车道、靠路边停车时，应当提前开启右转向灯。\r<br/>根据规定，向左变更车道应该<b>提前开启左转向灯</b>，选项C符合规定，因此本题答案为C。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1099,'在这种情况的铁路道口要加速通过。','2','前面是火车道，道口红灯已经亮起，表明即将有火车通过。这个时候应当停车等待，等火车过去了再通过。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1101,'（如图所示）这个符号的开关控制什么装置？','1','你看里边长的多像一个小孩，故选A最靠谱。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(1102,'这个标志是何含义？','4','表示一切车辆向左单向行驶。此标志设在单行路的路口和入口处的适当位置。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1103,'在交叉路口遇到这种情况享有优先通行权。','1','右转让左转，没有问题。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1104,'遇到路口情况复杂时，应做到“宁停三分，不抢一秒”。','1','文明驾车，安全行驶。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1105,'在这条公路上行驶的最高速度不能超过多少？','4','根据《中华人民共和国道路交通安全法实施条例》第四十五条：……在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：　　(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；　　(二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。图为公路，所以最高时速为70公里/每小时。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1106,'交通标志和交通标线不属于交通信号。','2','《公安部令第123号》第二十五条规定：交通信号包括交通信号灯、交通标志、交通标线和交通警察的指挥。\r<br/>题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1107,'前方路口这种信号灯亮表示什么意思？','4','红灯停。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1109,'在这段城市道路上行驶的最高速度不能超过多少？','2','《中华人民共和国道路交通安全法实施条例》<br/>第四十五条：机动车在道路上行驶不得超过限速标志、标线标明的速度。在没有限速标志、标线的道路上，机动车不得超过下列最高行驶速度：<br/>  <b>(一)没有道路中心线的道路，城市道路为每小时30公里，公路为每小时40公里；</b><br/>  (二)同方向只有1条机动车道的道路，城市道路为每小时50公里，公路为每小时70公里。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1111,'这段道路红车所在车道是什么车道？','1','《道路交通安全法实施条例》第四十四条：在道路同方向划有2条以上机动车道的，左侧为快速车道，右侧为慢速车道。红色车在最左侧，所以是在快速车道。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1113,'夜间驾驶机动车通过人行横道时需要交替使用远近光灯。','1','《道路交通安全法实施条例》第五十九条：机动车在夜间通过急弯、坡路、拱桥、人行横道或者没有交通信号灯控制的路口时，应当交替使用远近光灯示意。\r<br/>题目描述正确，因此本题答案应为正确。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1114,'这种握转向盘的动作是正确的。','2','正确的握法是握住方向盘的两边，分别在10点和4点位置，左手为主右手为辅。题中的握法是驾驶的陋习，是有很大的风险的。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1115,'驾驶人在行车中经过积水路面时，应怎样做？','1','行车中经过积水路面时，应特别留意减速慢行；<b>加速或保持正常车速通过，溅起的水花会冲击前挡风玻璃，阻挡驾驶员的视线，</b>无法观察前方情况，极易导致车辆失控或交通事故。另外，驾驶车辆行经两侧有行人或非机动车行驶且有积水的路面时，更应减速慢行，<b>以免泥水飞溅到行人或非机动车驾驶员身上。</b>',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1116,'车辆因故障必须在高速公路停车时，应在车后方多少米以外设置故障警告标志？','2','<b>车辆因故障必须在高速公路停车时，应在车后方（150米）处设置故障警告标志，夜间还需开启示廓灯和后位灯。</b>',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1117,'驾驶车辆在交叉路口前变更车道时，应怎样驶入要变更的车道？','4','实线不可跨线行驶，应该在虚线区按导向箭头指示变更车道。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1120,'机动车仪表板上（如图所示）亮时，防抱死制动系统处于打开状态。','2','此标志为防抱死制动系统出现故障，应该停车进行全面检查。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1121,'通过隧道时，不得超车。','1','《中华人民共和国道路交通安全法》 第四十三条 同车道行驶的机动车，……有下列情形之一的，不得超车： <br/>（一）前车正在左转弯、掉头、超车的； <br/>（二）与对面来车有会车可能的； <br/>（三）前车为执行紧急任务的警车、消防车、救护车、工程救险车的； <br/>（四）<b>行经铁路道口、交叉路口、窄桥、弯道、陡坡、隧道、人行横道、市区交通流量大的路段等没有超车条件的。</b>',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1122,'机动车仪表板上（如图所示）亮表示什么？','1','ABS就是防抱死制动系统',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1123,'这是什么操纵装置？','2','这个是点火装置没错。灯光开关在左手边，雨刷开关在右手边。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(1124,'这个标志是何含义？','3','表示该街道只供步行。此标志设在步行街的两端。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1125,'在路口遇到这种情形时怎样做？','2','《道路交通安全法实施条例》第五十三条：机动车在遇有前方机动车停车排队等候或者缓慢行驶时，应当依次排队，不得从前方车辆两侧穿插或者超越行驶，<b>不得在人行横道、网状线区域内停车等候。</b>\r<br/>根据规定，题目中情形为了不加重拥堵，机动车应该停在路口以外等待。B项符合要求，因此本题答案为B。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1126,'行至这种情况的铁路道口要停车观察。','1','在无人看守的铁道路口，要停车观察，确定安全后，才可以通过！',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1127,'这是什么踏板？','1','从左往右数起，分别是离合，制动踏板，加速踏板。图中指的最中间的是制动踏板。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1128,'机动车驾驶人在一个记分周期内累积记分达到12分，拒不参加学习和考试的，将被公安机关交通管理部门公告其驾驶证停止使用。','1','正确的，所以要及时去处理扣分。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(1133,'这个标志是何含义？','1','高速公路右侧出口预告：用于预告前方出口，设置在距离高速公路或城市快速路减速车道的渐变段起点处。出口预告标志应同时附着出口编号标志。查看高速公路标志大全：http://www.jszks.com/onepage/16721.html',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1134,'这一组交通警察手势是什么信号？','4','手势题详解：http://www.jszks.com/onepage/16203.html',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1135,'这个标志是何含义？','2','禁止向右转弯：表示前方路口禁止一切车辆向右转弯。此标志设在禁止向右转弯的路口前适当位置。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1137,'醉酒驾驶营运机动车的，由公安机关交通管理部门约束至酒醒，吊销机动车驾驶证，多长时间内不得重新取得机动车驾驶证，并依法追究刑事责任；重新取得机动车驾驶证后，不得驾驶营运机动车？','4','醉酒后驾驶营运机动车的，由公安机关交通管理部门约束至酒醒，吊销机动车驾驶证，10年内不得重新取得机动车驾驶证，并依法追究刑事责任',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1139,'驾驶机动车要选择绿色箭头灯亮的车道行驶。','1','只有绿灯是表示允许通行，机动车要选择绿色箭头灯亮的车道行驶。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1140,'这个标志是何含义？','1','表示机动车驶入前方道路之最低时速限制。此标志设在高速公路或其他道路限速路段的起点。高度限速标志是白底红字。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1142,'超过机动车驾驶证有效期一年以上未换证被注销，但未超过2年的，机动车驾驶人应当如何恢复驾驶资格？','1','《机动车驾驶证申领和使用规定》：被注销机动车驾驶证未超过两年的，机动车驾驶人考试科目一合格后，可以恢复驾驶资格。',NULL,'2023-10-13 11:37:36','2023-10-13 11:37:36',0),(1143,'如图所示，在高速公路同方向三条机动车道最左侧车道行驶，应保持什么车速？','1','《中华人民共和国道路交通安全法实施条例》第七十八条：同方向有2条车道的，左侧车道的最低车速为每小时100公里；同方向有3条以上车道的，最左侧车道的最低车速为每小时110公里，中间车道的最低车速为每小时90公里。道路限速标志标明的车速与上述车道行驶车速的规定不一致的，技照道路限速标志标明的车速行驶。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1144,'发生交通事故后，当事人故意破坏、伪造现场、毁灭证据的，承担全部责任。','1','发生交通事故后，当事人故意破坏、伪造现场、毁灭证据的，导致后期无法采证的，应该负全部责任。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1145,'公路客运车辆载客超过额定成员20%或者违反规定载货的，处多少罚款？','3','客运车辆载客超载，但是没有超过额定成员20%，罚的不算太狠，所以是200元上，500元以下；而超载超过20%的就是500元以上2000元以下。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1146,'如图所示，驾驶机动车遇到这种情况，以下做法正确的是什么？','1','驾驶机动车遇到这种情况，应该：减速慢行、鸣喇叭示意。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1147,'驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的一次记6分。','2','《公安部令第123号》规定，驾驶机动车在高速公路上倒车、逆行、穿越中央分隔带掉头的，一次记12分 。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1148,'驾驶机动车造成重大交通事故后逃逸，构成犯罪的，由公安机关交通管理部门吊销机动车驾驶证，且终生不得重新取得机动车驾驶证。','1','<b>《道路交通安全法》第一百零一条规定，造成交通事故后逃逸的，由公安机关交通管理部门吊销机动车驾驶证，且终身不得重新取得机动车驾驶证。</b>上述规定泛指各类交通事故，只要是造成交通事故后逃逸的，就应当由公安机关交通管理部门吊销其机动车驾驶证，并且终身不得重新取得驾驶证，而不论其造成交通事故后果的大小。也就是说，法律规定惩罚的交通肇事逃逸行为，与驾驶人造成交通事故后果的轻重无关；构成犯罪的，依法追究刑事责任。',NULL,'2023-10-13 11:38:05','2023-10-13 11:38:05',0),(1149,'这个标志的含义是警告前方出现向左的急转弯路。','1','向左急弯路：用以警告车辆驾驶人减速慢行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1150,'如图所示，A车可以从左侧超越B车。','2','实线是不能压的，所以A车不具备超车条件，应该放弃。',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(1151,'这个导向箭头是何含义？','1','导向箭头：提示前方道路有左弯或需向左合流。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1153,'驾驶证审验内容不包括以下哪一项？','4','驾驶证审验内容包括：道路交通安全违法行为、交通事故处理情况；身体条件情况；道路交通安全违法行为记分及记满12分后参加学习和考试情况。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1155,'驾驶机动车在隧道内行驶时，可以临时停车。','2','机动车在交叉路口、铁路道口、急弯路、宽度不足4米的窄路、桥梁、陡坡、隧道以及距离上述地点50米以内的路段，不得停车。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1156,'驾驶车辆驶入铁路道口前减速降挡，进入道口后应怎样做？','1','进路口前停车观望，进了就不能换挡，如果换挡不当，就会熄火，非常危险。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1157,'如图所示，驾驶机动车在路口遇到这种交通信号时，右转弯的车辆在不妨碍被放行的车辆、行人的情况下，可以通行。','1','驾驶机动车在路口遇到这种圆形交通信号时，右转弯的车辆在不妨碍被放行的车辆、行人的情况下，可以通行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1158,'这属于哪一种标志？','1','旅游区方向：设在通往旅游区各连接道路的交叉口处。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1159,'以下哪种违法行为的机动车驾驶人将被一次记6分？','3','二、机动车驾驶人有下列违法行为之一，一次记6分：<br/>（一）机动车驾驶证被暂扣期间驾驶机动车的；<br/><b>（二）驾驶机动车违反道路交通信号灯通行的；</b><br/>（三）驾驶营运客车（不包括公共汽车）、校车载人超过核定人数未达20％的，或者驾驶其他载客汽车载人超过核定人数20％以上的；<br/>（四）驾驶中型以上载客载货汽车、校车、危险物品运输车辆在高速公路、城市快速路上行驶超过规定时速未达20％的；<br/>（五）驾驶中型以上载客载货汽车、校车、危险物品运输车辆在高速公路、城市快速路以外的道路上行驶或者驾驶其他机动车行驶超过规定时速20%以上未达到50%的；<br/>（六）驾驶货车载物超过核定载质量30%以上或者违反规定载客的；<br/>（七）驾驶营运客车以外的机动车在高速公路车道内停车的；<br/>（八）驾驶机动车在高速公路或者城市快速路上违法占用应急车道行驶的；<br/>（九）低能见度气象条件下，驾驶机动车在高速公路上不按规定行驶的；<br/>（十）驾驶机动车运载超限的不可解体的物品，未按指定的时间、路线、速度行驶或者未悬挂明显标志的；',NULL,'2023-10-13 11:38:37','2023-10-13 11:38:37',0),(1160,'这个标志的含义是警告前方道路有障碍物，车辆减速绕行。','2','这个警告标志是向右急转弯。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1161,'这个标志的含义是警告前方道路易滑，注意慢行。','2','<p><img src=http://tp.mnks.cn/tp_125.jpg>\r<br/>反向弯路\r<br/><img src=http://tp.mnks.cn/tp_142.jpg>\r<br/>易滑路段</p>',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1162,'驾驶机动车在高速公路上遇到雨雪天气时，需要降低车速、保持安全距离的原因，以下说法错误的是什么？','4','驾驶机动车在高速公路上遇到雨雪天气时能见度下降，驾驶人难以及时发现前方车辆，<b>在此类天气条件下的道路上，车辆的制动距离变长，需要降低车速，为车辆安全行驶提供足够的安全距离。</b>\r<br/>而降低车速、保持安全距离，与降低恶劣天气对车辆造成的损害并无直接关系。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1163,'这个标志是何含义？','3','表示会车先行，此标志设在车道以前适当位置。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1164,'这个标志的含义是提醒前方道路变为不分离双向行驶路段。','1','警告标志注意双向交通。用以提醒车辆驾驶人注意会车。设在由双向分离行驶，因某种原因出现临时性或永久性的不分离双向行驶的路段，或由单向行驶进人双向行驶的路段以前适当位置。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1165,'这个标志是何含义？','4','交通监控设备标志属于指路标志，蓝底、白图形、白边框、蓝色衬边。用于告知机动车驾驶人该区域设置有固定式交通监控设备。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1166,'这个标志的含义是警告前方有两个相邻的反向转弯道路。','2','<p><img src=http://tp.mnks.cn/tp_125.jpg>\r<br/>反向弯路\r<br/><img src=http://tp.mnks.cn/tp_126.jpg>\r<br/>连续弯路</p>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1167,'这个标志的含义是前方即将行驶至Y型交叉路口？','2','交叉路口：用以警告车辆驾驶人谨慎慢行，注意横向来车。设在平面交叉路口驶入路段的适当位置。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1170,'如图所示，驾驶机动车行经该路段时，应减速慢行，避免因眩目导致的交通事故。','1','驾驶员在驶出隧道口时，因为此处光线发生变化，驾驶员会有炫目感。安全起见，还是要减速慢行。',NULL,'2023-10-13 11:33:51','2023-10-13 11:33:51',0),(1172,'在驾驶技能准考证明的有效期内，科目二和科目三道路驾驶技能考试预约次数不得超过多少次？','3','在驾驶技能准考证明有效期内，科目二和科目三道路驾驶技能考试预约考试的次数不得超过五次。第五次预约考试仍不合格的，已考试合格的其他科目成绩作废。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1173,'机动车发生正面碰撞时，安全气囊加上安全带的双重保护才能充分发挥作用。','1','研究表明，假设气囊加安全带是100%安全的话，安全带的作用是70%，气囊的作用是30%。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1176,'科目三考试分为道路驾驶技能考试和安全文明驾驶常识考试两部分。','1','机动车驾驶人考试内容分为道路交通安全法律、法规和相关知识考试科目（以下简称“科目一”）、场地驾驶技能考试科目（以下简称“科目二”）、<b>道路驾驶技能和安全文明驾驶常识考试科目（以下简称“科目三”）。</b>',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1177,'驾驶人户籍迁出原车辆管理所需要向什么地方的车辆管理所提出申请？','4','《公安部令第123号》第四十九条：机动车驾驶人户籍迁出原车辆管理所管辖区的，应当向迁入地车辆管理所申请换证。',NULL,'2023-10-13 11:32:53','2023-10-13 11:32:53',0),(1178,'这个标志是何含义？','3','注意信号灯：用以警告车辆驾驶人注意前方路段设有信号灯，应依信号灯指示行车。',NULL,'2023-10-13 11:36:03','2023-10-13 11:36:03',0),(1180,'这个标志是何含义？','1','十字交叉路口：除了基本形十字路口外，还有部分变异的十字路口，如：五路交叉路口、变形十字路口、变形五路交叉路口等。五路以上的路口均按十字路口对待。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1181,'这个标志是何含义？','4','禁止鸣喇叭：表示禁止鸣喇叭。此标志设在需要禁止鸣喇叭的地方。禁止鸣喇叭的时间和范围可用辅助标志说明。',NULL,'2023-10-13 11:35:22','2023-10-13 11:35:22',0),(1183,'申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的（被撤销的），申请人在多长时间内不得再次申领机动车驾驶证。','4','申请人以欺骗、贿赂等不正当手段取得机动车驾驶证的，公安机关交通管理部门收缴机动车驾驶证，撤销机动车驾驶许可；申请人在三年内不得再次申领机动车驾驶证。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1186,'客车行经转弯、上下坡、凹凸路时，应让乘客抓住车内固定物，尤其提醒后排乘客注意安全。','1','因为在行经这些路面时，很容易发生颠簸，让人失去平衡。大家都有这样的感觉，坐在后排起伏的幅度较大，很多时候通过颠簸路面时，会有强烈的波动。',NULL,'2023-10-13 11:36:43','2023-10-13 11:36:43',0),(1187,'这个标志是何含义？','4','连续下坡：用以提醒车辆驾驶人小心驾驶。当连续下坡总长大于3 km后，应重复设置。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1189,'夜间通过没有路灯或路灯照明不良时，应将近光灯转换为远光灯，但同向行驶的后车不得使用远光灯。','1','通过没有路灯或路灯照明不良的路段（非路口）时可以开启远光灯，但是前方有车或行人时，为了不影响他人视线，应关闭远光，改用近光。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1190,'这是什么操纵装置？','4','你看那些曲线，代表的就是雾气。题目扩展：上边的按钮是前挡风除雾，下边的按钮是后挡风除雾。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1191,'这个导向箭头是何含义？','3','本题箭头是掉头的箭头，那么本题是指示前方掉头。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1192,'这个标志的含义是提醒前方右侧行车道或路面变窄。','1','右侧变窄：用以警告车辆驾驶人注意前方车行道或路面狭窄情况，遇有来车应予减速避让。设在双车道路面宽度缩减为6 m以下的路段起点前方。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1194,'这个标志的含义是提醒车辆驾驶人前方是非机动车道。','2','<p><img src=http://tp.mnks.cn/tp_232.jpg>\r<br/>非机动车道</p><p><img src=http://tp.mnks.cn/tp_159.jpg>\r<br/>注意非机动车</p>\r<br/>图中标志是注意非机动车，并非提醒前方是非机动车车道。题目描述有误，因此本题答案应为错误。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1196,'机动车登记证书、号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向哪个部门申请补领、换领。','3','根据《机动车登记规定》第四十四条的规定：机动车号牌、行驶证灭失、丢失或者损毁的，机动车所有人应当向登记地车辆管理所申请补领、换领。申请时，机动车所有人应当填写申请表并提交身份证明。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1198,'这个标志的含义是告示前方道路施工，车辆左右绕行。','2','<b>图中是 [左右绕行] 标志。</b>用以告示前方道路有障碍物，车辆应按标志指示减速慢行。设在道路障碍物前适当位置。并非道路施工，题目描述有误，因此本题答案为错。\r<br/><p><img src=http://tp.mnks.cn/tp_163.jpg>\r<br/>左右绕行标志</p><p><img src=http://tp.mnks.cn/tp_167.jpg>\r<br/>前方施工标志</p>',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1199,'这是什么交通标志？','2','右侧变窄：用以警告车辆驾驶人注意前方车行道或路面狭窄情况，遇有来车应予减速避让。设在双车道路面宽度缩减为6 m以下的路段起点前方。',NULL,'2023-10-13 11:21:59','2023-10-13 11:21:59',0),(1201,'驾驶机动车在没有道路中心线的狭窄山路怎样会车？','1','在没有中心隔离设施或者没有中心线的道路上，机动车遇相对方向来车时应当遵守下列规定：\r<br/>1)减速靠右行驶，并与其他车辆、行人保持必要的安全距离。\r<br/>2)在有障碍的路段，无障碍的一方先行：但有障碍的一方已驶入障碍路段而无障碍的一方未驶入时，有障碍的一方先行。\r<br/>3)在狭窄的坡路，上坡的一方先行；但下坡的一方已行至中途而上坡的一方未上坡时，下坡的一方先行。\r<br/>4)<b>在狭窄的山路，不靠山体的一方先行。</b>\r<br/>5)夜间会车应当在距相对方向来车150m以外改用近光灯，在窄路、窄桥与非机动车会车时应当使用近光灯。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1202,'这个标志是何含义？','3','禁止向左向右转弯：表示前方路口禁止一切车辆向左向右转弯。此标志设在禁止向左向右转弯的路口前适当位置。',NULL,'2023-10-13 11:39:23','2023-10-13 11:39:23',0),(1204,'驾驶机动车应当随身携带哪种证件？','3','《道路交通安全法》第十九条：驾驶人应当按照驾驶证载明的准驾车型驾驶机动车；驾驶机动车时，应当随身携带机动车驾驶证。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1206,'这个标志是何含义？','3','乡道是白底Y字开头的，县道是白底X开头的，省道是黄底的，国道是红底的。',NULL,'2023-10-13 11:40:27','2023-10-13 11:40:27',0),(1209,'将转向灯开关向下拉，右转向灯亮。','2','向上提：右转向灯亮，（顺时针方向，向右打方向盘的方向） \r<br/>向下拉：左转向灯亮，（逆时针方向，向左打方向盘的方向）',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1210,'这个标志是何含义？','2','傍山险路：用以提醒车辆驾驶人小心驾驶。设在傍山险路路段以前适当位置。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1213,'同车道行驶的车辆前方遇到下列哪种车辆不得超车？','1','如果是真的执行任务的警车（此处不好判断），一定要让行。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1217,'机动车仪表板上（如图所示）亮表示什么？','4','这个没有问题吧。。。老衲也不知如何解释这个题。',NULL,'2023-10-13 11:31:06','2023-10-13 11:31:06',0),(1219,'准驾车型为小型汽车的，可以驾驶小型自动挡载客汽车。','1','小型汽车（C1）准驾车型：小型、微型载客汽车以及轻型、微型载货汽车；轻型、微型专项作业车，小型、微型自动挡载客汽车以及轻型、微型自动挡载货汽车，低速载货汽车，三轮汽车。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1220,'驾驶机动车违反道路交通安全法律法规发生交通事故属于交通违章行为。','2','题干中有明确表述“违反道路交通安全法”，因此属于违法行为，并非违章行为。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1221,'在这种情况下可以加速通过人行横道。','2','图中可以看出，人行横道上正在有老人过马路，所以应该是停车等待，等待行人通过后，再驶离人行横道。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1222,'驾驶人在驾驶证核发地车辆管理所管辖区以外居住的，可以向居住地车辆管理所申请换证。','1','《机动车驾驶证申领和使用规定》第四十九条：机动车驾驶人户籍迁出原车辆管理所管辖区的，应当向迁入地车辆管理所申请换证。机动车驾驶人在核发地车辆管理所管辖区以外居住的，可以向居住地车辆管理所申请换证。',NULL,'2023-10-13 11:24:48','2023-10-13 11:24:48',0),(1223,'如图所示，驾驶机动车直行遇前方道路堵塞时，车辆可以在黄色网格线区域临时停车等待，但不得在人行横道停车。','2','驾驶机动车直行遇前方道路堵塞时，车辆不可在黄色网格线区域临时停车等待，也不可在人行横道停车。即使绿灯亮了，也要在路口外停车等待。',NULL,'2023-10-13 11:39:53','2023-10-13 11:39:53',0),(1224,'驾驶机动车超车时，前方车辆不减速让路，应停止超车并适当减速，与前方车辆保持安全距离。','1','不具备超车条件时，应该主动放弃超车，并与前车保持安全距离，避免发生碰撞。',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0),(1226,'如图所示，驾驶机动车遇到这种情况时，A车应当注意避让。','1','《中华人民共和国道路交通安全法》第五十四条条明确规定：<b>道路养护车辆、工程作业车进行作业时，在不影响过往车辆通行的前提下，其行驶路线和方向不受交通标志、标线限制，过往车辆和人员应当注意避让。</b>',NULL,'2023-10-13 11:28:40','2023-10-13 11:28:40',0);

/*Table structure for table `role` */

DROP TABLE IF EXISTS `role`;

CREATE TABLE `role` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'id',
  `role_name` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '名称',
  `description` text CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci COMMENT '描述',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC;

/*Data for the table `role` */

insert  into `role`(`id`,`role_name`,`description`,`create_time`,`update_time`) values (1,'管理员','具有查看后台权限','2023-09-25 15:47:46','2023-09-25 15:47:50'),(2,'普通用户',NULL,'2023-10-11 09:19:58','2023-10-11 09:19:55');

/*Table structure for table `subject` */

DROP TABLE IF EXISTS `subject`;

CREATE TABLE `subject` (
  `subject_id` int NOT NULL AUTO_INCREMENT,
  `subject_category_type_id` int DEFAULT NULL COMMENT '汽车类别',
  `subject_type_id` int DEFAULT NULL COMMENT '科目类别',
  `subject_name` varchar(50) DEFAULT NULL COMMENT '具体科目类',
  PRIMARY KEY (`subject_id`),
  KEY `subject_type_id` (`subject_type_id`),
  KEY `subject_category_type_id` (`subject_category_type_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

/*Data for the table `subject` */

insert  into `subject`(`subject_id`,`subject_category_type_id`,`subject_type_id`,`subject_name`) values (1,1,1,'科目一'),(2,1,2,'科目二'),(3,1,3,'科目三'),(4,1,4,'科目四'),(5,2,1,NULL),(6,2,2,NULL),(7,2,3,NULL),(8,2,4,NULL);

/*Table structure for table `user` */

DROP TABLE IF EXISTS `user`;

CREATE TABLE `user` (
  `user_id` int NOT NULL AUTO_INCREMENT COMMENT '主键编号',
  `user_name` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '用户名称',
  `user_password` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '用户密码',
  `user_phone` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '手机号码',
  `user_address` varchar(100) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci DEFAULT NULL COMMENT '地址',
  `create_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `role_id` int DEFAULT NULL COMMENT '绑定角色id',
  `user_delete` int DEFAULT '0' COMMENT '逻辑删除 0表示存在 1删除',
  PRIMARY KEY (`user_id`) USING BTREE,
  KEY `role_Id` (`role_id`) USING BTREE,
  CONSTRAINT `user_ibfk_1` FOREIGN KEY (`role_id`) REFERENCES `role` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb3 ROW_FORMAT=DYNAMIC;

